// Custom Next.js server
// Intercepts TRACE/TRACK before Next.js processes them (Next.js throws TypeError for these methods)
process.env.NODE_ENV = process.env.NODE_ENV || 'production'

const { createServer } = require('http')
const next = require('next')

const dev = process.env.NODE_ENV !== 'production'
const hostname = process.env.HOSTNAME || '0.0.0.0'
const port = parseInt(process.env.PORT || '3000', 10)

const app = next({ dev, hostname, port })
const handle = app.getRequestHandler()

app.prepare().then(() => {
  createServer(async (req, res) => {
    // Block TRACE/TRACK before Next.js tries to construct a Request object (which throws for these methods)
    if (req.method === 'TRACE' || req.method === 'TRACK') {
      res.writeHead(405, {
        Allow: 'GET, HEAD, POST, PUT, PATCH, DELETE, OPTIONS',
        'Content-Type': 'text/plain',
      })
      res.end('Method Not Allowed')
      return
    }

    try {
      // Use WHATWG URL API to avoid url.parse() deprecation
      const baseUrl = `http://${hostname === '0.0.0.0' ? 'localhost' : hostname}:${port}`
      const parsed = new URL(req.url, baseUrl)
      await handle(req, res, { pathname: parsed.pathname, query: Object.fromEntries(parsed.searchParams), search: parsed.search })
    } catch (err) {
      console.error('Error occurred handling', req.url, err)
      res.statusCode = 500
      res.end('Internal Server Error')
    }
  }).listen(port, hostname, (err) => {
    if (err) throw err
    console.log(`\u25b2 Next.js custom server`)
    console.log(`- Local:   http://localhost:${port}`)
    console.log(`\u2713 Ready`)
  })
})

import { NextResponse } from 'next/server'
import { z } from 'zod'
import { requireAdmin, isAuthError, writeAuditLog } from '@/utils/admin-auth'

export const dynamic = 'force-dynamic'

const querySchema = z.object({
  page:   z.string().optional().default('1'),
  limit:  z.string().optional().default('20'),
  search: z.string().optional().default(''),
  role:   z.string().optional().default(''),
  plan:   z.string().optional().default(''),
  status: z.string().optional().default(''),
  sort:   z.string().optional().default('created_at'),
  order:  z.enum(['asc', 'desc']).optional().default('desc'),
})

export async function GET(req: Request) {
  const ctx = await requireAdmin()
  if (isAuthError(ctx)) return ctx

  const { searchParams } = new URL(req.url)
  const parsed = querySchema.safeParse(Object.fromEntries(searchParams))
  if (!parsed.success) {
    return NextResponse.json({ error: 'Invalid query parameters' }, { status: 422 })
  }

  const { page, limit, search, role, plan, status, sort, order } = parsed.data
  const pageNum  = Math.max(1, parseInt(page, 10))
  const pageSize = Math.min(100, Math.max(1, parseInt(limit, 10)))
  const offset   = (pageNum - 1) * pageSize

  let query = ctx.svc
    .from('profiles')
    .select('id, full_name, email, role, subscription_plan, account_status, is_banned, created_at, last_seen, avatar_url, tagline', { count: 'exact' })

  if (search) {
    query = query.or(`full_name.ilike.%${search}%,email.ilike.%${search}%`)
  }
  if (role)   query = query.eq('role', role)
  if (plan)   query = query.eq('subscription_plan', plan)
  if (status) query = query.eq('account_status', status)

  const validSortCols = ['created_at', 'full_name', 'email', 'last_seen', 'subscription_plan']
  const sortCol = validSortCols.includes(sort) ? sort : 'created_at'

  const { data, count, error } = await query
    .order(sortCol, { ascending: order === 'asc' })
    .range(offset, offset + pageSize - 1)

  if (error) return NextResponse.json({ error: error.message }, { status: 500 })

  return NextResponse.json({
    users: data ?? [],
    total: count ?? 0,
    page: pageNum,
    pageSize,
    totalPages: Math.ceil((count ?? 0) / pageSize),
  })
}

import { NextRequest, NextResponse } from 'next/server'
import Stripe from 'stripe'
import { createServerSupabaseClient, createAdminClient } from '@/utils/supabase/server'

function getStripeClient(): Stripe {
  const stripeKey = process.env.STRIPE_SECRET_KEY
  if (!stripeKey) {
    throw new Error('STRIPE_SECRET_KEY is not configured')
  }
  return new Stripe(stripeKey, { apiVersion: '2026-03-25.dahlia' as any })
}

// POST /api/hustle/connect — create Stripe Connect onboarding link
export async function POST(_req: NextRequest) {
  let stripe: Stripe
  try {
    stripe = getStripeClient()
  } catch (err: unknown) {
    const msg = err instanceof Error ? err.message : 'Stripe is not configured'
    return NextResponse.json({ error: msg }, { status: 500 })
  }

  const supabase = await createServerSupabaseClient()
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })

  const svc = await createAdminClient()

  // Fetch or create connected account
  const { data: profile } = await svc.from('profiles').select('stripe_account_id, stripe_account_status, account_status, full_name, email').eq('id', user.id).single()

  if (profile?.account_status === 'deactivated') {
    return NextResponse.json({ error: 'Your account has been permanently deactivated.' }, { status: 403 })
  }

  let accountId = profile?.stripe_account_id

  if (!accountId) {
    // Create a new Express Connect account
    const account = await stripe.accounts.create({
      type: 'express',
      email: profile?.email ?? undefined,
      capabilities: {
        transfers: { requested: true },
        card_payments: { requested: true },
      },
      business_type: 'individual',
      metadata: { platform_user_id: user.id },
    })
    accountId = account.id

    await svc.from('profiles').update({
      stripe_account_id: accountId,
      stripe_account_status: 'pending',
    }).eq('id', user.id)
  }

  // Create onboarding link
  const appUrl = process.env.NEXT_PUBLIC_APP_URL ?? 'https://espeezy.com'
  const accountLink = await stripe.accountLinks.create({
    account: accountId,
    refresh_url: `${appUrl}/dashboard/hustle/connect?refresh=1`,
    return_url: `${appUrl}/dashboard/hustle/connect?success=1`,
    type: 'account_onboarding',
  })

  await svc.from('profiles').update({ stripe_onboarding_url: accountLink.url }).eq('id', user.id)

  return NextResponse.json({ url: accountLink.url })
}

// GET /api/hustle/connect — check Connect account status
export async function GET(_req: NextRequest) {
  let stripe: Stripe
  try {
    stripe = getStripeClient()
  } catch (err: unknown) {
    const msg = err instanceof Error ? err.message : 'Stripe is not configured'
    return NextResponse.json({ error: msg }, { status: 500 })
  }

  const supabase = await createServerSupabaseClient()
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })

  const svc = await createAdminClient()
  const { data: profile } = await svc.from('profiles').select('stripe_account_id, stripe_account_status').eq('id', user.id).single()

  if (!profile?.stripe_account_id) {
    return NextResponse.json({ status: 'none' })
  }

  // Check with Stripe for current status
  try {
    const account = await stripe.accounts.retrieve(profile.stripe_account_id)
    const newStatus = account.payouts_enabled ? 'active' : (account.details_submitted ? 'restricted' : 'pending')

    if (newStatus !== profile.stripe_account_status) {
      await svc.from('profiles').update({ stripe_account_status: newStatus }).eq('id', user.id)
    }

    return NextResponse.json({
      status: newStatus,
      payoutsEnabled: account.payouts_enabled,
      chargesEnabled: account.charges_enabled,
      detailsSubmitted: account.details_submitted,
    })
  } catch {
    return NextResponse.json({ status: profile.stripe_account_status ?? 'unknown' })
  }
}

