import { NextRequest, NextResponse } from 'next/server'
import Stripe from 'stripe'
import { z } from 'zod'
import { createServerSupabaseClient, createAdminClient } from '@/utils/supabase/server'

export const dynamic = 'force-dynamic'

function getStripeClient(): Stripe {
  const stripeKey = process.env.STRIPE_SECRET_KEY
  if (!stripeKey) {
    throw new Error('STRIPE_SECRET_KEY is not configured')
  }
  return new Stripe(stripeKey, { apiVersion: '2026-03-25.dahlia' as any })
}

const APP_URL = process.env.NEXT_PUBLIC_APP_URL ?? 'https://espeezy.com'

// Platform fee: 2% of transfer, minimum 25 cents
function computeFee(amountCents: number): number {
  return Math.max(25, Math.ceil(amountCents * 0.02))
}

const SendSchema = z.object({
  recipient_username: z.string().min(2).max(50),
  amount_cents: z.number().int().min(100).max(100_000_00), // $1 – $100,000
  note: z.string().max(280).optional(),
})

// POST /api/payments/send — initiate a P2P payment checkout
export async function POST(req: NextRequest) {
  let stripe: Stripe
  try {
    stripe = getStripeClient()
  } catch (err: unknown) {
    const msg = err instanceof Error ? err.message : 'Stripe is not configured'
    return NextResponse.json({ error: msg }, { status: 500 })
  }

  const supabase = await createServerSupabaseClient()
  const { data: { user } } = await supabase.auth.getUser()
    .catch(() => ({ data: { user: null } }))
  if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })

  const body = await req.json().catch(() => null)
  const parsed = SendSchema.safeParse(body)
  if (!parsed.success) {
    return NextResponse.json({ error: 'Invalid request', details: parsed.error.flatten() }, { status: 422 })
  }

  const { recipient_username, amount_cents, note } = parsed.data

  const admin = await createAdminClient()

  // Fetch sender profile
  const { data: sender } = await admin
    .from('profiles')
    .select('id, username, full_name, espeezy_email, stripe_account_id, stripe_account_status, email')
    .eq('id', user.id)
    .single()

  if (!sender) return NextResponse.json({ error: 'Sender profile not found' }, { status: 404 })
  if (sender.username?.toLowerCase() === recipient_username.toLowerCase()) {
    return NextResponse.json({ error: 'You cannot send money to yourself' }, { status: 422 })
  }

  // Fetch recipient by username
  const { data: recipient } = await admin
    .from('profiles')
    .select('id, username, full_name, espeezy_email, stripe_account_id, stripe_account_status, email')
    .ilike('username', recipient_username)
    .single()

  if (!recipient) return NextResponse.json({ error: 'Recipient not found. Check the username.' }, { status: 404 })
  if (!recipient.stripe_account_id || recipient.stripe_account_status !== 'active') {
    return NextResponse.json({
      error: `${recipient.full_name} has not connected a bank account yet. Ask them to set up payouts first.`,
    }, { status: 400 })
  }

  const fee_cents = computeFee(amount_cents)
  const net_cents = amount_cents - fee_cents

  // Create a pending transfer record
  const { data: transfer, error: transferErr } = await admin
    .from('p2p_transfers')
    .insert({
      sender_id: sender.id,
      recipient_id: recipient.id,
      amount_cents,
      fee_cents,
      net_cents,
      note: note ?? null,
      status: 'pending',
      sender_espeezy_email: sender.espeezy_email ?? `${sender.username}@espeezy.com`,
      recipient_espeezy_email: recipient.espeezy_email ?? `${recipient.username}@espeezy.com`,
    })
    .select()
    .single()

  if (transferErr || !transfer) {
    return NextResponse.json({ error: 'Failed to create transfer record' }, { status: 500 })
  }

  // Create Stripe Checkout Session — sender pays amount_cents, net_cents goes to recipient
  const session = await stripe.checkout.sessions.create({
    payment_method_types: ['card'],
    mode: 'payment',
    customer_email: sender.email ?? undefined,
    line_items: [{
      price_data: {
        currency: 'usd',
        product_data: {
          name: `Send money to @${recipient.username}`,
          description: note ? `Note: ${note}` : `P2P transfer on Espeezy`,
        },
        unit_amount: amount_cents,
      },
      quantity: 1,
    }],
    payment_intent_data: {
      transfer_data: {
        destination: recipient.stripe_account_id,
        amount: net_cents,
      },
      metadata: {
        type: 'p2p_transfer',
        transfer_id: transfer.id,
        sender_id: sender.id,
        recipient_id: recipient.id,
      },
    },
    metadata: {
      type: 'p2p_transfer',
      transfer_id: transfer.id,
    },
    success_url: `${APP_URL}/dashboard/wallet?transfer=success&id=${transfer.id}`,
    cancel_url:  `${APP_URL}/dashboard/wallet?transfer=cancelled`,
  })

  // Store checkout session ID on the transfer record
  await admin
    .from('p2p_transfers')
    .update({ stripe_checkout_session_id: session.id })
    .eq('id', transfer.id)

  return NextResponse.json({ checkout_url: session.url, transfer_id: transfer.id }, { status: 201 })
}

import { NextResponse } from 'next/server'
import { createAdminClient } from '@/utils/supabase/server'
import { createHash } from 'crypto'
import { isValidEmail, sanitizeName, sanitizeText, checkBodySize, LIMITS } from '@/utils/sanitize'

export async function POST(req: Request) {
  try {
    // Reject oversized bodies before parsing
    if (!checkBodySize(req, 50_000)) {
      return NextResponse.json({ error: 'Payload too large.' }, { status: 413 })
    }

    const body = await req.json().catch(() => null)
    if (!body || typeof body !== 'object' || Array.isArray(body)) {
      return NextResponse.json({ error: 'Invalid request body.' }, { status: 400 })
    }

    const { email, fullName, institution, role, source, campaignRef } = body as Record<string, unknown>

    if (!isValidEmail(email)) {
      return NextResponse.json({ error: 'A valid email address is required.' }, { status: 400 })
    }

    // Sanitize all string fields
    const cleanEmail = (email as string).trim().toLowerCase().slice(0, LIMITS.MAX_EMAIL_LENGTH)
    const cleanFullName = sanitizeName(fullName)
    const cleanInstitution = sanitizeText(institution, 200)
    const cleanRole = typeof role === 'string' && ['student', 'educator', 'professional', 'other'].includes(role)
      ? role : 'student'
    const cleanSource = typeof source === 'string' ? sanitizeText(source, 50) : 'organic'
    const cleanCampaignRef = typeof campaignRef === 'string' ? sanitizeText(campaignRef, 100) : null

    // Hash IP for deduplication without storing raw IP
    const ipHeader = req.headers.get('x-forwarded-for') ?? req.headers.get('x-real-ip') ?? 'unknown'
    const ip = ipHeader.split(',')[0].trim()
    const ipHash = createHash('sha256').update(ip + (process.env.IP_HASH_SALT ?? 'fallback')).digest('hex').slice(0, 16)
    const userAgent = (req.headers.get('user-agent') ?? '').slice(0, 500)

    const supabase = await createAdminClient()

    const { error } = await supabase
      .from('pre_registrations')
      .insert({
        email: cleanEmail,
        full_name: cleanFullName || null,
        institution: cleanInstitution || null,
        role: cleanRole,
        source: cleanSource,
        campaign_ref: cleanCampaignRef,
        ip_hash: ipHash,
        user_agent: userAgent,
      })

    if (error) {
      // Unique constraint = already registered
      if (error.code === '23505') {
        return NextResponse.json({ success: true, message: 'You are already registered! We will be in touch.' })
      }
      console.error('[preregister] DB error:', error.code)
      return NextResponse.json({ error: 'Registration failed. Please try again.' }, { status: 500 })
    }

    // Fetch updated count
    const { data: countData } = await supabase.rpc('get_prereg_count')
    const count = countData ?? 0

    return NextResponse.json({
      success: true,
      message: 'You are on the list! We will notify you at launch.',
      count,
    })
  } catch (err) {
    console.error('[preregister] Unexpected error type:', typeof err)
    return NextResponse.json({ error: 'An unexpected error occurred.' }, { status: 500 })
  }
}

export async function GET() {
  try {
    const supabase = await createAdminClient()
    const { data, error } = await supabase.rpc('get_prereg_count')
    if (error) throw error
    return NextResponse.json({ count: data ?? 0 })
  } catch (err) {
    return NextResponse.json({ count: 0 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { createServerSupabaseClient, createAdminClient } from '@/utils/supabase/server'

export const dynamic = 'force-dynamic'

// GET /api/quiz/categories — list active quiz categories with prize info
export async function GET(_req: NextRequest) {
  const supabase = await createServerSupabaseClient()
  const { data: { user } } = await supabase.auth.getUser()
    .catch(() => ({ data: { user: null } }))
  if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })

  const admin = await createAdminClient()

  const { data: categories, error } = await admin
    .from('quiz_categories')
    .select('id, slug, name, description, icon, difficulty_tier, prize_pool_cents, is_seasonal, season_start, season_end')
    .eq('is_active', true)
    .order('prize_pool_cents', { ascending: false })

  if (error) return NextResponse.json({ error: error.message }, { status: 500 })

  return NextResponse.json({ categories: categories ?? [] })
}

import { NextRequest, NextResponse } from 'next/server'
import Stripe from 'stripe'
import { z } from 'zod'
import { createServerSupabaseClient, createAdminClient } from '@/utils/supabase/server'
import { sendP2PTransactionEmail } from '@/services/email'

export const dynamic = 'force-dynamic'

function getStripeClient(): Stripe {
  const stripeKey = process.env.STRIPE_SECRET_KEY
  if (!stripeKey) {
    throw new Error('STRIPE_SECRET_KEY is not configured')
  }
  return new Stripe(stripeKey, { apiVersion: '2026-03-25.dahlia' as any })
}

const PayoutSchema = z.object({
  limit: z.number().int().min(1).max(100).optional().default(20),
})

async function isAdminUser(): Promise<boolean> {
  const supabase = await createServerSupabaseClient()
  const { data: { user } } = await supabase.auth.getUser().catch(() => ({ data: { user: null } }))
  if (!user) return false
  const admin = await createAdminClient()
  const { data: profile } = await admin.from('profiles').select('role').eq('id', user.id).single()
  return profile?.role === 'admin'
}

// POST /api/quiz/prizes/payout — settle unpaid quiz cash prizes
// Auth: admin session OR X-Agent-Key header for internal workers
export async function POST(req: NextRequest) {
  let stripe: Stripe
  try {
    stripe = getStripeClient()
  } catch (err: unknown) {
    const msg = err instanceof Error ? err.message : 'Stripe is not configured'
    return NextResponse.json({ error: msg }, { status: 500 })
  }

  const agentKey = req.headers.get('x-agent-key')
  const internalAllowed = Boolean(process.env.AGENT_API_KEY) && agentKey === process.env.AGENT_API_KEY
  const adminAllowed = await isAdminUser()

  if (!internalAllowed && !adminAllowed) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
  }

  const body = await req.json().catch(() => ({}))
  const parsed = PayoutSchema.safeParse(body)
  if (!parsed.success) {
    return NextResponse.json({ error: 'Invalid request', details: parsed.error.flatten() }, { status: 422 })
  }

  const { limit } = parsed.data
  const admin = await createAdminClient()

  const { data: sessions, error } = await admin
    .from('quiz_sessions')
    .select('id, user_id, prize_cents_won, prize_paid_out')
    .eq('status', 'completed')
    .eq('prize_paid_out', false)
    .gt('prize_cents_won', 0)
    .order('completed_at', { ascending: true })
    .limit(limit)

  if (error) return NextResponse.json({ error: error.message }, { status: 500 })
  if (!sessions?.length) return NextResponse.json({ processed: 0, paid: 0, skipped: 0, results: [] })

  let paid = 0
  let skipped = 0
  const results: Array<{ session_id: string; status: 'paid' | 'skipped' | 'failed'; reason?: string }> = []

  for (const session of sessions) {
    const { data: profile } = await admin
      .from('profiles')
      .select('id, full_name, username, email, espeezy_email, stripe_account_id, stripe_account_status')
      .eq('id', session.user_id)
      .single()

    if (!profile?.stripe_account_id || profile.stripe_account_status !== 'active') {
      skipped++
      results.push({ session_id: session.id, status: 'skipped', reason: 'No active Stripe connected account' })
      continue
    }

    try {
      const transfer = await stripe.transfers.create({
        amount: session.prize_cents_won,
        currency: 'usd',
        destination: profile.stripe_account_id,
        description: `Quiz prize payout for session ${session.id}`,
        metadata: {
          type: 'quiz_prize',
          quiz_session_id: session.id,
          user_id: profile.id,
        },
      })

      await admin
        .from('quiz_sessions')
        .update({ prize_paid_out: true, prize_transfer_id: transfer.id })
        .eq('id', session.id)

      await admin.from('reward_ledger').insert({
        user_id: profile.id,
        type: 'prize_cash_awarded',
        points: 0,
        cash_value_cents: session.prize_cents_won,
        description: `Cash prize payout for quiz session ${session.id}`,
        reference_id: session.id,
        reference_type: 'quiz_session',
      })

      await admin.from('notifications').insert({
        user_id: profile.id,
        type: 'quiz_prize_paid',
        title: `Prize paid: $${(session.prize_cents_won / 100).toFixed(2)}`,
        message: `Your quiz cash prize has been paid to your connected account.`,
        link: '/dashboard/wallet',
      })

      const to = [profile.email, profile.espeezy_email].filter((v): v is string => Boolean(v))
      if (to.length > 0) {
        await sendP2PTransactionEmail({
          to,
          role: 'recipient',
          transferId: transfer.id,
          counterpartyName: 'Espeezy Quiz Prize Engine',
          counterpartyUsername: 'espeezy',
          amountCents: session.prize_cents_won,
          feeCents: 0,
          netCents: session.prize_cents_won,
          note: `Quiz session ${session.id}`,
        })
      }

      paid++
      results.push({ session_id: session.id, status: 'paid' })
    } catch (e: unknown) {
      results.push({
        session_id: session.id,
        status: 'failed',
        reason: e instanceof Error ? e.message : 'Unknown transfer error',
      })
    }
  }

  return NextResponse.json({ processed: sessions.length, paid, skipped, results })
}

import { NextRequest, NextResponse } from 'next/server'
import { createServerSupabaseClient, createAdminClient } from '@/utils/supabase/server'

export const dynamic = 'force-dynamic'

// GET /api/quiz/tournaments — list active + upcoming tournaments
export async function GET(_req: NextRequest) {
  const supabase = await createServerSupabaseClient()
  const { data: { user } } = await supabase.auth.getUser()
    .catch(() => ({ data: { user: null } }))
  if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })

  const admin = await createAdminClient()

  const { data: tournaments, error } = await admin
    .from('quiz_tournaments')
    .select(`
      id, slug, name, description, difficulty, prize_pool_cents, entry_fee_cents,
      max_participants, status, starts_at, ends_at, prize_distribution,
      is_seasonal, season_name,
      category:quiz_categories(id, name, slug, difficulty_tier)
    `)
    .in('status', ['upcoming', 'active'])
    .order('starts_at', { ascending: true })

  if (error) return NextResponse.json({ error: error.message }, { status: 500 })

  // For each tournament, get participant count
  type TournamentRow = { id: string }
  const enriched = await Promise.all(((tournaments ?? []) as TournamentRow[]).map(async (t) => {
    const { count } = await admin
      .from('quiz_tournament_participants')
      .select('*', { count: 'exact', head: true })
      .eq('tournament_id', t.id)

    const { data: myEntry } = await admin
      .from('quiz_tournament_participants')
      .select('rank, prize_cents_won, entry_paid')
      .eq('tournament_id', t.id)
      .eq('user_id', user.id)
      .maybeSingle()

    return { ...t, participant_count: count ?? 0, my_entry: myEntry ?? null }
  }))

  return NextResponse.json({ tournaments: enriched })
}

import { createAdminClient } from '@/utils/supabase/server'
import { NextResponse } from 'next/server'

export async function POST(request: Request) {
  try {
    const { userId } = await request.json()
    if (!userId) return NextResponse.json({ error: 'User ID missing' }, { status: 400 })

    const supabase = await createAdminClient()
    const { data: profile, error: fetchError } = await supabase
      .from('profiles')
      .select('spotify_refresh_token')
      .eq('id', userId)
      .single()

    if (fetchError || !profile?.spotify_refresh_token) {
      return NextResponse.json({ error: 'Refresh token not found' }, { status: 404 })
    }

    const client_id = process.env.SPOTIFY_CLIENT_ID
    const client_secret = process.env.SPOTIFY_CLIENT_SECRET

    const response = await fetch('https://accounts.spotify.com/api/token', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Authorization': 'Basic ' + Buffer.from(client_id + ':' + client_secret).toString('base64')
      },
      body: new URLSearchParams({
        grant_type: 'refresh_token',
        refresh_token: profile.spotify_refresh_token
      })
    })

    const data = await response.json()

    if (data.error) {
      return NextResponse.json({ error: data.error_description }, { status: 400 })
    }

    // New refresh token is optional – Spotify might not return a new one if it hasn't changed.
    const updates: any = {
      spotify_access_token: data.access_token,
      spotify_token_expires_at: new Date(Date.now() + data.expires_in * 1000).toISOString()
    }

    if (data.refresh_token) {
      updates.spotify_refresh_token = data.refresh_token
    }

    const { error: updateError } = await supabase
      .from('profiles')
      .update(updates)
      .eq('id', userId)

    if (updateError) throw updateError

    return NextResponse.json({ access_token: data.access_token })
  } catch (err: any) {
    console.error('Spotify Refresh Route Error:', err)
    return NextResponse.json({ error: err.message }, { status: 500 })
  }
}

