import { NextResponse } from 'next/server'
import crypto from 'crypto'
import { createClient } from '@supabase/supabase-js'

export async function POST(req: Request) {
  // We initialize the client INSIDE the handler. Otherwise, Next.js tries to statically compile it 
  // during `npm run build` without environment variables, causing a Vercel Pipeline crash.
  const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!
  const supabaseServiceKey = process.env.SUPABASE_SERVICE_ROLE_KEY || process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
  const supabase = createClient(supabaseUrl, supabaseServiceKey)

  try {
    const rawBody = await req.text()
    const signature = req.headers.get('x-hub-signature-256')
    const webhookSecret = process.env.GITHUB_WEBHOOK_SECRET

    if (!webhookSecret) {
      console.warn("GITHUB_WEBHOOK_SECRET is not set. Bypassing validation (NOT FOR PRODUCTION).")
    } else if (signature) {
      // Validate Payload
      const hmac = crypto.createHmac('sha256', webhookSecret)
      const digest = 'sha256=' + hmac.update(rawBody).digest('hex')
      if (signature !== digest) {
        return new NextResponse('Unauthorized: Invalid Signature', { status: 401 })
      }
    }

    const payload = JSON.parse(rawBody)

    // Only process push events with commits
    if (!payload.commits || payload.commits.length === 0) {
      return new NextResponse('No commits to process', { status: 200 })
    }

    const uuidRegex = /[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}/i;

    for (const commit of payload.commits) {
      const match = commit.message.match(uuidRegex)
      
      if (match) {
        const taskId = match[0]
        
        // 1. Fetch the Task to find who it's assigned to
        const { data: task, error: taskError } = await supabase
          .from('tasks')
          .select('assignees, status, is_coding_task')
          .eq('id', taskId)
          .single()

        if (!taskError && task?.is_coding_task) {
           // 2. Base Algorithmic Validity Engine (MVP scoring calculation)
           const impactScore = 15; // standard base reward
           
           // 3. Record the Commit mathematically
           await supabase.from('commits').insert([{
             hash: commit.id,
             message: commit.message,
             author_email: commit.author.email,
             task_id: taskId,
             impact_score: impactScore,
             lines_added: 0,
             lines_deleted: 0
           }])

           // 4. Update Task Status dynamically to Done
           await supabase.from('tasks').update({ status: 'Done' }).eq('id', taskId)

           // 5. Update Profile Score across ALL ACTIVE COLLABORATORS
           if (task.assignees && task.assignees.length > 0) {
              for (const userId of task.assignees) {
                 const { data: profile } = await supabase.from('profiles').select('total_score').eq('id', userId).single()
                 if (profile) {
                    await supabase.from('profiles').update({ total_score: profile.total_score + impactScore }).eq('id', userId)
                 }
              }
           }
        }
      }
    }

    return new NextResponse('Webhook processed successfully', { status: 200 })
    
  } catch (err: any) {
    console.error("Webhook Error:", err)
    return new NextResponse(`Server Error: ${err.message}`, { status: 500 })
  }
}

'use client'

import { useState, useEffect } from 'react'
import { createBrowserSupabaseClient } from '@/utils/supabase/client'
import { useRouter } from 'next/navigation'
import { ShieldCheck, Lock, Activity, ArrowRight } from 'lucide-react'
import TransientError from '@/components/TransientError'

export default function ResetPasswordPage() {
  const [password, setPassword] = useState('')
  const [confirmPassword, setConfirmPassword] = useState('')
  const [error, setError] = useState<string | null>(null)
  const [success, setSuccess] = useState(false)
  const [loading, setLoading] = useState(false)
  const router = useRouter()
  const supabase = createBrowserSupabaseClient()

  const handleReset = async (e: React.FormEvent) => {
    e.preventDefault()
    if (password !== confirmPassword) {
      setError('Passwords do not match.')
      return
    }
    if (password.length < 6) {
      setError('Password must be at least 6 characters.')
      return
    }

    setLoading(true)
    setError(null)

    try {
      const { error } = await supabase.auth.updateUser({ password })
      if (error) {
        setError(error.message)
      } else {
        setSuccess(true)
        setTimeout(() => router.push('/login'), 3000)
      }
    } catch (err: any) {
      setError(err.message || 'An unexpected error occurred.')
    } finally {
      setLoading(false)
    }
  }

  return (
    <div style={{
      minHeight: '100vh',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      background: 'var(--bg-main)',
      padding: '1.5rem'
    }}>
      <div className="auth-card" style={{ maxWidth: '450px', width: '100%', animation: 'fadeIn 0.5s ease-out' }}>
        <div style={{ textAlign: 'center', marginBottom: '2.5rem' }}>
          <div style={{ width: '60px', height: '60px', background: 'var(--brand)', borderRadius: '18px', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 1.5rem', boxShadow: '0 8px 16px rgba(var(--brand-rgb), 0.3)' }}>
            <Lock color="white" size={30} />
          </div>
          <h1 style={{ fontSize: '2rem', fontWeight: 900, letterSpacing: '-0.03em', margin: 0 }}>Secure Account Recovery</h1>
          <p style={{ color: 'var(--text-sub)', marginTop: '0.6rem', fontWeight: 600 }}>Update your terminal credentials to regain access.</p>
        </div>

        {error && <TransientError message={error} />}
        
        {success ? (
          <div style={{ textAlign: 'center', padding: '1rem' }}>
            <div style={{ color: 'var(--success)', marginBottom: '1.5rem' }}>
              <ShieldCheck size={48} style={{ margin: '0 auto' }} />
            </div>
            <h3 style={{ fontWeight: 900, marginBottom: '0.5rem' }}>Protocol Updated</h3>
            <p style={{ color: 'var(--text-sub)', fontWeight: 600 }}>Identity credentials have been successfully reset. Redirecting to terminal...</p>
          </div>
        ) : (
          <form onSubmit={handleReset} style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
            <div className="form-group">
              <label className="form-label">New Password</label>
              <input 
                type="password" 
                className="form-input" 
                required 
                value={password} 
                onChange={e => setPassword(e.target.value)}
                placeholder="••••••••"
                style={{ borderRadius: '14px' }}
              />
            </div>
            <div className="form-group">
              <label className="form-label">Confirm Password</label>
              <input 
                type="password" 
                className="form-input" 
                required 
                value={confirmPassword} 
                onChange={e => setConfirmPassword(e.target.value)}
                placeholder="••••••••"
                style={{ borderRadius: '14px' }}
              />
            </div>
            <button className="btn btn-primary" type="submit" disabled={loading} style={{ height: '3.5rem', borderRadius: '18px', fontWeight: 900, fontSize: '1.1rem' }}>
              {loading ? 'Updating Credentials...' : 'Update Password'}
            </button>
          </form>
        )}

        <div style={{ marginTop: '2.5rem', paddingTop: '1.5rem', borderTop: '1px solid var(--border)', textAlign: 'center' }}>
          <div style={{ display: 'inline-flex', alignItems: 'center', gap: '0.5rem', color: 'var(--text-sub)', fontSize: '0.8rem', fontWeight: 800, textTransform: 'uppercase', letterSpacing: '0.05em' }}>
            <Activity size={14} color="var(--brand)" /> 
            System Recovery Mode Active
          </div>
        </div>
      </div>
    </div>
  )
}

