  'DevOps':         '#06b6d4',
  'Ethics & Legal': '#ef4444',
}

const STATUS_COLORS: Record<string, string> = {
  'To Do':       '#64748b',
  'In Progress': '#f59e0b',
  'Done':        '#10b981',
}

export default function AnalyticsPage({ params }: { params: Promise<{ id: string }> }) {
  const { id: groupId } = use(params)
  const [loading, setLoading] = useState(true)
  const { addToast } = useNotifications()
  const [currentUser, setCurrentUser] = useState<Profile | null>(null)
  const [isMember, setIsMember] = useState(false)
  const [group, setGroup] = useState<Group | null>(null)
  const [tasks, setTasks] = useState<Task[]>([])
  const [taskSearch, setTaskSearch] = useState('')
  const [members, setMembers] = useState<ProfileDB[]>([])
  const [artifacts, setArtifacts] = useState<any[]>([])
  const [mounted, setMounted] = useState(false)
  const { onlineUsers } = usePresence()
  const supabase = createBrowserSupabaseClient()

  useEffect(() => { 
    setMounted(true)
    fetchData() 
  }, [groupId])

  const fetchData = async () => {
    setLoading(true)
    
    // 1. Get current user profile for membership verification
    const { data: { user: authUser } } = await supabase.auth.getUser()
    if (!authUser) return

    try {
      const [profileData, groupData, tasksData, membersData, artifactsData] = await Promise.all([
        supabase.from('profiles').select('*').eq('id', authUser.id).single(),
        supabase.from('groups').select('*').eq('id', groupId).single(),
        supabase.from('tasks').select('*').eq('group_id', groupId),
        supabase.from('profiles').select('*').eq('group_id', groupId).order('total_score', { ascending: false }),
        supabase.from('artifacts').select('*, tasks!inner(title, group_id)').eq('tasks.group_id', groupId)
      ])

      if (profileData.error && profileData.error.code !== 'PGRST116') throw profileData.error
      if (groupData.error) throw groupData.error

      const userProfile = profileData.data
      setCurrentUser(userProfile)
      
      // Check membership (using profile.group_id vs current page's groupId)
      const memberCheck = userProfile?.group_id === groupId
      setIsMember(memberCheck)

      if (groupData.data) setGroup(groupData.data)
      
      // Only set full data if user is a member or admin (security layer in UI)
      if (memberCheck) {
        if (tasksData.data) setTasks(tasksData.data)
        if (membersData.data) setMembers(membersData.data)
        setArtifacts(artifactsData.data || [])
      } else {
        // Restricted view: still show member count but hide task details
        if (membersData.data) setMembers(membersData.data)
      }
    } catch (err: any) {
      console.error('Analytics Fetch Error:', err)
    } finally {
      setLoading(false)
    }
  }

  const [hasSentRequest, setHasSentRequest] = useState(false)

  const handleJoinRequest = async () => {
    if (!currentUser || !group || hasSentRequest) return
    
    setLoading(true)
    try {
      const { sendJoinRequest } = await import('@/app/dashboard/join/actions')
      await sendJoinRequest(groupId, currentUser.full_name || 'A student')
      setHasSentRequest(true)
      addToast('Sync Success', 'Protocol access request has been transmitted to team leader.', 'success')
    } catch (err: any) {
      addToast('System Error', 'Failed to transmit access request: ' + err.message, 'error')
    } finally {
      setLoading(false)
    }
  }

  // --- METRICS ---
  const doneTasks = tasks.filter(t => t.status === 'Done').length
  const inProgressTasks = tasks.filter(t => t.status === 'In Progress').length
  const todoTasks = tasks.filter(t => t.status === 'To Do').length
  const completionRate = tasks.length > 0 ? Math.round((doneTasks / tasks.length) * 100) : 0
  const overdueTasks = tasks.filter(t => t.due_date && new Date(t.due_date) < new Date() && t.status !== 'Done').length
  const riskLevel = overdueTasks > 3 ? 'Critical' : overdueTasks > 0 ? 'Elevated' : 'Optimal'
  const totalEvidence = artifacts.length
  const evidenceDensity = tasks.length > 0 ? (totalEvidence / tasks.length).toFixed(1) : '0'

  const calculateMemberEffort = (memberId: string) =>
    tasks.filter(t => t.status === 'Done' && t.assignees?.includes(memberId)).length

  const totalGroupEffort = members.reduce((acc, m) => acc + calculateMemberEffort(m.id), 0)

  // --- CHART DATA ---
  const statusPieData = [
    { name: 'Done', value: doneTasks, color: STATUS_COLORS['Done'] },
    { name: 'In Progress', value: inProgressTasks, color: STATUS_COLORS['In Progress'] },
    { name: 'To Do', value: todoTasks, color: STATUS_COLORS['To Do'] },
  ].filter(d => d.value > 0)

  const categoryBarData = Object.keys(CATEGORY_COLORS)
    .map(cat => ({ name: cat.replace(' ', '\n'), fullName: cat, count: tasks.filter(t => t.category === cat).length, color: CATEGORY_COLORS[cat] }))
    .filter(d => d.count > 0)

  const memberBarData = members.map(m => ({
    name: (m.full_name || 'Unknown').split(' ')[0],
    completed: calculateMemberEffort(m.id),
    assigned: tasks.filter(t => t.assignees?.includes(m.id)).length,
  }))

  // --- EXPORT ---
  const exportToCSV = async () => {
    setLoading(true)
    const { data: logs } = await supabase.from('activity_log').select('*, profiles(full_name)').eq('group_id', groupId).order('created_at', { ascending: false })
    const headers = ['Type', 'User', 'Description', 'Timestamp']
    const rows = (logs || []).map(l => [l.action_type, (l.profiles as any)?.full_name || 'System', l.description, l.created_at])
    const csvContent = [headers, ...rows].map(e => e.map(c => `"${c}"`).join(',')).join('\n')
    setLoading(false)
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' })
    const url = URL.createObjectURL(blob)
    const link = document.createElement('a')
    link.setAttribute('href', url)
    link.setAttribute('download', `Espeezy_${group?.module_code || 'Report'}_${new Date().toISOString().split('T')[0]}.csv`)
    document.body.appendChild(link); link.click(); document.body.removeChild(link)
  }

  if (loading) return (
    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '60vh', color: 'var(--text-sub)' }}>
      <div style={{ textAlign: 'center' }}>
        <div style={{ width: '40px', height: '40px', border: '4px solid var(--border)', borderTopColor: 'var(--brand)', borderRadius: '50%', animation: 'spin 1s linear infinite', margin: '0 auto 1.5rem' }} />
        <p style={{ fontWeight: 600, fontSize: '1.1rem' }}>Retrieving project intelligence...</p>
      </div>
    </div>
  )

  if (!isMember) {
    return (
      <div style={{ maxWidth: '1000px', margin: '4rem auto', textAlign: 'center' }}>
        <div style={{ padding: '4rem', background: 'var(--bg-sub)', borderRadius: '32px', border: '1px solid var(--border)', boxShadow: 'var(--shadow-md)' }}>
           <div style={{ width: '80px', height: '80px', background: 'rgba(var(--brand-rgb), 0.1)', color: 'var(--brand)', borderRadius: '24px', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 2rem' }}>
              <ShieldCheck size={40} />
           </div>
           <h1 style={{ fontSize: '2.5rem', fontWeight: 900, marginBottom: '1rem' }}>{group?.name || 'Private Team'}</h1>
           <p style={{ color: 'var(--text-sub)', fontSize: '1.2rem', marginBottom: '2.5rem' }}>
             This team is private. You must be a member to see their work and news.
           </p>

           <div style={{ display: 'flex', gap: '2rem', justifyContent: 'center', marginBottom: '3rem' }}>
              <div style={{ textAlign: 'center' }}>
                 <div style={{ fontSize: '1.5rem', fontWeight: 900 }}>{members.length}</div>
                 <div style={{ fontSize: '0.8rem', color: 'var(--text-sub)', textTransform: 'uppercase', fontWeight: 700 }}>Team Members</div>
              </div>
              <div style={{ width: '1px', background: 'var(--border)' }} />
              <div style={{ textAlign: 'center' }}>
                 <div style={{ fontSize: '1.5rem', fontWeight: 900 }}>{group?.module_code || '---'}</div>
                 <div style={{ fontSize: '0.8rem', color: 'var(--text-sub)', textTransform: 'uppercase', fontWeight: 700 }}>Module Code</div>
              </div>
           </div>

           <div style={{ display: 'flex', gap: '1rem', justifyContent: 'center' }}>
              <button 
                onClick={handleJoinRequest} 
                disabled={hasSentRequest || loading}
                className={hasSentRequest ? "btn btn-secondary" : "btn btn-primary"} 
                style={{ padding: '1rem 2.5rem', width: 'auto', fontSize: '1.1rem', opacity: hasSentRequest ? 0.7 : 1, cursor: hasSentRequest ? 'default' : 'pointer' }}
              >
                {hasSentRequest ? 'Request sent. Waiting for team leader approval' : 'Request to Join'}
              </button>
              <Link href="/dashboard/network" className="btn btn-secondary" style={{ padding: '1rem 2.5rem', width: 'auto', fontSize: '1.1rem' }}>
                Back to Network
              </Link>
           </div>
        </div>
      </div>
    )
  }

  return (
    <div style={{ maxWidth: '1400px', margin: '0 auto', padding: '0 var(--p-safe)', animation: 'fadeIn 0.5s ease-out' }}>

      {/* Header */}
      <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', marginBottom: '2rem', flexWrap: 'wrap', gap: '1rem' }}>
        <div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', color: 'var(--brand)', marginBottom: '0.5rem', fontWeight: 700, fontSize: '0.7rem', textTransform: 'uppercase', letterSpacing: '1px' }}>
            <BarChart3 size={14} /><span>Analytics Summary</span>
          </div>
          <h1 className="fluid-h1" style={{ fontWeight: 900, margin: 0 }}>{group?.name || 'Project'}</h1>
          <p style={{ color: 'var(--text-sub)', fontSize: '0.9rem', marginTop: '0.5rem', fontWeight: 500 }}>
            {group?.module_code} • Live project tracking
          </p>
        </div>
        <div style={{ display: 'flex', gap: '0.5rem' }}>
          <button onClick={exportToCSV} className="btn btn-ghost btn-inline" style={{ display: 'flex', alignItems: 'center', gap: '0.4rem', fontSize: '0.8rem' }}>
            <Download size={14} /> CSV
          </button>
          <button onClick={() => window.print()} className="btn btn-primary btn-inline" style={{ display: 'flex', alignItems: 'center', gap: '0.4rem', fontSize: '0.8rem' }}>
            <Printer size={14} /> Print
          </button>
        </div>
      </header>

      {/* KPI Row */}
      <div className="kpi-grid" style={{ 
        display: 'grid', 
        gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))', 
        gap: 'var(--gap-sm)', 
        marginBottom: '1.5rem' 
      }}>
        {[
          { icon: <Zap size={18} />, label: 'Project Progress', value: `${completionRate}%`, color: 'var(--brand)', bg: 'rgba(56,189,248,0.1)' },
          { icon: <CheckCircle2 size={18} />, label: 'Completed Tasks', value: `${doneTasks}/${tasks.length}`, color: '#10b981', bg: 'rgba(16,185,129,0.1)' },
          { icon: <Users size={18} />, label: 'Team Members', value: `${members.length} / ${group?.capacity || 5}`, color: 'var(--brand)', bg: 'rgba(56,189,248,0.1)' },
          { icon: <AlertCircle size={18} />, label: 'Risk Assessment', value: riskLevel, color: riskLevel === 'Optimal' ? '#10b981' : '#ef4444', bg: riskLevel === 'Optimal' ? 'rgba(16,185,129,0.1)' : 'rgba(239,68,68,0.1)' },
          { icon: <ShieldCheck size={18} />, label: 'Evidence Density', value: evidenceDensity, color: '#10b981', bg: 'rgba(16,185,129,0.1)' },
          { icon: <Timer size={18} />, label: 'Overdue Tasks', value: overdueTasks, color: overdueTasks > 0 ? '#ef4444' : '#10b981', bg: overdueTasks > 0 ? 'rgba(239,68,68,0.1)' : 'rgba(16,185,129,0.1)' },
        ].map(kpi => (
          <div key={kpi.label} style={{ background: 'var(--surface)', border: '1px solid var(--border)', borderRadius: '16px', padding: 'var(--kpi-p)', display: 'flex', alignItems: 'center', gap: '0.75rem' }} className="kpi-card-print">
            <div style={{ padding: '0.5rem', background: kpi.bg, color: kpi.color, borderRadius: '10px', flexShrink: 0 }} className="print-hide">{kpi.icon}</div>
            <div style={{ minWidth: 0 }}>
              <div style={{ fontSize: '1.25rem', fontWeight: 900, color: kpi.color, lineHeight: 1 }}>{kpi.value}</div>
              <div style={{ fontSize: '0.65rem', fontWeight: 700, color: 'var(--text-sub)', marginTop: '0.2rem', textTransform: 'uppercase', letterSpacing: '0.5px' }}>{kpi.label}</div>
            </div>
          </div>
        ))}
      </div>

      {/* Charts Row */}
      <div className="charts-grid" style={{ 
        display: 'grid', 
        gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', 
        gap: 'var(--gap-sm)', 
        marginBottom: '1.5rem' 
      }}>

        {/* Task Status Donut */}
        <div style={{ background: 'var(--surface)', border: '1px solid var(--border)', borderRadius: '20px', padding: '1rem' }}>
          <h3 style={{ margin: '0 0 0.75rem', fontSize: '0.9rem', fontWeight: 800 }}>Task Status</h3>
          {!mounted || tasks.length === 0 ? (
            <div style={{ height: 160, display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--text-sub)', fontSize: '0.85rem' }}>{!mounted ? 'Calibrating...' : 'No tasks yet'}</div>
          ) : (
            <>
              <ResponsiveContainer width="100%" height={160}>
                <PieChart>
                  <Pie data={statusPieData} cx="50%" cy="50%" innerRadius={40} outerRadius={65} paddingAngle={2} dataKey="value">
                    {statusPieData.map((entry, i) => <Cell key={i} fill={entry.color} />)}
                  </Pie>
                  <Tooltip formatter={(v, n) => [`${v} tasks`, n]} contentStyle={{ background: 'var(--surface)', border: '1px solid var(--border)', borderRadius: '12px', fontSize: '0.75rem' }} />
                </PieChart>
              </ResponsiveContainer>
              <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap', marginTop: '0.25rem' }}>
                {statusPieData.map(d => (
                  <div key={d.name} style={{ display: 'flex', alignItems: 'center', gap: '0.3rem', fontSize: '0.7rem', fontWeight: 700 }}>
                    <div style={{ width: 8, height: 8, borderRadius: '50%', background: d.color }} />
                    <span style={{ color: 'var(--text-sub)' }}>{d.name} ({d.value})</span>
                  </div>
                ))}
              </div>
            </>
          )}
        </div>

        {/* Task Categories Bar */}
        <div style={{ background: 'var(--surface)', border: '1px solid var(--border)', borderRadius: '20px', padding: '1rem' }}>
          <h3 style={{ margin: '0 0 0.75rem', fontSize: '0.9rem', fontWeight: 800 }}>By Category</h3>
          {!mounted || categoryBarData.length === 0 ? (
            <div style={{ height: 160, display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--text-sub)', fontSize: '0.85rem' }}>{!mounted ? 'Calibrating...' : 'No tasks'}</div>
          ) : (
            <ResponsiveContainer width="100%" height={180}>
              <BarChart data={categoryBarData} layout="vertical" margin={{ left: -20, right: 10, top: 0, bottom: 0 }}>
                <XAxis type="number" hide />
                <YAxis type="category" dataKey="fullName" tick={{ fontSize: 9, fill: 'var(--text-sub)' }} width={80} />
                <Tooltip contentStyle={{ background: 'var(--surface)', border: '1px solid var(--border)', borderRadius: '12px', fontSize: '0.75rem' }} />
                <Bar dataKey="count" radius={[0, 4, 4, 0]} barSize={12}>
                  {categoryBarData.map((entry, i) => <Cell key={i} fill={entry.color} />)}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          )}
        </div>

        {/* Member Contribution */}
        <div style={{ background: 'var(--surface)', border: '1px solid var(--border)', borderRadius: '20px', padding: '1rem' }}>
          <h3 style={{ margin: '0 0 0.75rem', fontSize: '0.9rem', fontWeight: 800 }}>Contribution</h3>
          {!mounted || members.length === 0 ? (
            <div style={{ height: 160, display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--text-sub)', fontSize: '0.85rem' }}>{!mounted ? 'Calibrating...' : 'No members'}</div>
          ) : (
            <ResponsiveContainer width="100%" height={180}>
              <BarChart data={memberBarData} margin={{ left: -25, right: 10, top: 0, bottom: 10 }}>
                <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" vertical={false} />
                <XAxis dataKey="name" tick={{ fontSize: 9, fill: 'var(--text-sub)' }} angle={-30} textAnchor="end" interval={0} />
                <YAxis tick={{ fontSize: 9, fill: 'var(--text-sub)' }} allowDecimals={false} />
                <Tooltip contentStyle={{ background: 'var(--surface)', border: '1px solid var(--border)', borderRadius: '12px', fontSize: '0.75rem' }} />
                <Legend iconSize={8} wrapperStyle={{ fontSize: '0.65rem', paddingTop: '0.5rem' }} />
                <Bar dataKey="assigned" name="Assigned" fill="rgba(56,189,248,0.2)" radius={[2,2,0,0]} />
                <Bar dataKey="completed" name="Done" fill="#10b981" radius={[2,2,0,0]} />
              </BarChart>
            </ResponsiveContainer>
          )}
        </div>
      </div>

      {/* Progress Bar — overall */}
      <div style={{ background: 'var(--surface)', border: '1px solid var(--border)', borderRadius: '16px', padding: '1.25rem', marginBottom: '1.5rem' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '0.5rem' }}>
          <span style={{ fontWeight: 800, fontSize: '0.9rem' }}>Project Pulse</span>
          <span style={{ fontWeight: 900, fontSize: '1.1rem', color: 'var(--brand)' }}>{completionRate}%</span>
        </div>
        <div style={{ height: '8px', background: 'var(--bg-main)', borderRadius: '8px', overflow: 'hidden' }}>
          <div style={{ width: `${completionRate}%`, height: '100%', background: 'linear-gradient(90deg, var(--brand), #10b981)', borderRadius: '8px', transition: 'width 1s ease' }} />
        </div>
      </div>

      {/* Main Two-Column */}
      <div className="analytics-details-grid" style={{ 
        display: 'grid', 
        gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', 
        gap: 'var(--gap-sm)' 
      }}>

        {/* Team Leaderboard — fixed table */}
        <section style={{ background: 'var(--surface)', borderRadius: '20px', border: '1px solid var(--border)', padding: '1.25rem' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.25rem' }}>
            <h2 style={{ fontSize: '1.1rem', fontWeight: 900, margin: 0 }}>Team Leaderboard</h2>
          </div>

          {members.length === 0 ? (
            <p style={{ color: 'var(--text-sub)', textAlign: 'center', padding: '1rem 0' }}>Syncing with the institutional graph...</p>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
              {members.map((member, idx) => {
                const isOnline = onlineUsers.has(member.id)
                const tasksDone = calculateMemberEffort(member.id)
                const assigned = tasks.filter(t => t.assignees?.includes(member.id)).length
                
                return (
                  <div key={member.id} style={{
                    display: 'flex', alignItems: 'center', gap: '1rem',
                    padding: '1rem', borderRadius: '16px',
                    background: idx === 0 ? 'rgba(var(--brand-rgb), 0.05)' : 'var(--bg-sub)',
                    border: `1px solid ${idx === 0 ? 'var(--brand)' : 'var(--border)'}`,
                    transition: 'transform 0.2s ease',
                    position: 'relative',
                    overflow: 'hidden'
                  }}>
                    {/* Rank Badge */}
                    <div style={{ width: '28px', textAlign: 'center', fontWeight: 950, fontSize: '1rem', color: idx === 0 ? '#fbbf24' : 'var(--text-sub)', flexShrink: 0 }}>
                      {idx === 0 ? '🥇' : idx === 1 ? '🥈' : idx === 2 ? '🥉' : idx + 1}
                    </div>

                    {/* Avatar with Status */}
                    <div style={{ position: 'relative', flexShrink: 0 }}>
                      <div style={{ width: '40px', height: '40px', borderRadius: '12px', background: 'var(--surface)', border: '2px solid var(--border)', overflow: 'hidden', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                        {member.avatar_url ? <img src={member.avatar_url} style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <UserCircle size={24} color="var(--text-sub)" />}
                      </div>
                      <div style={{ position: 'absolute', bottom: -2, right: -2, width: '12px', height: '12px', borderRadius: '50%', background: isOnline ? '#10b981' : 'var(--border)', border: '2px solid var(--surface)', boxShadow: '0 0 10px rgba(0,0,0,0.1)' }} title={isOnline ? "Online" : "Offline"} />
                    </div>

                    {/* Member Info */}
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ fontWeight: 900, fontSize: '0.9rem', color: 'var(--text-main)', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{member.full_name || 'Anonymous Specialist'}</div>
                      <div style={{ display: 'flex', gap: '0.5rem', alignItems: 'center', marginTop: '0.2rem' }}>
                        <span style={{ fontSize: '0.65rem', color: 'var(--text-sub)', fontWeight: 700, textTransform: 'uppercase' }}>{member.role || 'Collaborator'}</span>
                        <span style={{ width: '2px', height: '2px', borderRadius: '50%', background: 'var(--border)' }} />
                        <span style={{ fontSize: '0.65rem', color: '#10b981', fontWeight: 800 }}>{tasksDone} Tasks Done</span>
                      </div>
                    </div>

                    {/* Points Tally */}
                    <div style={{ textAlign: 'right', flexShrink: 0 }}>
                      <div style={{ fontWeight: 950, fontSize: '1.25rem', color: idx === 0 ? 'var(--brand)' : 'var(--text-main)', lineHeight: 1 }}>{member.total_score ?? 0}</div>
                      <div style={{ fontSize: '0.6rem', color: 'var(--text-sub)', fontWeight: 800, textTransform: 'uppercase', letterSpacing: '0.5px' }}>Points</div>
                    </div>
                  </div>
                )
              })}
            </div>
          )}

          <div style={{ marginTop: '1.5rem', paddingTop: '1.25rem', borderTop: '1px solid var(--border)' }}>
            <h3 style={{ fontSize: '0.95rem', fontWeight: 900, marginBottom: '1rem' }}>Activity Stream</h3>
            <ActivityLogView groupId={groupId} limit={10} />
          </div>
        </section>

        {/* Right sidebar */}
        <section style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>

          {/* Pipeline Metrics */}
          <div style={{ background: 'var(--surface)', borderRadius: '20px', border: '1px solid var(--border)', padding: '1.25rem' }}>
            <h3 style={{ fontSize: '0.95rem', fontWeight: 900, marginBottom: '1rem', display: 'flex', alignItems: 'center', gap: '0.4rem' }}>
              <TrendingUp size={16} color="var(--brand)" /> Focus Areas
            </h3>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
              {Object.entries(CATEGORY_COLORS).map(([cat, color]) => {
                const count = tasks.filter(t => t.category === cat).length
                if (count === 0) return null
                const pct = tasks.length > 0 ? (count / tasks.length) * 100 : 0
                return (
                  <div key={cat}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '3px', fontSize: '0.75rem', color: 'var(--text-sub)', fontWeight: 700 }}>
                      <span>{cat}</span>
                      <span>{count}</span>
                    </div>
                    <div style={{ height: '4px', background: 'var(--bg-main)', borderRadius: '10px' }}>
                      <div style={{ width: `${pct}%`, height: '100%', background: color, borderRadius: '10px' }} />
                    </div>
                  </div>
                )
              })}
              {tasks.length === 0 && <p style={{ color: 'var(--text-sub)', fontSize: '0.8rem' }}>No data yet</p>}
            </div>
          </div>

          {/* Recently Completed */}
          <div style={{ background: 'var(--surface)', borderRadius: '20px', border: '1px solid var(--border)', padding: '1.25rem' }}>
           <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem', flexWrap: 'wrap', gap: '0.5rem' }}>
             <h3 style={{ fontSize: '0.95rem', fontWeight: 900, margin: 0, display: 'flex', alignItems: 'center', gap: '0.4rem' }}>
               <Clock size={16} color="var(--brand)" /> Success Log
             </h3>
             <div style={{ position: 'relative', width: '180px' }}>
                <Search size={14} style={{ position: 'absolute', left: '0.75rem', top: '50%', transform: 'translateY(-50%)', color: 'var(--text-sub)' }} />
                <input 
                  type="text" 
                  placeholder="Filter tasks..." 
                  value={taskSearch}
                  onChange={(e) => setTaskSearch(e.target.value)}
                  style={{ width: '100%', padding: '0.4rem 0.5rem 0.4rem 2rem', borderRadius: '8px', background: 'var(--bg-main)', border: '1px solid var(--border)', color: 'var(--text-main)', fontSize: '0.75rem' }}
                />
             </div>
           </div>
            {tasks.filter(t => t.status === 'Done').length === 0 ? (
              <p style={{ color: 'var(--text-sub)', fontSize: '0.8rem' }}>Check back later</p>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '0.6rem' }}>
                {tasks
                  .filter(t => t.status === 'Done')
                  .filter(t => t.title.toLowerCase().includes(taskSearch.toLowerCase()))
                  .slice(0, 10)
                  .map(t => (
                  <div key={t.id} style={{ display: 'flex', alignItems: 'center', gap: '0.6rem', padding: '0.5rem', background: 'var(--bg-main)', borderRadius: '10px' }}>
                    <FileCheck size={14} color="#10b981" style={{ flexShrink: 0 }} />
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ fontSize: '0.8rem', fontWeight: 800, whiteSpace: 'nowrap', textOverflow: 'ellipsis', overflow: 'hidden' }}>{t.title}</div>
                      <div style={{ fontSize: '0.65rem', color: 'var(--text-sub)' }}>
                        {t.category && <span style={{ color: CATEGORY_COLORS[t.category] || 'var(--brand)', fontWeight: 800 }}>{t.category}</span>}
                      </div>
                    </div>
                  </div>
                ))}
                <Link href="/dashboard" style={{ fontSize: '0.75rem', color: 'var(--brand)', fontWeight: 800, textDecoration: 'none', display: 'flex', alignItems: 'center', gap: '0.2rem', marginTop: '0.4rem' }}>
                  Full Board <ChevronRight size={12} />
                </Link>
              </div>
            )}
          </div>

        </section>
      </div>

      <style jsx>{`
        .kpi-grid, .charts-grid, .analytics-details-grid {
           --gap-sm: 1.5rem;
           --kpi-p: 1.25rem 1.5rem;
        }
        @media (max-width: 768px) {
          .kpi-grid { 
            grid-template-columns: repeat(2, 1fr) !important; 
            --gap-sm: 0.75rem;
            --kpi-p: 1rem;
          }
          .charts-grid, .analytics-details-grid {
            --gap-sm: 1rem;
          }
        }
        @media print {
          @page { margin: 1cm; }
          button, .print-hide, .btn, .panel-tool, header .btn-inline { display: none !important; }
          body { background: white !important; color: black !important; padding: 0 !important; }
          .page-fade { animation: none !important; transform: none !important; }
          .kpi-grid { gap: 0.5rem !important; }
          .kpi-card-print { border: 1px solid #eee !important; box-shadow: none !important; }
          .charts-grid { display: block !important; }
          .charts-grid > div { margin-bottom: 2rem !important; page-break-inside: avoid !important; border: 1px solid #eee !important; }
          aside, nav, .sidebar-container, .mobile-header { display: none !important; }
          .main-content { margin: 0 !important; padding: 0 !important; width: 100% !important; }
        }
        @keyframes spin { to { transform: rotate(360deg); } }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  )
}

'use client'

import { useState, useEffect, useMemo, useCallback } from 'react'
import { useRouter } from 'next/navigation'
import { createBrowserSupabaseClient } from '@/utils/supabase/client'
import { 
  Sparkles, 
  Gamepad2, 
  Users, 
  BrainCircuit, 
  ShieldCheck, 
  Terminal, 
  Zap,
  CheckCircle2,
  Play,
  Loader2,
  Dna,
  Cpu,
  RefreshCw
} from 'lucide-react'
import { useProfile } from '@/context/ProfileContext'
import { usePresence } from '@/components/PresenceProvider'
import { useNotifications } from '@/components/NotificationProvider'
import { useSmartLoading } from '@/components/GlobalLoadingProvider'

import { motion, AnimatePresence } from 'framer-motion'

const TOPICS = [
  { 
    id: 'cyber_ethics', 
    name: 'Cyber Ethics & Law', 
    icon: ShieldCheck, 
    color: 'var(--error)',
    description: 'Master the legal landscape of the digital academic frontier.'
  },
  { 
    id: 'logic_puzzles', 
    name: 'Algorithmic Riddles', 
    icon: BrainCircuit, 
    color: 'var(--brand)',
    description: 'Test your raw logic with complex computing patterns.'
  },
  { 
    id: 'pop_culture', 
    name: 'Digital History', 
    icon: Gamepad2, 
    color: 'var(--success)',
    description: 'From Turing to Jobs: The history of the digital era.'
  },
  { 
    id: 'institutional', 
    name: 'Espeezy Protocols', 
    icon: Terminal, 
    color: 'var(--accent)',
    description: "Deep dive into the app's advanced governance."
  }
]

export default function ChillOutHub() {
  const router = useRouter()
  const { profile } = useProfile()
  const { onlineUsers } = usePresence()
  const { addToast } = useNotifications()
  const { withLoading } = useSmartLoading()
  const supabase = useMemo(() => createBrowserSupabaseClient(), [])

  const [step, setStep] = useState(1) // 1: Topic, 2: Config, 3: Preview, 4: Players
  const [selectedTopic, setSelectedTopic] = useState<typeof TOPICS[0] | null>(null)
  
  // Config State
  const [difficulty, setDifficulty] = useState<'Easy' | 'Medium' | 'Hard'>('Medium')
  const [gameMode, setGameMode] = useState<'Speed Recall' | 'AI Evaluated'>('Speed Recall')
  const [roundCount, setRoundCount] = useState<number>(5)
  
  const [isGenerating, setIsGenerating] = useState(false)
  const [questions, setQuestions] = useState<any[]>([])
  const [selectedPlayers, setSelectedPlayers] = useState<string[]>([])
  const [onlineProfiles, setOnlineProfiles] = useState<any[]>([])
  const [userStats, setUserStats] = useState<any>(null)

  // 1. Fetch Stats & Profiles
  useEffect(() => {
    async function fetchData() {
      if (!profile?.id) return

      // Fetch User Stats
      const { data: stats } = await supabase
        .from('user_game_stats')
        .select('*')
        .eq('user_id', profile.id)
        .maybeSingle()
      
      if (!stats) {
        const { data: newStats } = await supabase
          .from('user_game_stats')
          .insert({ user_id: profile.id, total_xp: 0, level: 1 })
          .select()
          .single()
        setUserStats(newStats)
      } else {
        setUserStats(stats)
      }

      // Fetch Online Profiles
      if (onlineUsers.size > 0) {
        const ids = Array.from(onlineUsers)
        const { data } = await supabase
          .from('profiles')
          .select('id, full_name, avatar_url')
          .in('id', ids)
        
        if (data) setOnlineProfiles(data.filter(p => p.id !== profile?.id))
      }
    }
    fetchData()
  }, [onlineUsers, supabase, profile?.id])

  // 2. AI Synthesis
  const handleTopicSelect = (topic: typeof TOPICS[0]) => {
    setSelectedTopic(topic)
    setStep(2)
  }

  const handleInitializeQuestions = async () => {
    setIsGenerating(true)
    try {
      const res = await fetch('/api/ai/quiz', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          topic: selectedTopic?.name,
          difficulty,
          mode: gameMode,
          count: roundCount
        })
      })
      const data = await res.json()
      if (data.questions) {
        setQuestions(data.questions)
        setStep(3)
      } else {
        throw new Error(data.error || 'Synthesis error')
      }
    } catch (err: any) {
      addToast('Sync Failure', err.message, 'error')
    } finally {
      setIsGenerating(false)
    }
  }

  const togglePlayer = (id: string) => {
    setSelectedPlayers(prev => 
      prev.includes(id) ? prev.filter(p => p !== id) : [...prev, id]
    )
  }

  const handleStartGame = async () => {
    if (selectedPlayers.length === 0) {
      addToast('No Players', 'You must invite at least one online peer.', 'warning')
      return
    }

    const roomId = `skirmish_${Date.now()}`
    
    await withLoading(async () => {
      // 1. Create Game Session in DB (Archive)
      await supabase.from('game_sessions').insert({
        room_id: roomId,
        creator_id: profile?.id,
        topic_id: selectedTopic?.id,
        difficulty,
        mode: gameMode
      })

      // 2. Send Notifications
      for (const playerId of selectedPlayers) {
        await supabase.from('notifications').insert({
          user_id: playerId,
          type: 'skirmish_invite',
          title: 'SKIRMISH DETECTED',
          message: `${profile?.full_name || 'A Peer'} challenged you to ${difficulty} ${selectedTopic?.name}.`,
          metadata: { room_id: roomId, topic_id: selectedTopic?.id, mode: gameMode, questions }
        })
      }
      
      // 3. SECURE HAND-OFF: Save questions for the room to pick up
      if (typeof window !== 'undefined') {
        sessionStorage.setItem(`skirmish_setup_${roomId}`, JSON.stringify({ questions, config: { difficulty, mode: gameMode } }))
      }
      
      router.push(`/dashboard/chillout/room/${roomId}?id=${roomId}`)
    }, 'Initializing Competitive Flux...')
  }

  return (
    <div className="page-fade" style={{ display: 'flex', flexDirection: 'column', gap: '2rem', paddingBottom: '4rem' }}>
      
      {/* ── STATS HUD ─────────────────────────────────────────── */}
      <AnimatePresence>
        <motion.div 
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', background: 'var(--surface)', padding: '1.25rem 2rem', borderRadius: '24px', border: '1px solid var(--border)', boxShadow: 'var(--shadow-sm)' }}
        >
          <div style={{ display: 'flex', alignItems: 'center', gap: '1.5rem' }}>
             <div style={{ position: 'relative' }}>
                <div style={{ width: '60px', height: '60px', borderRadius: '18px', background: 'linear-gradient(135deg, var(--brand), #8b5cf6)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', fontWeight: 950, fontSize: '1.5rem', boxShadow: '0 8px 16px rgba(var(--brand-rgb), 0.3)' }}>
                  {userStats?.level || 1}
                </div>
                <div style={{ position: 'absolute', bottom: -5, left: '50%', transform: 'translateX(-50%)', background: 'var(--brand)', color: 'white', padding: '2px 8px', borderRadius: '6px', fontSize: '0.6rem', fontWeight: 900, whiteSpace: 'nowrap' }}>LVL</div>
             </div>
             <div>
                <h4 style={{ margin: 0, fontSize: '1.1rem', fontWeight: 950, letterSpacing: '-0.02em' }}>{userStats?.rank_title || 'Novice Scholar'}</h4>
                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginTop: '0.4rem' }}>
                   <div style={{ width: '200px', height: '6px', background: 'var(--bg-main)', borderRadius: '10px', overflow: 'hidden' }}>
                      <motion.div 
                        initial={{ width: 0 }} 
                        animate={{ width: `${(userStats?.total_xp % 100)}%` }}
                        style={{ height: '100%', background: 'var(--brand)' }} 
                      />
                   </div>
                   <span style={{ fontSize: '0.7rem', fontWeight: 800, color: 'var(--text-sub)' }}>{userStats?.total_xp || 0} XP Total</span>
                </div>
             </div>
          </div>
          <div style={{ display: 'flex', gap: '2rem' }}>
             <div style={{ textAlign: 'center' }}>
                <div style={{ fontSize: '1.25rem', fontWeight: 950 }}>{userStats?.wins || 0}</div>
                <div style={{ fontSize: '0.65rem', fontWeight: 700, color: 'var(--text-sub)', textTransform: 'uppercase' }}>Wins</div>
             </div>
             <div style={{ textAlign: 'center' }}>
                <div style={{ fontSize: '1.25rem', fontWeight: 950 }}>{userStats?.games_played || 0}</div>
                <div style={{ fontSize: '0.65rem', fontWeight: 700, color: 'var(--text-sub)', textTransform: 'uppercase' }}>Battles</div>
             </div>
          </div>
        </motion.div>
      </AnimatePresence>

      {/* ── HEADER ────────────────────────────────────────────── */}
      <header>
        <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '0.5rem' }}>
          <div style={{ padding: '0.75rem', borderRadius: '14px', background: 'rgba(var(--brand-rgb), 0.1)', color: 'var(--brand)' }}>
             <Sparkles size={32} />
          </div>
          <div>
            <h1 style={{ fontSize: '2.25rem', fontWeight: 950, letterSpacing: '-0.04em', margin: 0 }}>
              Chill Out <span style={{ color: 'var(--brand)' }}>Zone</span>
            </h1>
            <p style={{ color: 'var(--text-sub)', fontWeight: 600, fontSize: '0.9rem' }}>Decompress and dominate with real-time academic skirmishes.</p>
          </div>
        </div>
      </header>

      {/* ── CONTENT RENDERING ────────────────────────────────────── */}
      {isGenerating ? (
        <div style={{ height: '400px', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', textAlign: 'center' }}>
          <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 4, ease: "linear" }}>
             <Dna size={80} style={{ color: 'var(--brand)' }} />
          </motion.div>
          <h2 style={{ fontSize: '1.5rem', fontWeight: 950, letterSpacing: '-0.03em', marginBottom: '0.5rem', marginTop: '2rem' }}>Synthesizing Shards</h2>
          <p style={{ color: 'var(--text-sub)', fontWeight: 700, fontSize: '0.85rem' }}>Constructing {difficulty} logic for {selectedTopic?.name}...</p>
        </div>
      ) : (
        <AnimatePresence mode="wait">
          {step === 1 && (
            <motion.div 
              key="step1" 
              initial={{ opacity: 0, x: 20 }} 
              animate={{ opacity: 1, x: 0 }} 
              exit={{ opacity: 0, x: -20 }}
              style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '1.5rem' }}
            >
              {TOPICS.map(topic => (
                <button 
                  key={topic.id}
                  onClick={() => handleTopicSelect(topic)}
                  className="glass hover-card"
                  style={{ padding: '2rem', borderRadius: '24px', border: '1px solid var(--border)', textAlign: 'left', background: 'var(--surface)', cursor: 'pointer', display: 'flex', flexDirection: 'column', gap: '1rem' }}
                >
                  <div style={{ width: '56px', height: '56px', borderRadius: '16px', background: `rgba(${topic.id === 'cyber_ethics' ? '239, 68, 68' : 'var(--brand-rgb)'}, 0.1)`, color: topic.color, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                     <topic.icon size={28} />
                  </div>
                  <div>
                    <h3 style={{ margin: 0, fontSize: '1.25rem', fontWeight: 900, letterSpacing: '-0.02em', color: 'var(--text-main)' }}>{topic.name}</h3>
                    <p style={{ margin: '0.5rem 0 0', fontSize: '0.85rem', color: 'var(--text-sub)', lineHeight: 1.5, fontWeight: 500 }}>{topic.description}</p>
                  </div>
                </button>
              ))}
            </motion.div>
          )}

          {step === 2 && (
            <motion.div 
              key="step2" 
              initial={{ opacity: 0, x: 20 }} 
              animate={{ opacity: 1, x: 0 }} 
              exit={{ opacity: 0, x: -20 }}
              style={{ background: 'var(--surface)', borderRadius: '32px', border: '1px solid var(--border)', padding: '2.5rem', maxWidth: '800px', margin: '0 auto', width: '100%' }}
            >
               <h2 style={{ fontSize: '1.75rem', fontWeight: 950, marginBottom: '2rem' }}>Configure Skirmish</h2>
               
               <div style={{ display: 'flex', flexDirection: 'column', gap: '2rem' }}>
                  {/* Difficulty */}
                  <div>
                    <label style={{ fontSize: '0.75rem', fontWeight: 900, textTransform: 'uppercase', color: 'var(--text-sub)', display: 'block', marginBottom: '1rem' }}>Challenge Level</label>
                    <div style={{ display: 'flex', gap: '0.75rem' }}>
                       {['Easy', 'Medium', 'Hard'].map(d => (
                         <button key={d} onClick={() => setDifficulty(d as any)} style={{ flex: 1, padding: '1rem', borderRadius: '14px', border: '2px solid', borderColor: difficulty === d ? 'var(--brand)' : 'var(--border)', background: difficulty === d ? 'rgba(var(--brand-rgb), 0.05)' : 'var(--bg-sub)', color: difficulty === d ? 'var(--text-main)' : 'var(--text-sub)', fontWeight: 900, cursor: 'pointer', transition: '0.2s' }}>{d}</button>
                       ))}
                    </div>
                  </div>

                  {/* Mode */}
                  <div>
                    <label style={{ fontSize: '0.75rem', fontWeight: 900, textTransform: 'uppercase', color: 'var(--text-sub)', display: 'block', marginBottom: '1rem' }}>Grading Protocol</label>
                    <div style={{ display: 'flex', gap: '0.75rem' }}>
                       {['Speed Recall', 'AI Evaluated'].map(m => (
                         <button key={m} onClick={() => setGameMode(m as any)} style={{ flex: 1, padding: '1rem', borderRadius: '14px', border: '2px solid', borderColor: gameMode === m ? 'var(--brand)' : 'var(--border)', background: gameMode === m ? 'rgba(var(--brand-rgb), 0.05)' : 'var(--bg-sub)', color: gameMode === m ? 'var(--text-main)' : 'var(--text-sub)', fontWeight: 900, cursor: 'pointer', transition: '0.2s', textAlign: 'left' }}>
                            <div style={{ fontWeight: 950 }}>{m}</div>
                            <div style={{ fontSize: '0.65rem', opacity: 0.6, marginTop: '2px' }}>{m === 'Speed Recall' ? 'Reveal & choices' : 'Text input + AI Grade'}</div>
                         </button>
                       ))}
                    </div>
                  </div>

                  {/* Rounds */}
                  <div>
                    <label style={{ fontSize: '0.75rem', fontWeight: 900, textTransform: 'uppercase', color: 'var(--text-sub)', display: 'block', marginBottom: '1rem' }}>Skirmish Depth</label>
                    <div style={{ display: 'flex', gap: '0.75rem' }}>
                       {[3, 5, 10].map(r => (
                         <button key={r} onClick={() => setRoundCount(r)} style={{ flex: 1, padding: '1rem', borderRadius: '14px', border: '2px solid', borderColor: roundCount === r ? 'var(--brand)' : 'var(--border)', background: roundCount === r ? 'rgba(var(--brand-rgb), 0.05)' : 'var(--bg-sub)', color: roundCount === r ? 'var(--text-main)' : 'var(--text-sub)', fontWeight: 900, cursor: 'pointer', transition: '0.2s' }}>{r} Rounds</button>
                       ))}
                    </div>
                  </div>
               </div>

               <div style={{ display: 'flex', gap: '1rem', marginTop: '3rem' }}>
                  <button onClick={() => setStep(1)} className="btn btn-secondary" style={{ flex: 1 }}>Back</button>
                  <button onClick={handleInitializeQuestions} className="btn btn-primary" style={{ flex: 2, fontWeight: 950 }}>INITIALIZE AI ENGINE</button>
               </div>
            </motion.div>
          )}

          {step === 3 && (
            <motion.div 
              key="step3" 
              initial={{ opacity: 0, x: 20 }} 
              animate={{ opacity: 1, x: 0 }} 
              exit={{ opacity: 0, x: -20 }}
              style={{ background: 'var(--surface)', borderRadius: '24px', border: '1px solid var(--border)', padding: '2rem' }}
            >
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                 <h2 style={{ fontSize: '1.5rem', fontWeight: 950, margin: 0 }}>Battle Log Configuration</h2>
                 <div style={{ display: 'flex', gap: '1rem' }}>
                    <button onClick={() => setStep(2)} className="btn btn-secondary" style={{ fontSize: '0.8rem' }}>Re-Sync AI</button>
                    <button onClick={() => setStep(4)} className="btn btn-primary" style={{ fontSize: '0.8rem', fontWeight: 950 }}>PROCEED TO INVITES</button>
                 </div>
              </div>
              
              <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                {questions.map((q, i) => (
                  <div key={i} style={{ padding: '1.25rem', borderRadius: '16px', border: '1px solid var(--border)', background: 'var(--bg-sub)', display: 'flex', gap: '1rem' }}>
                    <div style={{ width: '24px', height: '24px', borderRadius: '50%', background: 'var(--brand)', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.75rem', fontWeight: 900, flexShrink: 0 }}>{i + 1}</div>
                    <div style={{ flex: 1 }}>
                      <div style={{ display: 'flex', gap: '0.5rem', marginBottom: '0.4rem' }}>
                         <span style={{ fontSize: '0.6rem', padding: '2px 6px', borderRadius: '4px', background: 'rgba(var(--brand-rgb), 0.1)', color: 'var(--brand)', fontWeight: 900, textTransform: 'uppercase' }}>{q.type}</span>
                         <span style={{ fontSize: '0.6rem', padding: '2px 6px', borderRadius: '4px', background: 'var(--bg-main)', color: 'var(--text-sub)', fontWeight: 900 }}>D-IDX: {q.difficulty_multiplier || 1}</span>
                      </div>
                      <div style={{ fontWeight: 800, fontSize: '0.95rem', color: 'var(--text-main)' }}>{q.question}</div>
                    </div>
                  </div>
                ))}
              </div>
            </motion.div>
          )}

          {step === 4 && (
            <motion.div 
              key="step4" 
              initial={{ opacity: 0, x: 20 }} 
              animate={{ opacity: 1, x: 0 }} 
              style={{ display: 'flex', flexDirection: 'column', gap: '2rem' }}
            >
              <div style={{ background: 'var(--surface)', borderRadius: '24px', border: '1px solid var(--border)', padding: '2.5rem' }}>
                <h2 style={{ fontSize: '1.5rem', fontWeight: 950, marginBottom: '0.5rem' }}>Deploy Challenge Signals</h2>
                <p style={{ color: 'var(--text-sub)', fontSize: '0.9rem', marginBottom: '2rem' }}>Only online scholars can receive real-time game signals.</p>
                
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '1.25rem' }}>
                  {onlineProfiles.length === 0 ? (
                    <div style={{ gridColumn: '1/-1', textAlign: 'center', padding: '4rem', color: 'var(--text-sub)' }}>
                      <Users size={48} style={{ opacity: 0.1, marginBottom: '1rem' }} />
                      <p style={{ fontWeight: 700 }}>No other scholars are currently online.</p>
                    </div>
                  ) : (
                    onlineProfiles.map(p => (
                      <button 
                        key={p.id}
                        onClick={() => togglePlayer(p.id)}
                        className="glass"
                        style={{ 
                          padding: '1.25rem', 
                          borderRadius: '18px', 
                          border: '2px solid', 
                          background: selectedPlayers.includes(p.id) ? 'rgba(var(--brand-rgb), 0.05)' : 'var(--surface)',
                          borderColor: selectedPlayers.includes(p.id) ? 'var(--brand)' : 'var(--border)',
                          display: 'flex',
                          alignItems: 'center',
                          gap: '1rem',
                          cursor: 'pointer',
                          transition: 'all 0.2s',
                          textAlign: 'left'
                        }}
                      >
                        <div style={{ width: '36px', height: '36px', borderRadius: '12px', overflow: 'hidden', background: 'var(--bg-main)', border: '1px solid var(--border)' }}>
                          {p.avatar_url ? <img src={p.avatar_url} style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <div style={{ width: '100%', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><Users size={16} /></div>}
                        </div>
                        <span style={{ fontSize: '0.9rem', fontWeight: 900, flex: 1, color: 'var(--text-main)' }}>{p.full_name}</span>
                        {selectedPlayers.includes(p.id) && <motion.div initial={{ scale: 0 }} animate={{ scale: 1 }}><CheckCircle2 size={18} color="var(--brand)" /></motion.div>}
                      </button>
                    ))
                  )}
                </div>
              </div>

              <div style={{ display: 'flex', justifyContent: 'center', gap: '1rem' }}>
                 <button onClick={() => setStep(3)} className="btn btn-secondary" style={{ padding: '1rem 2.5rem' }}>Back</button>
                 <button 
                   onClick={handleStartGame} 
                   className="btn btn-primary" 
                   style={{ padding: '1rem 4rem', borderRadius: '20px', display: 'flex', alignItems: 'center', gap: '1rem', fontWeight: 950, fontSize: '1.1rem' }}
                   disabled={selectedPlayers.length === 0}
                 >
                   <Play size={22} fill="currentColor" />
                   INITIATE SKIRMISH
                 </button>
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      )}

      <style jsx>{`
        .hover-card:hover {
          transform: translateY(-8px);
          border-color: var(--brand) !important;
          box-shadow: 0 20px 40px rgba(var(--brand-rgb), 0.2);
        }
        .page-fade { animation: fadeIn 0.4s ease-out; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .animate-pulse { animation: pulse 2s cubic-bezier(0.4, 0, 0.6, 1) infinite; }
        @keyframes pulse { 0%, 100% { opacity: 1; } 50% { opacity: .5; } }
        
        .neural-bg {
          position: fixed;
          top: 0;
          left: 0;
          right: 0;
          bottom: 0;
          background: radial-gradient(circle at 50% 50%, rgba(var(--brand-rgb), 0.03) 0%, transparent 70%);
          z-index: -1;
          pointer-events: none;
        }

        .neural-bg::after {
          content: '';
          position: absolute;
          inset: 0;
          background-image: url("data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%239C92AC' fill-opacity='0.03'%3E%3Cpath d='M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");
        }
      `}</style>
      <div className="neural-bg" />
    </div>
  )
}

'use client'

import React, { useState, useEffect } from 'react'
import { useParams, useRouter } from 'next/navigation'
import { 
  RoomProvider, 
  useStorage, 
  useMutation, 
  useMyPresence, 
  useOthers
} from '@/liveblocks.config'
import { LiveList, LiveObject } from '@liveblocks/client'
import { 
  Trophy, 
  Timer, 
  Crown, 
  Zap,
  Loader2,
  AlertCircle
} from 'lucide-react'
import { useProfile } from '@/context/ProfileContext'
import { useNotifications } from '@/components/NotificationProvider'
import confetti from 'canvas-confetti'
import { motion, AnimatePresence } from 'framer-motion'
import { jsPDF } from 'jspdf'
import { updateUserGameStats } from '@/app/dashboard/actions'
import { SkirmishTimer } from '@/components/skirmish/SkirmishTimer'

export default function QuizRoomPage() {
  const params = useParams()
  const roomId = params?.id as string
  
  if (!roomId) return <div style={{ height: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><Loader2 className="animate-spin" /></div>

  return (
    <RoomProvider 
      id={roomId} 
      initialStorage={{ 
        tasks: new LiveList([]),
        messages: new LiveList([]),
        quizQuestions: new LiveList([]),
        quizScores: new LiveList([]),
        quizStatus: 'setup',
        currentQuestionIndex: 0,
        activeTurnUserId: null,
        gameId: roomId,
        roundStartTime: 0,
        timerDuration: 20,
        config: new LiveObject({ difficulty: 'Medium', mode: 'Speed Recall' })
      }}
      initialPresence={{ draggingTaskId: null, isThinking: false, lastAction: null }}
    >
      <QuizGameContainer roomId={roomId} />
    </RoomProvider>
  )
}

function QuizGameContainer({ roomId }: { roomId: string }) {
  const { profile } = useProfile()
  const { addToast } = useNotifications()
  const router = useRouter()
  const [me, updateMyPresence] = useMyPresence()
  const others = useOthers()
  
  const quizStatus = useStorage(s => s.quizStatus)
  const questions = useStorage(s => s.quizQuestions)
  const currentIdx = useStorage(s => s.currentQuestionIndex) ?? 0
  const scores = useStorage(s => s.quizScores)
  const activeTurnId = useStorage(s => s.activeTurnUserId)
  const roundStartTime = useStorage(s => s.roundStartTime)
  const timerDuration = useStorage(s => s.timerDuration) ?? 20
  const config = useStorage(s => s.config)
  
  const [showIntro, setShowIntro] = useState(true)
  const [selectedOption, setSelectedOption] = useState<number | null>(null)
  const [hasAnswered, setHasAnswered] = useState(false)
  const [textAnswer, setTextAnswer] = useState('')
  const [isRevealed, setIsRevealed] = useState(false)
  const [isGrading, setIsGrading] = useState(false)
  const [aiCritique, setAiCritique] = useState('')

  // ── LOADING GUARD ──────────────────────────────────────────────
  if (quizStatus === null) {
    return (
      <div style={{ height: 'calc(var(--vh-dynamic) - 6rem)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: '1rem', color: 'var(--text-sub)' }}>
         <Loader2 className="animate-spin" size={32} />
         <div style={{ fontWeight: 800, textTransform: 'uppercase', letterSpacing: '0.2em', fontSize: '0.8rem' }}>Calibrating Storage...</div>
      </div>
    )
  }
  const [hasSetupData, setHasSetupData] = useState(false)
  
  useEffect(() => {
    if (typeof window !== 'undefined') {
        const setup = sessionStorage.getItem(`skirmish_setup_${roomId}`)
        if (setup) setHasSetupData(true)
    }
  }, [roomId])

  const handleStartSkirmish = useMutation(({ storage }) => {
    const setupRaw = sessionStorage.getItem(`skirmish_setup_${roomId}`)
    if (!setupRaw) return

    try {
        const { questions: newQs, config: setupConfig } = JSON.parse(setupRaw)
        
        // Populate Storage
        const qList = storage.get('quizQuestions')
        qList.clear()
        newQs.forEach((q: any) => qList.push(q))
        
        storage.set('quizStatus', 'playing')
        storage.set('currentQuestionIndex', 0)
        storage.set('roundStartTime', Date.now())
        storage.set('activeTurnUserId', profile?.id ?? null)
        
        const firstQ = newQs[0]
        const firstDuration = (firstQ?.difficulty_multiplier || 2) * 10
        storage.set('timerDuration', firstDuration)
        
        const conf = storage.get('config')
        conf.set('difficulty', setupConfig.difficulty)
        conf.set('mode', setupConfig.mode)

        addToast('Skirmish Injected', 'AI shards synchronized. Battle started!', 'success')
        sessionStorage.removeItem(`skirmish_setup_${roomId}`)
    } catch (err) {
        addToast('Critical Failure', 'Mental sync aborted.', 'error')
    }
  }, [roomId, profile])

  // ── TIMER LOGIC ──────────────────────────────────────────────────
  // Timer controlled by SkirmishTimer component now

  // ── RESET UI ON QUESTION CHANGE ──────────────────────────────────
  useEffect(() => {
    setSelectedOption(null)
    setHasAnswered(false)
    setTextAnswer('')
    setIsRevealed(false)
    setAiCritique('')
  }, [currentIdx, timerDuration])

  // ── MUTATIONS ───────────────────────────────────────────────────
  const submitActionResult = useMutation(({ storage }, isCorrect: boolean, bonusXp = 0) => {
    const userId = profile?.id
    if (!userId) return

    // Update Scores
    const scoresList = storage.get('quizScores')
    let found = false
    const pointsToAdd = isCorrect ? (100 + bonusXp) : -50

    for (let i = 0; i < scoresList.length; i++) {
        const item = scoresList.get(i)
        if (item && item.userId === userId) {
            scoresList.set(i, { ...item, points: Math.max(0, item.points + pointsToAdd) })
            found = true
            break
        }
    }
    if (!found) {
        scoresList.push({ userId, userName: profile?.full_name || 'Anonymous', points: Math.max(0, pointsToAdd) })
    }

    // Next Round Setup
    const currentQList = storage.get('quizQuestions')
    const nextIdx = storage.get('currentQuestionIndex') + 1
    
    if (nextIdx < currentQList.length) {
      storage.set('currentQuestionIndex', nextIdx)
      storage.set('roundStartTime', Date.now())
      
      const nextQ = currentQList.get(nextIdx)
      if (nextQ) {
          const nextDuration = (nextQ.difficulty_multiplier || 2) * 10
          storage.set('timerDuration', nextDuration)
      }

      const players = [userId, ...others.map(o => o.id)].filter(Boolean)
      storage.set('activeTurnUserId', players[nextIdx % players.length])
    } else {
      storage.set('quizStatus', 'results')
      handleFinalizeStats()
    }
  }, [profile, others])

  const handleSkipRound = () => {
    submitActionResult(false)
    addToast('Time Out!', 'The round was skipped due to temporal flux.', 'warning')
  }

  const handleFinalizeStats = async () => {
    if (!profile?.id || !scores) return
    const myScore = scores.find(s => s.userId === profile.id)?.points || 0
    const isWinner = scores.length > 1 && myScore >= Math.max(...scores.map(s => s.points))

    await updateUserGameStats(profile.id, Math.floor(myScore / 4), isWinner)
  }

  const handleResetSkirmish = useMutation(({ storage }) => {
    storage.set('quizStatus', 'setup')
    storage.set('currentQuestionIndex', 0)
    storage.get('quizQuestions').clear()
    storage.set('activeTurnUserId', null)
    addToast('Archives Reset', 'Neural buffer cleared. Ready for a new iteration.', 'info')
  }, [])

  // ── COLLECTIVE CELEBRATION ────────────────────────────────────
  useEffect(() => {
    if (quizStatus === 'results') {
        confetti({ 
          particleCount: 150, 
          spread: 80, 
          origin: { y: 0.6 },
          colors: ['#0ea5e9', '#38bdf8', '#fbbf24']
        })
        addToast('Ascension Validated', 'The collective knowledge has been successfully assimilated.', 'success')
    }
  }, [quizStatus])

  // ── INTERACTION HANDLERS ───────────────────────────────────────
  const currentQ = questions && questions.length > currentIdx ? questions[currentIdx] : null
  const isMyTurn = activeTurnId === profile?.id

  const handleMCSelect = (idx: number) => {
    if (!isMyTurn || hasAnswered || !currentQ) return
    setSelectedOption(idx)
    setHasAnswered(true)
    
    const correct = idx === currentQ.correctAnswer
    if (correct) {
      confetti({ particleCount: 40, scalar: 0.7 })
      addToast('Correct!', 'Neural pathways aligned.', 'success')
    } else {
      addToast('Incorrect', 'Divergent thought detected.', 'error')
    }
    
    // Performance: Reduced delay for snappier feel
    setTimeout(() => submitActionResult(correct), 600)
  }

  const handleAIEvaluation = async () => {
    if (!textAnswer.trim() || !currentQ) return
    setIsGrading(true)
    try {
        const res = await fetch('/api/ai/grade', {
           method: 'POST',
           headers: { 'Content-Type': 'application/json' },
           body: JSON.stringify({
              question: currentQ.question,
              correctAnswer: currentQ.correctAnswer,
              userResponse: textAnswer
           })
        })
        const data = await res.json()
        setAiCritique(data.critique)
        setHasAnswered(true)
        
        if (data.isCorrect) {
          confetti({ particleCount: 50 })
          addToast('Synthesis Validated', 'AI score: ' + data.score, 'success')
        }
        
        // Performance: Reduced delay
        setTimeout(() => submitActionResult(data.isCorrect, data.score), 1000)
    } catch (err) {
        addToast('Evaluation Failed', 'Judge is offline.', 'error')
    } finally {
        setIsGrading(false)
    }
  }

  const downloadTrophy = () => {
    if (!scores || scores.length === 0) return
    const doc = new jsPDF()
    const sortedScores = [...scores].sort((a,b) => b.points - a.points)
    const winner = sortedScores[0]
    
    doc.setFillColor(15, 23, 42)
    doc.rect(0, 0, 210, 297, 'F')
    
    doc.setTextColor(59, 130, 246)
    doc.setFontSize(35)
    doc.text('SKIRMISH RECEIPT', 105, 50, { align: 'center' })
    
    doc.setTextColor(255, 255, 255)
    doc.setFontSize(20)
    doc.text(`${config?.difficulty || 'Standard'} ${config?.mode || 'Battle'}`.toUpperCase(), 105, 75, { align: 'center' })
    
    doc.setTextColor(251, 191, 36)
    doc.setFontSize(28)
    doc.text(winner?.userName?.toUpperCase() || 'PEER', 105, 120, { align: 'center' })
    
    doc.setTextColor(255, 255, 255)
    doc.setFontSize(14)
    doc.text(`VICTORY SCORE: ${winner?.points || 0}`, 105, 140, { align: 'center' })
    doc.text(`CHALLENGES CLEARED: ${questions?.length || 0}`, 105, 150, { align: 'center' })
    
    doc.save(`skirmish_receipt_${winner?.userName || 'winner'}.pdf`)
  }

  useEffect(() => {
    const timer = setTimeout(() => setShowIntro(false), 2500)
    return () => clearTimeout(timer)
  }, [])

  if (showIntro) {
    return (
      <div style={{ height: 'var(--vh-dynamic)', background: 'var(--bg-main)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', textAlign: 'center' }}>
         <motion.div initial={{ scale: 0.5, rotate: -45 }} animate={{ scale: 1, rotate: 0 }} transition={{ type: 'spring' }}>
            <Zap size={120} className="text-brand" fill="var(--brand)" style={{ filter: 'drop-shadow(0 0 30px rgba(var(--brand-rgb), 0.5))' }} />
         </motion.div>
         <h1 style={{ fontSize: '3.5rem', fontWeight: 950, letterSpacing: '-0.06em', marginTop: '2rem' }}>SKIRMISH <span style={{ color: 'var(--brand)' }}>ACTIVE</span></h1>
         <p style={{ color: 'var(--text-sub)', fontWeight: 800, textTransform: 'uppercase', letterSpacing: '0.4em' }}>Assembling Virtual Shards...</p>
      </div>
    )
  }

  return (
    <div className="page-fade" style={{ display: 'grid', gridTemplateColumns: '1fr 320px', gap: '2rem', height: 'calc(var(--vh-dynamic) - 6rem)', overflow: 'hidden' }}>
      
      {/* ── MAIN SKYRMISH AREA ────────────────────────────────────────── */}
      <div style={{ background: 'var(--surface)', borderRadius: '32px', border: '1px solid var(--border)', display: 'flex', flexDirection: 'column', position: 'relative', overflow: 'hidden', boxShadow: 'var(--shadow-xl)' }}>
        
        {quizStatus === 'setup' && (
          <div style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', textAlign: 'center', padding: '2rem' }}>
             <Crown size={80} className="text-brand" style={{ marginBottom: '2rem', opacity: 0.2 }} />
             <h2 style={{ fontSize: '2rem', fontWeight: 950, marginBottom: '1rem' }}>Initiating Protocol</h2>
             <p style={{ color: 'var(--text-sub)', marginBottom: '2.5rem', maxWidth: '450px', fontWeight: 600 }}>
                {hasSetupData 
                  ? "The Master Librarian awaits your signal. Deploy the academic shards whenever you feel adequately prepared." 
                  : "Synchronizing with the Central Archive. Waiting for the Host to initiate the knowledge extraction."}
             </p>
             
             {hasSetupData ? (
                <button 
                  onClick={handleStartSkirmish}
                  className="btn btn-primary"
                  style={{ padding: '1.25rem 3.5rem', borderRadius: '20px', fontWeight: 950, fontSize: '1.1rem', boxShadow: '0 10px 30px rgba(var(--brand-rgb), 0.3)' }}
                >
                  COMMENCE THE EXTRACTION
                </button>
             ) : (
                <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '1rem' }}>
                   <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', color: 'var(--brand)', fontWeight: 900 }}>
                      <Loader2 className="animate-spin" size={24} /> 
                      <span className="animate-pulse">AWAITING HOST COMMAND...</span>
                   </div>
                   <div style={{ fontSize: '0.75rem', fontWeight: 800, color: 'var(--text-sub)' }}>{others.length + 1} Scholars Connected</div>
                </div>
             )}
          </div>
        )}

        {quizStatus === 'playing' && currentQ && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} style={{ flex: 1, display: 'flex', flexDirection: 'column', padding: '3rem' }}>
             {/* Header */}
             <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '3rem' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                   <div style={{ width: '48px', height: '48px', borderRadius: '14px', background: 'rgba(var(--brand-rgb), 0.1)', color: 'var(--brand)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 950, fontSize: '1.25rem' }}>{currentIdx + 1}</div>
                   <div>
                      <div style={{ fontSize: '0.65rem', fontWeight: 950, textTransform: 'uppercase', color: 'var(--text-sub)', letterSpacing: '0.15em' }}>Round Progress</div>
                      <div style={{ fontWeight: 850 }}>{config?.mode || 'Battle'} <span style={{ color: 'var(--text-sub)' }}>({config?.difficulty || 'Standard'})</span></div>
                   </div>
                </div>
                
                {/* SMART TIMER (Isolated for performance) */}
                <SkirmishTimer 
                  roundStartTime={roundStartTime || 0} 
                  timerDuration={timerDuration || 20}
                  activeTurnId={activeTurnId}
                  currentProfileId={profile?.id || null}
                  onTimeOut={handleSkipRound}
                />
             </div>

             {/* Question Area */}
             <div style={{ textAlign: 'center', marginBottom: '3rem', minHeight: '120px' }}>
                <AnimatePresence mode="wait">
                   <motion.h2 
                     key={currentIdx}
                     initial={{ y: 20, opacity: 0 }}
                     animate={{ y: 0, opacity: 1 }}
                     style={{ fontSize: '2.25rem', fontWeight: 950, color: 'var(--text-main)', letterSpacing: '-0.04em', lineHeight: 1.1, marginBottom: '1.5rem' }}
                   >
                     {currentQ.question}
                   </motion.h2>
                </AnimatePresence>
                <div style={{ display: 'flex', justifyContent: 'center', gap: '0.75rem', alignItems: 'center' }}>
                   <motion.div 
                     animate={isMyTurn ? { scale: [1, 1.05, 1], boxShadow: ['0 0 0px var(--brand)', '0 0 20px var(--brand)', '0 0 0px var(--brand)'] } : {}}
                     transition={{ repeat: Infinity, duration: 1.5 }}
                     style={{ padding: '6px 16px', background: isMyTurn ? 'var(--brand)' : 'var(--bg-sub)', color: isMyTurn ? 'white' : 'var(--text-sub)', borderRadius: '10px', fontSize: '0.75rem', fontWeight: 950, textTransform: 'uppercase', letterSpacing: '0.05em' }}
                   >
                      {isMyTurn ? '⚡ IT IS YOUR TURN TO SYNTHESIZE' : `🔍 ${others.find(o => o.id === activeTurnId)?.info?.name || 'A Peer'} is currently being evaluated...`}
                   </motion.div>
                </div>
             </div>

             {/* Dynamic Mode Controller */}
             <div style={{ flex: 1 }}>
                {/* 1. Multiple Choice Mode */}
                {currentQ?.type === 'multiple_choice' && (
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.25rem' }}>
                        {currentQ.options?.map((opt: string, i: number) => {
                            const isCorrect = hasAnswered && i === currentQ.correctAnswer
                            const isWrong = hasAnswered && selectedOption === i && i !== currentQ.correctAnswer
                            return (
                                <button 
                                  key={i}
                                  disabled={!isMyTurn || hasAnswered}
                                  onClick={() => handleMCSelect(i)}
                                  className="glass"
                                  style={{ 
                                    padding: '1.5rem', borderRadius: '20px', border: '2px solid',
                                    borderColor: isCorrect ? 'var(--success)' : isWrong ? 'var(--error)' : selectedOption === i ? 'var(--brand)' : 'var(--border)',
                                    background: isCorrect ? 'rgba(var(--success-rgb), 0.05)' : 'var(--surface)',
                                    textAlign: 'left', fontWeight: 800, cursor: isMyTurn ? 'pointer' : 'default', transition: '0.2s', width: '100%'
                                  }}
                                >
                                    {opt}
                                </button>
                            )
                        })}
                    </div>
                )}

                {/* 2. Speed Recall Mode */}
                {config?.mode === 'Speed Recall' && currentQ?.type === 'explanation' && (
                    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '2rem' }}>
                        <AnimatePresence>
                           {isRevealed ? (
                               <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} style={{ padding: '2rem', background: 'rgba(var(--brand-rgb), 0.03)', borderRadius: '24px', border: '1px dashed var(--brand)', width: '100%', textAlign: 'center' }}>
                                  <div style={{ fontSize: '0.7rem', fontWeight: 950, color: 'var(--brand)', marginBottom: '0.5rem', textTransform: 'uppercase' }}>Correct Answer</div>
                                  <div style={{ fontSize: '1.1rem', fontWeight: 800 }}>{currentQ?.correctAnswer}</div>
                               </motion.div>
                           ) : (
                               <button onClick={() => setIsRevealed(true)} className="btn btn-primary" style={{ padding: '1rem 3rem', borderRadius: '16px', fontWeight: 950 }}>REVEAL FLUX</button>
                           )}
                        </AnimatePresence>

                        {isRevealed && isMyTurn && !hasAnswered && (
                            <div style={{ display: 'flex', gap: '1rem' }}>
                                <button onClick={() => { setHasAnswered(true); submitActionResult(false); }} className="btn" style={{ background: 'var(--error)', color: 'white', padding: '1rem 2rem', borderRadius: '12px', fontWeight: 900 }}>MISSED IT</button>
                                <button onClick={() => { setHasAnswered(true); confetti(); submitActionResult(true); }} className="btn" style={{ background: 'var(--success)', color: 'white', padding: '1rem 2rem', borderRadius: '12px', fontWeight: 900 }}>GOT IT!</button>
                            </div>
                        )}
                    </div>
                )}

                {/* 3. AI Evaluated Mode */}
                {config?.mode === 'AI Evaluated' && currentQ?.type === 'explanation' && (
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                        <textarea 
                          value={textAnswer}
                          onChange={(e) => setTextAnswer(e.target.value)}
                          disabled={!isMyTurn || hasAnswered}
                          placeholder="Synthesize your explanation here..."
                          style={{ width: '100%', height: '140px', background: 'var(--bg-sub)', border: '2px solid var(--border)', borderRadius: '20px', padding: '1.5rem', color: 'var(--text-main)', fontSize: '1rem', outline: 'none', resize: 'none', transition: 'border-color 0.2s' }}
                        />
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                           <div style={{ color: 'var(--text-sub)', fontSize: '0.8rem', fontWeight: 600 }}>{textAnswer.length} characters used</div>
                           <button 
                             onClick={handleAIEvaluation}
                             disabled={!isMyTurn || hasAnswered || isGrading || !textAnswer.trim()}
                             className="btn btn-primary"
                             style={{ padding: '0.8rem 2.5rem', borderRadius: '14px', fontWeight: 950, display: 'flex', alignItems: 'center', gap: '0.75rem' }}
                           >
                              {isGrading ? <Loader2 className="animate-spin" size={18} /> : <Zap size={18} />}
                              DEPLOY FOR GRADING
                           </button>
                        </div>
                        {aiCritique && (
                            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} style={{ padding: '1rem 1.5rem', background: 'var(--bg-main)', borderLeft: '4px solid var(--brand)', borderRadius: '0 12px 12px 0' }}>
                               <span style={{ fontSize: '0.7rem', fontWeight: 900, color: 'var(--brand)', textTransform: 'uppercase' }}>Judge's Critique:</span>
