'use client'

import { useState, useEffect } from 'react'
import { useParams, useRouter } from 'next/navigation'
import { createBrowserSupabaseClient } from '@/utils/supabase/client'
import { 
  X, UserCircle, ShieldCheck, Mail, Target, Award, Hash, 
  GraduationCap, Calendar, UserPlus, Check, MessageSquare, 
  Video, Info, Clock, ChevronLeft, ExternalLink, Activity, Terminal
} from 'lucide-react'
import Link from 'next/link'
import { Profile } from '@/types/database'
import { useSmartLoading } from '@/components/GlobalLoadingProvider'

export default function StudentProfilePage() {
  const params = useParams()
  const router = useRouter()
  const studentId = params.id as string
  const supabase = createBrowserSupabaseClient()

  const [member, setMember] = useState<Profile | null>(null)
  const [me, setMe] = useState<any>(null)
  const [loading, setLoading] = useState(true)
  const [connectionStatus, setConnectionStatus] = useState<'idle' | 'pending' | 'connected'>('idle')
  const [activeTab, setActiveTab] = useState<'info' | 'accomplishments'>('info')
  const { withLoading, showConfirmation } = useSmartLoading()

  const formatRelativeTime = (date: string | null) => {
    if (!date) return 'Unknown'
    const now = new Date()
    const diff = now.getTime() - new Date(date).getTime()
    const mins = Math.floor(diff / 60000)
    if (mins < 1) return 'Just now'
    if (mins < 60) return `${mins}m ago`
    const hours = Math.floor(mins / 60)
    if (hours < 24) return `${hours}h ago`
    return new Date(date).toLocaleDateString()
  }

  useEffect(() => {
    fetchProfileData()
  }, [studentId])

  const fetchProfileData = async () => {
    setLoading(true)
    const { data: { user } } = await supabase.auth.getUser()
    setMe(user)

    const { data: profile } = await supabase
      .from('profiles')
      .select('*, groups(*)')
      .eq('id', studentId)
      .single()

    if (profile) {
      setMember(profile as any)
      if (user) {
        // Check if there is ANY accepted connection or a pending one sent by me
        const { data: conns } = await supabase
          .from('user_connections')
          .select('id, user_id, target_id, status')
          .or(`and(user_id.eq.${user.id},target_id.eq.${studentId}),and(user_id.eq.${studentId},target_id.eq.${user.id})`)

        const connection = conns?.find(c => c.status === 'connected' || c.status === 'accepted')
        const pendingSentByMe = conns?.find(c => c.user_id === user.id && c.status === 'pending')

        if (connection) {
          setConnectionStatus('connected')
        } else if (pendingSentByMe) {
          setConnectionStatus('pending')
        } else {
          setConnectionStatus('idle')
        }
      }
    }

    setLoading(false)
  }

  const handleConnect = async () => {
    if (!me || !member || connectionStatus !== 'idle') return

    await withLoading(async () => {
      const { error: connError } = await supabase
        .from('user_connections')
        .upsert({ 
          user_id: me.id, 
          target_id: member.id, 
          status: 'pending' 
        }, { onConflict: 'user_id,target_id' })

      if (connError) throw connError

      await supabase.from('notifications').insert({
        user_id: member.id,
        type: 'connection_request',
        title: 'New Connection Request',
        message: `${me.user_metadata?.full_name || me.email} wants to connect with you.`,
        metadata: { sender_id: me.id }
      })

      setConnectionStatus('pending')
      
      showConfirmation({
        title: 'Request Sent',
        message: `Your connection request has been sent to ${member.full_name?.split(' ')[0]}.`,
        type: 'success',
        onConfirm: () => {}
      })
    }, 'Authenticating Request...')
  }

  if (loading) {
    return (
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '60vh' }}>
        <div className="spinner-mini" style={{ width: '32px', height: '32px', borderTopColor: 'var(--brand)' }} />
      </div>
    )
  }

  if (!member) {
    return (
      <div style={{ textAlign: 'center', padding: '4rem 2rem' }}>
        <h2 style={{ fontWeight: 800 }}>Scholar Not Identified</h2>
        <Link href="/dashboard/network" className="btn btn-secondary btn-inline" style={{ marginTop: '1rem' }}>Back to Network</Link>
      </div>
    )
  }

  return (
    <div style={{ maxWidth: '1000px', margin: '0 auto', padding: '0 var(--p-safe) 5rem', animation: 'fadeIn 0.5s ease-out' }}>
      
      <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '1.25rem', marginTop: '1rem' }}>
        <button 
          onClick={() => router.back()}
          style={{ background: 'var(--surface)', border: '1px solid var(--border)', borderRadius: '10px', padding: '0.5rem', cursor: 'pointer', color: 'var(--text-main)' }}
        >
          <ChevronLeft size={20} />
        </button>
        <h1 style={{ fontSize: '1.25rem', fontWeight: 900, margin: 0 }}>Scholar Transcript</h1>
      </div>

      <div className="profile-main-layout" style={{ display: 'grid', gridTemplateColumns: 'minmax(280px, 320px) 1fr', gap: '1.5rem' }}>
        
        <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
          <div style={{ background: 'var(--surface)', borderRadius: '16px', border: '1px solid var(--border)', padding: '1.5rem', textAlign: 'center', boxShadow: 'var(--shadow-sm)' }}>
            <div style={{ position: 'relative', width: '90px', height: '90px', margin: '0 auto 1rem' }}>
              <div style={{ width: '100%', height: '100%', borderRadius: '50%', background: 'var(--bg-sub)', border: '3px solid var(--surface)', boxShadow: 'var(--shadow-md)', overflow: 'hidden', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                {member.avatar_url ? (
                  <img src={member.avatar_url} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                ) : (
                  <UserCircle size={60} color="var(--text-sub)" />
                )}
              </div>
              <div style={{ position: 'absolute', bottom: '2px', right: '2px', width: '14px', height: '14px', borderRadius: '50%', background: 'var(--success)', border: '2px solid var(--surface)' }} />
            </div>

            <h2 style={{ fontSize: '1.5rem', fontWeight: 950, marginBottom: '0.25rem' }}>{member.full_name}</h2>
            {member.tagline && (
              <p style={{ fontSize: '0.85rem', color: 'var(--brand)', fontWeight: 800, fontStyle: 'italic', marginBottom: '1rem' }}>
                "{member.tagline}"
              </p>
            )}

            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.3rem', marginBottom: '1.25rem' }}>
               <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.4rem', color: 'var(--text-sub)', fontSize: '0.75rem', fontWeight: 700 }}>
                  <ShieldCheck size={14} color="var(--brand)" /> 
                  {member.rank || 'Scholar'}
               </div>
               <div style={{ color: 'var(--text-sub)', fontSize: '0.7rem', fontWeight: 600 }}>
                 Last active {formatRelativeTime(member.last_seen || null)}
               </div>
            </div>

            <button 
              onClick={handleConnect}
              disabled={connectionStatus !== 'idle'}
              className="btn btn-primary"
              style={{ fontSize: '0.9rem', padding: '0.75rem' }}
            >
              {connectionStatus === 'connected' ? <Check size={18} /> : connectionStatus === 'pending' ? <Clock size={18} /> : <UserPlus size={18} />}
              {connectionStatus === 'connected' ? 'Connected' : connectionStatus === 'pending' ? 'Pending' : 'Connect'}
            </button>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '0.5rem' }}>
             {[
               { id: 'info', icon: Info, label: 'Stats' },
               { id: 'chat', icon: MessageSquare, label: 'Chat', disabled: connectionStatus !== 'connected' },
               { id: 'accomplishments', icon: Award, label: 'Badges' }
             ].map((item) => (
               <button
                 key={item.id}
                 onClick={() => {
                   if (item.disabled) return;
                   if (item.id === 'chat') router.push(`/dashboard/network/chat/${studentId}`);
                   else setActiveTab(item.id as any);
                 }}
                 style={{ 
                   borderRadius: '12px', border: activeTab === item.id ? '2px solid var(--brand)' : '1px solid var(--border)',
                   background: activeTab === item.id ? 'var(--bg-sub)' : 'var(--surface)',
                   color: activeTab === item.id ? 'var(--brand)' : 'var(--text-sub)',
                   display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '0.4rem',
                   padding: '0.75rem 0', fontSize: '0.7rem', fontWeight: 800, cursor: item.disabled ? 'not-allowed' : 'pointer',
                   opacity: item.disabled ? 0.4 : 1, transition: 'all 0.2s'
                 }}
               >
                 <item.icon size={16} />
                 {item.label}
               </button>
             ))}
          </div>
        </div>

        <div style={{ background: 'var(--surface)', borderRadius: '16px', border: '1px solid var(--border)', padding: '1.5rem', boxShadow: 'var(--shadow-sm)' }}>
           {activeTab === 'info' && (
              <div className="page-fade">
                 <div style={{ marginBottom: '1.5rem' }}>
                    <h3 style={{ fontSize: '1rem', fontWeight: 900, marginBottom: '0.75rem' }}>Scholar Overview</h3>
                    <div style={{ padding: '1rem', background: 'var(--bg-sub)', borderRadius: '12px', border: '1px solid var(--border)', display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                       <GraduationCap size={18} color="var(--brand)" />
                       <div>
                          <div style={{ fontSize: '0.6rem', fontWeight: 800, color: 'var(--text-sub)', textTransform: 'uppercase' }}>Current Track</div>
                          <div style={{ fontSize: '0.9rem', fontWeight: 800 }}>{member.course_name || 'Independent Scholar'}</div>
                       </div>
                    </div>
                 </div>

                 <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '1.5rem' }}>
                    <div style={{ background: 'var(--bg-sub)', padding: '1rem', borderRadius: '12px', border: '1px solid var(--border)' }}>
                       <div style={{ fontSize: '0.6rem', fontWeight: 800, color: 'var(--text-sub)', textTransform: 'uppercase' }}>Score</div>
                       <div style={{ fontSize: '1.5rem', fontWeight: 950, color: 'var(--brand)' }}>{member.total_score}</div>
                    </div>
                    <div style={{ background: 'var(--bg-sub)', padding: '1rem', borderRadius: '12px', border: '1px solid var(--border)' }}>
                       <div style={{ fontSize: '0.6rem', fontWeight: 800, color: 'var(--text-sub)', textTransform: 'uppercase' }}>Grad Year</div>
                       <div style={{ fontSize: '0.9rem', fontWeight: 800, marginTop: '0.4rem' }}>{member.completion_year || 'N/A'}</div>
                    </div>
                 </div>

                 {member.stack && (
                    <div style={{ marginBottom: '1.5rem' }}>
                       <h4 style={{ fontSize: '0.75rem', fontWeight: 900, textTransform: 'uppercase', color: 'var(--text-sub)', marginBottom: '0.5rem' }}>
                          <Terminal size={14} style={{ verticalAlign: 'middle', marginRight: '4px' }} /> Technical Arsenal
                       </h4>
                       <div style={{ display: 'flex', flexWrap: 'wrap', gap: '0.4rem' }}>
                          {member.stack.split(',').map((tech, idx) => (
                             <span key={idx} style={{ padding: '0.3rem 0.6rem', background: 'var(--bg-sub)', border: '1px solid var(--border)', borderRadius: '6px', fontSize: '0.75rem', fontWeight: 800, color: 'var(--brand)' }}>
                                {tech.trim()}
                             </span>
                          ))}
                       </div>
                    </div>
                 )}

                 <div style={{ marginBottom: '1.5rem' }}>
                    <h4 style={{ fontSize: '0.75rem', fontWeight: 900, textTransform: 'uppercase', color: 'var(--text-sub)', marginBottom: '0.5rem' }}>Scholar Identity</h4>
                    <p style={{ fontSize: '0.9rem', lineHeight: 1.6, color: 'var(--text-main)', opacity: 0.85 }}>
                      {member.biography || `An active scholar in the Espeezy network, specializing in ${member.course_name || 'their academic field'}.`}
                    </p>
                 </div>
              </div>
           )}

           {activeTab === 'accomplishments' && (
              <div className="page-fade">
                 <h3 style={{ fontSize: '1rem', fontWeight: 900, marginBottom: '1.25rem' }}>Verified Credentials</h3>
                 <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(130px, 1fr))', gap: '0.75rem' }}>
                    {member.badges_count && member.badges_count > 0 ? (
                      [...Array(member.badges_count)].map((_, i) => (
                         <div key={i} style={{ background: 'var(--bg-sub)', padding: '1rem', borderRadius: '12px', border: '1px solid var(--border)', textAlign: 'center' }}>
                            <Award size={24} color="#f59e0b" style={{ marginBottom: '0.5rem' }} />
                            <div style={{ fontWeight: 800, fontSize: '0.75rem' }}>Verified</div>
                         </div>
                      ))
                    ) : (
                      <div style={{ gridColumn: '1 / -1', textAlign: 'center', padding: '3rem 1rem', background: 'var(--bg-sub)', borderRadius: '12px', opacity: 0.5 }}>
                         <Award size={40} style={{ marginBottom: '0.5rem' }} />
                         <p style={{ fontWeight: 700, fontSize: '0.85rem' }}>No credentials earned yet.</p>
                      </div>
                    )}
                 </div>
              </div>
           )}
        </div>
      </div>

      <style jsx>{`
        @keyframes fadeIn { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }
        @media (max-width: 800px) {
          .profile-main-layout { grid-template-columns: 1fr !important; }
        }
      `}</style>
    </div>
  )
}

'use client'

import { useState, useEffect } from 'react'
import { createBrowserSupabaseClient } from '@/utils/supabase/client'
import { useNotifications } from '@/components/NotificationProvider'
import type { Notification } from '@/types/ui'
import { Bell, UserPlus, Check, X, Shield, Clock, Inbox, Mail, MessageSquare } from 'lucide-react'
import { formatDistanceToNow } from 'date-fns'

type InboxNotification = Notification & { metadata?: { sender_id?: string } }

export default function NotificationsPage() {
  const { notifications, markAsRead, markAllAsRead, addToast, refreshNotifications } = useNotifications()
  const [loading, setLoading] = useState(false)
  const [view, setView] = useState<'inbox' | 'settings'>('inbox')
  const supabase = createBrowserSupabaseClient()

  // Settings state
  const [settings, setSettings] = useState({
    email_notifications: true,
    push_notifications: true,
    marketing_emails: false
  })

  useEffect(() => {
    async function fetchSettings() {
      const { data: { user } } = await supabase.auth.getUser()
      if (!user) return
      const { data } = await supabase.from('profiles').select('email_notifications, push_notifications, marketing_emails').eq('id', user.id).single()
      if (data) setSettings(data)
    }
    fetchSettings()
  }, [supabase])

  const updateSetting = async (key: keyof typeof settings, value: boolean) => {
    const newSettings = { ...settings, [key]: value }
    setSettings(newSettings)
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) return
    await supabase.from('profiles').update({ [key]: value }).eq('id', user.id)
    addToast('Success', 'Preferences updated', 'success')
  }

  const handleAcceptConnection = async (notification: InboxNotification) => {
    setLoading(true)
    const { sender_id } = notification.metadata || {}
    if (!sender_id) return

    const { data: { user } } = await supabase.auth.getUser()
    if (!user) return

    // 1. Update Connection to 'connected'
    const { error: connError } = await supabase
      .from('user_connections')
      .upsert({ user_id: user.id, target_id: sender_id, status: 'connected' })

    if (connError) {
      addToast('Error', 'Failed to accept connection', 'error')
    } else {
      // 2. Mark notification as read
      await markAsRead(notification.id)
      
      // 3. Send reciprocal notification to sender
      await supabase.from('notifications').insert({
        user_id: sender_id,
        type: 'connection_accepted',
        title: 'Connection Accepted',
        message: 'Your connection request was accepted. You can now chat real-time.',
        metadata: { acceptor_id: user.id }
      })

      addToast('Success', 'Connection established!', 'success')
    }
    setLoading(false)
  }

  const handleDeclineConnection = async (notification: InboxNotification) => {
    const senderId = notification.metadata?.sender_id
    if (senderId) {
      const { data: { user } } = await supabase.auth.getUser()
      if (user) {
        await supabase
          .from('user_connections')
          .delete()
          .eq('user_id', senderId)
          .eq('target_id', user.id)
      }
    }
    await markAsRead(notification.id)
    addToast('Success', 'Request ignored', 'info')
  }

  return (
    <div className="page-fade" style={{ maxWidth: '800px', margin: '0 auto', padding: '0 var(--p-safe) 4rem' }}>
      
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
          <div style={{ padding: '8px', background: 'var(--brand)', borderRadius: '10px', boxShadow: '0 4px 8px rgba(var(--brand-rgb), 0.15)' }}>
            <Bell size={20} color="white" />
          </div>
          <h1 className="fluid-h1" style={{ margin: 0, fontWeight: 900, fontSize: '1.5rem' }}>Inbox</h1>
        </div>
      </div>

      {/* Tab Switcher */}
      <div style={{ display: 'flex', gap: '0.5rem', marginBottom: '1rem', borderBottom: '1px solid var(--border)', paddingBottom: '0.5rem' }}>
         <button 
           onClick={() => setView('inbox')}
           style={{ background: 'none', border: 'none', padding: '0.4rem 0.8rem', borderRadius: '6px', cursor: 'pointer', fontWeight: 800, fontSize: '0.85rem', color: view === 'inbox' ? 'var(--brand)' : 'var(--text-sub)', borderBottom: view === 'inbox' ? '2px solid var(--brand)' : 'none' }}
         >
           Inbox ({notifications.filter(n => !n.read).length})
         </button>
         <button 
           onClick={() => setView('settings')}
           style={{ background: 'none', border: 'none', padding: '0.4rem 0.8rem', borderRadius: '6px', cursor: 'pointer', fontWeight: 800, fontSize: '0.85rem', color: view === 'settings' ? 'var(--brand)' : 'var(--text-sub)', borderBottom: view === 'settings' ? '2px solid var(--brand)' : 'none' }}
         >
           Settings
         </button>
      </div>

      {view === 'inbox' ? (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '2px' }}>
          {notifications.length === 0 ? (
            <div style={{ 
              textAlign: 'center', padding: '5rem 2rem', background: 'var(--surface)', 
              borderRadius: '24px', border: '1px solid var(--border)', opacity: 0.8 
            }}>
              <Bell size={48} color="var(--text-sub)" style={{ opacity: 0.2, marginBottom: '1.5rem' }} />
              <h3 style={{ margin: 0, color: 'var(--text-main)', fontSize: '1.25rem' }}>Your inbox is clean</h3>
              <p style={{ color: 'var(--text-sub)', marginTop: '0.5rem' }}>New connection requests and project updates will appear here.</p>
            </div>
          ) : (
            <>
              <div style={{ display: 'flex', justifyContent: 'flex-end', marginBottom: '0.5rem' }}>
                 <button onClick={markAllAsRead} style={{ background: 'none', border: 'none', fontSize: '0.75rem', color: 'var(--brand)', cursor: 'pointer', fontWeight: 700 }}>Mark all as read</button>
              </div>
              {notifications.map(n => (
                <div 
                  key={n.id}
                  onClick={() => !n.read && markAsRead(n.id)}
                  style={{ 
                    padding: '0.6rem 0.75rem', borderRadius: '8px', border: '1px solid var(--border)', 
                    background: n.read ? 'var(--surface)' : 'rgba(var(--brand-rgb), 0.04)',
                    transition: 'all 0.2s ease',
                    position: 'relative',
                    display: 'flex',
                    gap: '0.75rem',
                    alignItems: 'center',
                    cursor: n.read ? 'default' : 'pointer'
                  }}
                >
                  {!n.read && <div style={{ position: 'absolute', top: '0.5rem', right: '0.5rem', width: '6px', height: '6px', borderRadius: '50%', background: 'var(--brand)' }} />}
                  
                  <div style={{ 
                    width: '32px', height: '32px', borderRadius: '8px', flexShrink: 0,
                    background: n.type === 'connection_request' ? 'rgba(var(--brand-rgb), 0.1)' : 'var(--bg-sub)',
                    display: 'flex', alignItems: 'center', justifyContent: 'center', color: n.type === 'connection_request' ? 'var(--brand)' : 'var(--text-sub)'
                  }}>
                    {n.type === 'connection_request' ? <UserPlus size={16} /> : n.type === 'message' ? <MessageSquare size={16} /> : <Mail size={16} />}
                  </div>

                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: '1rem' }}>
                      <h4 style={{ margin: 0, fontSize: '0.85rem', fontWeight: 800, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{n.title}</h4>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                        <span style={{ fontSize: '0.65rem', color: 'var(--text-sub)', fontWeight: 600 }}>{formatDistanceToNow(new Date(n.created_at))} ago</span>
                        {n.type === 'connection_request' && !n.read && (
                          <div style={{ display: 'flex', gap: '0.35rem' }}>
                            <button 
                              onClick={(e) => { e.stopPropagation(); handleAcceptConnection(n); }}
                              disabled={loading}
                              style={{ padding: '0.25rem 0.5rem', borderRadius: '4px', background: 'var(--brand)', color: 'white', border: 'none', fontWeight: 800, cursor: 'pointer', fontSize: '0.7rem' }}
                            >
                              {loading ? '...' : 'Accept'}
                            </button>
                            <button 
                              onClick={(e) => { e.stopPropagation(); handleDeclineConnection(n); }}
                              style={{ padding: '0.25rem 0.5rem', borderRadius: '4px', background: 'var(--bg-sub)', color: 'var(--text-sub)', border: 'none', fontWeight: 800, cursor: 'pointer', fontSize: '0.7rem' }}
                            >
                              Ignore
                            </button>
                          </div>
                        )}
                      </div>
                    </div>
                    <p style={{ margin: 0, fontSize: '0.8rem', color: 'var(--text-sub)', lineHeight: 1.3, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{n.message}</p>
                  </div>
                </div>
              ))}
            </>
          )}
        </div>
      ) : (
        <div style={{ background: 'var(--surface)', borderRadius: '12px', border: '1px solid var(--border)', padding: '1.25rem', display: 'flex', flexDirection: 'column', gap: '1rem' }}>
           <h3 style={{ margin: 0, fontSize: '1rem', fontWeight: 900 }}>Alert Preferences</h3>
           
           {[
             { key: 'email_notifications', label: 'Email Alerts', desc: 'Receive project updates and connection requests via email.' },
             { key: 'push_notifications', label: 'Push Notifications', desc: 'Real-time browser notifications for chat and system signals.' },
             { key: 'marketing_emails', label: 'Academic Insights', desc: 'Periodic summaries of your project progress and network growth.' }
           ].map((item) => (
              <div key={item.key} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: '1rem' }}>
                 <div style={{ flex: 1 }}>
                    <div style={{ fontWeight: 800, fontSize: '0.9rem', marginBottom: '0.15rem' }}>{item.label}</div>
                    <div style={{ fontSize: '0.8rem', color: 'var(--text-sub)', lineHeight: 1.3 }}>{item.desc}</div>
                 </div>
                <button 
                  onClick={() => updateSetting(item.key as any, !settings[item.key as keyof typeof settings])}
                  style={{ 
                    width: '50px', height: '26px', borderRadius: '13px', border: 'none', position: 'relative', cursor: 'pointer',
                    background: settings[item.key as keyof typeof settings] ? 'var(--brand)' : 'var(--bg-sub)',
                    transition: 'background 0.3s ease'
                  }}
                >
                   <div style={{ 
                     position: 'absolute', top: '3px', left: settings[item.key as keyof typeof settings] ? '27px' : '3px',
                     width: '20px', height: '20px', borderRadius: '50%', background: 'white', boxShadow: '0 2px 4px rgba(0,0,0,0.2)', transition: 'left 0.3s ease' 
                   }} />
                </button>
             </div>
           ))}
        </div>
      )}
    </div>
  )
}

'use client'

import { useState, useEffect, useMemo } from 'react'
import { createBrowserSupabaseClient } from '@/utils/supabase/client'
import Image from 'next/image'
import { User, Activity, Award, Mail, Calendar, ShieldCheck, Terminal, Fingerprint, Edit2, Check, X, Zap, Handshake, CheckCircle2, Globe, Target } from 'lucide-react'
import { useProfile } from '@/context/ProfileContext'
import { getFlagComponent } from '@/utils/geo'

export default function ProfilePage() {
   const { profile, loading, refreshProfile } = useProfile()
   const supabase = createBrowserSupabaseClient()
   const [isEditingBio, setIsEditingBio] = useState(false)
   const [bioText, setBioText] = useState('')
   const [isSaving, setIsSaving] = useState(false)
   const [achievements, setAchievements] = useState<any[]>([])

   useEffect(() => {
     async function fetchAchievements() {
       if (!profile?.id) return
       const { data: artifacts } = await supabase.from('artifacts').select('*').eq('user_id', profile.id).limit(3)
       const { data: commits } = await supabase.from('commits').select('*').eq('user_id', profile.id).limit(3)
       const combined = [
         ...(artifacts || []).map(a => ({ type: 'artifact', ...a })),
         ...(commits || []).map(c => ({ type: 'commit', ...c }))
       ]
       setAchievements(combined)
     }
     fetchAchievements()
   }, [supabase, profile?.id])

   const score = profile?.total_score || 0
   const levelData = useMemo(() => {
      if (score < 100) return { level: 1, name: 'Academic Novice', next: 100, color: '#94a3b8' }
      if (score < 500) return { level: 2, name: 'Project Contributor', next: 500, color: 'var(--success)' }
      if (score < 2000) return { level: 3, name: 'Senior Researcher', next: 2000, color: 'var(--brand)' }
      if (score < 5000) return { level: 4, name: 'Lead Analyst', next: 5000, color: 'var(--accent)' }
      return { level: 5, name: 'Principal Scholar', next: 10000, color: '#fbbf24' }
   }, [score])

   const progressToNext = Math.min(100, Math.round((score / levelData.next) * 100))

   useEffect(() => {
      if (profile?.biography) {
         setBioText(profile.biography)
      }
   }, [profile?.biography])

   const handleSaveBio = async () => {
      if (!profile) return
      setIsSaving(true)
      const { error } = await supabase
         .from('profiles')
         .update({ biography: bioText })
         .eq('id', profile.id)
      
      if (!error) {
         await refreshProfile()
         setIsEditingBio(false)
      }
      setIsSaving(false)
   }

   if (loading) {
      return (
         <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '60vh', color: 'var(--text-sub)' }}>
            <div style={{ textAlign: 'center' }}>
               <div className="spinner" style={{ border: '3px solid var(--border)', borderTop: '3px solid var(--brand)', borderRadius: '50%', width: '30px', height: '30px', animation: 'spin 1s linear infinite', margin: '0 auto 1rem' }} />
               <span>Loading Identity...</span>
            </div>
         </div>
      )
   }

   return (
      <div style={{ maxWidth: '1200px', margin: '0 auto', padding: '0 var(--p-safe) 4rem', animation: 'fadeIn 0.5s ease-out' }}>

         {/* Identity Hub Header */}
          <div className={`profile-header-card ${profile?.subscription_plan === 'premium' ? 'glow-premium' : profile?.subscription_plan === 'pro' ? 'glow-pro' : ''}`} style={{ 
            maxWidth: '100%', 
            marginBottom: 'var(--gap-lg)', 
            padding: 'var(--section-p)', 
            position: 'relative', 
            overflow: 'hidden', 
            background: 'var(--surface)', 
            borderRadius: '24px', 
            border: profile?.subscription_plan === 'premium' ? '2px solid var(--gold-primary)' : profile?.subscription_plan === 'pro' ? '2px solid var(--pro-cobalt)' : '1px solid var(--border)', 
            boxShadow: profile?.subscription_plan === 'premium' ? '0 0 40px rgba(212, 175, 55, 0.25)' : profile?.subscription_plan === 'pro' ? '0 0 30px rgba(26, 115, 232, 0.15)' : 'var(--shadow-lg)',
            transition: 'all 0.5s cubic-bezier(0.4, 0, 0.2, 1)'
          }}>
            {profile?.subscription_plan === 'premium' && (
              <div style={{ position: 'absolute', top: 0, right: 0, width: '100%', height: '100%', background: 'linear-gradient(135deg, rgba(212, 175, 55, 0.05) 0%, transparent 100%)', pointerEvents: 'none' }} />
            )}
            <div style={{ position: 'absolute', top: 0, right: 0, width: '250px', height: '250px', background: profile?.subscription_plan === 'premium' ? 'radial-gradient(circle, #d4af37 0%, transparent 70%)' : 'radial-gradient(circle, var(--brand) 0%, transparent 70%)', opacity: 0.1, filter: 'blur(50px)' }} />

            <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--gap-lg)', flexWrap: 'wrap', justifyContent: 'center', textAlign: 'center' }}>
               <div style={{ position: 'relative' }}>
                  <div style={{ width: '130px', height: '130px', borderRadius: '50%', background: 'var(--bg-sub)', border: profile?.subscription_plan === 'premium' ? '4px solid #d4af37' : profile?.subscription_plan === 'pro' ? '4px solid var(--pro-cobalt)' : '4px solid var(--surface)', boxShadow: profile?.subscription_plan === 'premium' ? '0 0 25px rgba(212, 175, 55, 0.5)' : profile?.subscription_plan === 'pro' ? '0 0 20px rgba(26, 115, 232, 0.4)' : 'var(--shadow-md)', display: 'flex', alignItems: 'center', justifyContent: 'center', overflow: 'hidden' }}>
                     {profile?.avatar_url ? (
                        <Image 
                           src={profile.avatar_url} 
                           alt={`${profile.full_name || 'User'} avatar`} 
                           width={130} 
                           height={130} 
                           priority
                           style={{ width: '100%', height: '100%', objectFit: 'cover' }} 
                        />
                     ) : (
                        <User size={60} color="var(--text-sub)" />
                     )}
                  </div>
                  <div style={{ position: 'absolute', bottom: '10px', right: '10px', width: '22px', height: '22px', borderRadius: '50%', background: 'var(--success)', border: '3px solid var(--surface)', boxShadow: '0 0 10px var(--success)' }} />
               </div>

                 <div style={{ flex: '1 1 320px' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', justifyContent: 'center', marginBottom: '0.5rem' }}>
                        <h1 className="fluid-h1" style={{ fontWeight: 950, margin: 0, fontSize: '2.5rem', letterSpacing: '-0.04em', display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                          {profile?.full_name}
                          {(() => {
                            const Flag = getFlagComponent((profile as any)?.country_code)
                            return Flag ? <div style={{ width: '32px', height: '20px', borderRadius: '4px', overflow: 'hidden', boxShadow: '0 4px 10px rgba(0,0,0,0.1)' }}><Flag /></div> : null
                          })()}
                        </h1>
                        {profile?.subscription_plan === 'premium' && (
                          <div className="locked-badge locked-badge-premium glow-premium" style={{ display: 'flex', alignItems: 'center', gap: '4px', padding: '6px 16px', fontSize: '0.75rem' }}>
                            <Award size={14} /> PREMIUM ARCHITECT
                          </div>
                        )}
                        {profile?.subscription_plan === 'pro' && (
                          <div className="locked-badge locked-badge-pro glow-pro" style={{ display: 'flex', alignItems: 'center', gap: '4px', padding: '6px 16px', fontSize: '0.75rem' }}>
                            <Zap size={14} /> PRO ANALYST
                          </div>
                        )}
                    </div>
                    {profile?.tagline && (
                       <p style={{ fontSize: '1rem', color: 'var(--brand)', fontStyle: 'italic', margin: '0.4rem 0 0.75rem', fontWeight: 800 }}>
                          "{profile.tagline}"
                       </p>
                    )}
                    <p style={{ color: 'var(--text-sub)', fontSize: '1rem', margin: '0.5rem 0 1.25rem', display: 'flex', alignItems: 'center', gap: '0.5rem', justifyContent: 'center', flexWrap: 'wrap', fontWeight: 700 }}>
                      <ShieldCheck size={18} color="var(--brand)" />
                      {profile?.course_name || 'Project Analyst'} &bull; {(profile as any)?.role || 'Team Member'}
                    </p>
                   <div style={{ display: 'flex', gap: '0.75rem', flexWrap: 'wrap', justifyContent: 'center' }}>
                      <span style={{ display: 'flex', alignItems: 'center', gap: '0.4rem', fontSize: '0.75rem', color: 'var(--text-sub)', background: 'var(--bg-sub)', padding: '0.4rem 0.8rem', borderRadius: '50px', border: '1px solid var(--border)', fontWeight: 700 }}>
                         <Mail size={14} /> {profile?.email}
                      </span>
                      <span style={{ display: 'flex', alignItems: 'center', gap: '0.4rem', fontSize: '0.75rem', color: 'var(--text-sub)', background: 'var(--bg-sub)', padding: '0.4rem 0.8rem', borderRadius: '50px', border: '1px solid var(--border)', fontWeight: 700 }}>
                         <Calendar size={14} /> Joined {profile?.created_at ? new Date(profile.created_at).toLocaleDateString(undefined, { month: 'short', year: 'numeric' }) : 'N/A'}
                      </span>
                   </div>
                </div>
             </div>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(320px, 1fr))', gap: 'var(--gap-md)' }}>
             {/* Left Column: Stats & Meta */}
             <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--gap-md)' }}>
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 'var(--gap-md)' }}>
                   <div style={{ background: 'var(--brand)', color: 'white', borderRadius: '24px', padding: '1.5rem', display: 'flex', flexDirection: 'column', justifyContent: 'center', minHeight: '140px', boxShadow: '0 8px 16px rgba(var(--brand-rgb), 0.2)' }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', opacity: 0.8, marginBottom: '0.5rem' }}>
                         <Activity size={18} />
                         <span style={{ fontSize: '0.7rem', fontWeight: 900, textTransform: 'uppercase', letterSpacing: '1px' }}>Team Points</span>
                      </div>
                      <div style={{ fontSize: '2.5rem', fontWeight: 950, lineHeight: 1, letterSpacing: '-0.04em' }}>{profile?.total_score || 0}</div>
                      <p style={{ fontSize: '0.75rem', opacity: 0.8, marginTop: '0.6rem', fontWeight: 700 }}>Academic Contribution</p>
                   </div>

                    <div style={{ background: 'var(--surface)', borderRadius: '24px', padding: '1.5rem', border: '1px solid var(--border)', display: 'flex', flexDirection: 'column', gap: '0.75rem', justifyContent: 'center' }}>
                       <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                          <span style={{ color: 'var(--text-sub)', fontSize: '0.75rem', fontWeight: 850, textTransform: 'uppercase' }}>Standing</span>
                          <span style={{ fontWeight: 950, fontSize: '0.9rem', color: levelData.color }}>{levelData.name}</span>
                       </div>
                       <div style={{ background: 'var(--bg-sub)', height: '6px', borderRadius: '3px', overflow: 'hidden', position: 'relative' }}>
                          <div style={{ position: 'absolute', top: 0, left: 0, height: '100%', width: `${progressToNext}%`, background: levelData.color, transition: 'width 1s ease-out' }} />
                       </div>
                       <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                          <span style={{ color: 'var(--text-sub)', fontSize: '0.75rem', fontWeight: 850 }}>ID#</span>
                          <span style={{ fontWeight: 800, fontSize: '0.9rem', color: 'var(--text-main)' }}>{profile?.school_id || 'U-ID-01'}</span>
                       </div>
                    </div>
                </div>

                <div className="card-item" style={{ background: 'var(--surface)', borderRadius: '24px', padding: '2rem', border: '1px solid var(--border)' }}>
                   <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                      <h3 style={{ fontSize: '0.85rem', margin: 0, display: 'flex', alignItems: 'center', gap: '0.6rem', fontWeight: 900, textTransform: 'uppercase', color: 'var(--text-sub)', letterSpacing: '0.05em' }}>
                         <Fingerprint size={16} color="var(--brand)" /> 
                         Personal Bio
                      </h3>
                      {!isEditingBio ? (
                         <button onClick={() => setIsEditingBio(true)} style={{ background: 'none', border: 'none', color: 'var(--brand)', cursor: 'pointer', fontSize: '0.75rem', fontWeight: 800 }}>EDIT</button>
                      ) : (
                         <div style={{ display: 'flex', gap: '0.75rem' }}>
                            <button onClick={handleSaveBio} disabled={isSaving} style={{ background: 'none', border: 'none', color: 'var(--success)', cursor: 'pointer', fontSize: '0.75rem', fontWeight: 900 }}>SAVE</button>
                            <button onClick={() => setIsEditingBio(false)} style={{ background: 'none', border: 'none', color: 'var(--error)', cursor: 'pointer', fontSize: '0.75rem', fontWeight: 900 }}>CANCEL</button>
                         </div>
                      )}
                   </div>
                   {isEditingBio ? (
                      <textarea value={bioText} onChange={(e) => setBioText(e.target.value)} rows={4} style={{ width: '100%', padding: '1rem', background: 'var(--bg-sub)', border: '1px solid var(--border)', borderRadius: '12px', color: 'var(--text-main)', fontSize: '0.95rem', outline: 'none', resize: 'none' }} />
                   ) : (
                      <p style={{ margin: 0, fontSize: '0.95rem', color: 'var(--text-main)', lineHeight: 1.6 }}>{profile?.biography || `Student collaborator participating in institutional group projects.`}</p>
                   )}
                </div>
             </div>

              {/* Right Column: Achievements & Credentials */}
              <div className="card-item" style={{ background: 'var(--surface)', borderRadius: '24px', padding: '2rem', border: '1px solid var(--border)' }}>
                 <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                    <h3 style={{ fontSize: '1.1rem', fontWeight: 950, margin: 0, display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                       <Award size={24} color="var(--brand)" />
                       Verifiable Accomplishments
                    </h3>
                    <div style={{ fontSize: '0.7rem', fontWeight: 900, background: 'rgba(var(--brand-rgb), 0.1)', color: 'var(--brand)', padding: '4px 10px', borderRadius: '8px' }}>
                      {profile?.badges_count || 0} Badges
                    </div>
                 </div>

                 <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                    {achievements.length > 0 ? achievements.map((ach, idx) => (
                      <div key={idx} style={{ padding: '1.25rem', background: 'rgba(var(--brand-rgb), 0.02)', borderRadius: '20px', border: '1px solid var(--border)', display: 'flex', alignItems: 'center', gap: '1rem', transition: 'all 0.2s' }}>
                        <div style={{ width: '44px', height: '44px', borderRadius: '12px', background: ach.type === 'artifact' ? 'rgba(var(--brand-rgb), 0.1)' : 'rgba(34, 197, 94, 0.1)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                          {ach.type === 'artifact' ? <Target size={20} color="var(--brand)" /> : <CheckCircle2 size={20} color="var(--success)" />}
                        </div>
                        <div style={{ flex: 1, minWidth: 0 }}>
                          <div style={{ fontSize: '0.95rem', fontWeight: 800, color: 'var(--text-main)', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{ach.title || ach.content || 'Contribution'}</div>
                          <div style={{ fontSize: '0.75rem', color: 'var(--text-sub)', marginTop: '2px', display: 'flex', alignItems: 'center', gap: '0.4rem' }}>
                            {ach.type === 'artifact' ? 'Academic Evidence' : 'Protocol Synchronization'} &bull; {new Date(ach.created_at).toLocaleDateString()}
                          </div>
                        </div>
                      </div>
                    )) : (
                      <div style={{ padding: '4rem 2rem', textAlign: 'center', color: 'var(--text-sub)', border: '1px dashed var(--border)', borderRadius: '24px' }}>
                         <Award size={48} style={{ opacity: 0.1, marginBottom: '1.5rem' }} />
                         <p style={{ fontSize: '0.9rem', fontWeight: 700, margin: 0 }}>Identity pending credential sync.</p>
                         <p style={{ fontSize: '0.75rem', marginTop: '0.5rem', opacity: 0.7 }}>Contribute to artifacts or push commits to build your wall.</p>
                      </div>
                    )}
                 </div>
              </div>
          </div>

          <style jsx>{`
             @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
             .premium-aura {
               animation: auraPulse 4s infinite alternate ease-in-out;
             }
             @keyframes auraPulse {
               0% { box-shadow: 0 0 20px rgba(212, 175, 55, 0.1); }
               100% { box-shadow: 0 0 40px rgba(212, 175, 55, 0.3); }
             }
          `}</style>
      </div>
   )
}

'use client'

import { useState, useEffect, useCallback } from 'react'
import { createBrowserSupabaseClient } from '@/utils/supabase/client'
import {
