                    zIndex: 2,
                    display: 'flex',
                    alignItems: 'center',
                    gap: '4px',
                    whiteSpace: 'nowrap'
                  }}>
                    <Sparkles size={12} />
                    {profile.subscription_plan === 'lifetime' ? 'FOUNDER ACCESS' : profile.subscription_plan === 'premium' ? 'ELITE SCHOLAR' : 'PRO MEMBER'}
                  </div>
