                       </button>
                       <button
                         onClick={() => window.location.href = `/dashboard/analytics/${group.id}`}
                         className="btn btn-ghost"
                         style={{ width: 'auto', padding: '0.5rem', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
