                </label>
                <p style={{ marginTop: '1rem', fontSize: '0.75rem', color: 'var(--text-sub)', fontWeight: 600 }}>Immersive glassmorphism will adapt to your custom imagery.</p>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'security' && (
          <div className="auth-card" style={{ maxWidth: '100%' }}>
