                    <img
                      src={member.avatar_url}
                      alt={member.full_name ? `${member.full_name}'s avatar` : 'User avatar'}
                      style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                    />
                  ) : (
                    <User size={24} color="var(--text-sub)" />
                  )}
                </div>
                {isOnline && (
                  <div
                    style={{
                      position: 'absolute',
                      bottom: '2px',
                      right: '2px',
                      width: '12px',
                      height: '12px',
                      borderRadius: '50%',
                      background: 'var(--success)',
                      border: '2px solid var(--bg-main)',
                      boxShadow: '0 0 8px var(--success)'
                    }}
                  />
                )}
              </div>

              <div>
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                  <span style={{ fontWeight: 700, fontSize: '1rem', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                    {member.full_name} {isMe && '(You)'}
                    {(() => {
                      const Flag = getFlagComponent((member as any).country_code)
                      return Flag ? <div style={{ width: '16px', height: '11px', borderRadius: '2px', overflow: 'hidden' }}><Flag /></div> : null
                    })()}
                  </span>
                  {member.role === 'admin' && <Shield size={14} color="var(--brand)" />}
                </div>
                <div
                  style={{
                    fontSize: '0.75rem',
                    color: isTyping ? 'var(--brand)' : 'var(--text-sub)',
                    fontWeight: isTyping ? 700 : 500
                  }}
                >
                  {isTyping ? (
                    <span style={{ fontStyle: 'italic' }}>is typing...</span>
                  ) : isOnline ? (
                    'Online now'
                  ) : (
                    `Last active ${formatLastSeen(member.last_seen ?? null)}`
                  )}
                </div>
              </div>
            </div>

            <div style={{ textAlign: 'right' }}>
              <div
                style={{
                  fontSize: '0.7rem',
                  color: 'var(--text-sub)',
                  textTransform: 'uppercase',
                  letterSpacing: '1px',
                  fontWeight: 800
                }}
              >
                Role
              </div>
              <div style={{ fontSize: '1.25rem', fontWeight: 900, color: 'var(--brand)' }}>
                {member.role ? member.role.toUpperCase() : 'Member'}
              </div>
            </div>
          </div>
        )
      })}
    </div>
  )
}

'use client'

import { useState, useEffect, useMemo, useCallback } from 'react'
import { createBrowserSupabaseClient } from '@/utils/supabase/client'
import {
  MessageSquare,
  CheckCircle,
  PlusCircle,
  Trash2,
  Settings,
  Palette,
  Shield,
  UserMinus,
  FileUp,
  History,
  Clock,
  Calendar,
  Search,
  X
} from 'lucide-react'
import { LogEntry } from '@/types/ui'

const getActionIcon = (type: string) => {
  switch (type) {
    case 'message_sent': return <MessageSquare size={16} color="var(--brand)" />
    case 'task_created': return <PlusCircle size={16} color="var(--success)" />
    case 'task_updated': return <CheckCircle size={16} color="var(--brand)" />
    case 'task_deleted': return <Trash2 size={16} color="var(--error)" />
    case 'message_deleted': return <Trash2 size={16} color="var(--text-sub)" />
    case 'setting_updated': return <Settings size={16} color="var(--text-main)" />
    case 'theme_changed': return <Palette size={16} color="#e900ff" />
    case 'privacy_toggled': return <Shield size={16} color="var(--warning)" />
    case 'member_kicked': return <UserMinus size={16} color="var(--error)" />
    case 'artifact_uploaded': return <FileUp size={16} color="var(--success)" />
    default: return <History size={16} color="var(--text-sub)" />
  }
}

const groupActivities = (items: LogEntry[]) => {
  const groups: { label: string; items: LogEntry[] }[] = []
  const now = new Date()
  const today = new Date(now.getFullYear(), now.getMonth(), now.getDate()).getTime()
  const yesterday = today - 86400000
  const weekAgo = today - (86400000 * 7)

  items.forEach(item => {
    const time = new Date(item.created_at).getTime()
    let label = 'Older'
    if (time >= today) label = 'Today'
    else if (time >= yesterday) label = 'Yesterday'
    else if (time >= weekAgo) label = 'Past Week'

    const existing = groups.find(g => g.label === label)
    if (existing) existing.items.push(item)
    else groups.push({ label, items: [item] })
  })

  return groups
}

export default function ActivityLogView({ 
  userId, 
  groupId, 
  limit = 50 
}: { 
  userId?: string, 
  groupId?: string, 
  limit?: number 
}) {
  const [activities, setActivities] = useState<LogEntry[]>([])
  const [logSearch, setLogSearch] = useState('')
  const [loading, setLoading] = useState(true)
  const supabase = useMemo(() => createBrowserSupabaseClient(), [])

  const filteredLogs = useMemo(() => {
    if (!logSearch.trim()) return activities
    const term = logSearch.toLowerCase()
    return activities.filter(a => 
      a.description.toLowerCase().includes(term) || 
      a.action_type.toLowerCase().includes(term) ||
      a.profiles?.full_name?.toLowerCase().includes(term)
    )
  }, [activities, logSearch])

  const grouped = useMemo(() => groupActivities(filteredLogs), [filteredLogs])

  const fetchLogs = useCallback(async () => {
    setLoading(true)
    let query = supabase
      .from('activity_log')
      .select('*, profiles(full_name, avatar_url)')
      .order('created_at', { ascending: false })
      .limit(limit)

    if (userId) query = query.eq('user_id', userId)
    if (groupId) query = query.eq('group_id', groupId)

    const { data } = await query
    if (data) setActivities(data as LogEntry[])
    setLoading(false)
  }, [userId, groupId, limit, supabase])

  useEffect(() => {
    void (async () => {
      await fetchLogs()
    })()

    // Real-time synchronization for the audit log
    const channel = supabase.channel(`activity_log_${groupId || 'personal'}`)
      .on(
        'postgres_changes',
        { 
          event: 'INSERT', 
          schema: 'public', 
          table: 'activity_log',
          filter: groupId ? `group_id=eq.${groupId}` : userId ? `user_id=eq.${userId}` : undefined
        },
        () => {
          // Re-fetch to get the profile join correctly, or we could optimistic insert
          void fetchLogs()
        }
      )
      .subscribe()

    return () => {
      supabase.removeChannel(channel)
    }
  }, [fetchLogs, groupId, userId, supabase])

  if (loading) {
    return (
      <div style={{ display: 'flex', flexDirection: 'column', gap: '2rem' }}>
        {[1, 2].map(g => (
          <div key={g}>
            <div className="skeleton skeleton-text" style={{ width: '100px', marginBottom: '1.5rem' }} />
            <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem', paddingLeft: '1rem', borderLeft: '2px solid var(--border)' }}>
              {[1, 2, 3].map(i => (
                <div key={i} style={{ display: 'flex', gap: '1rem' }}>
                  <div className="skeleton" style={{ width: '32px', height: '32px', borderRadius: '8px' }} />
                  <div style={{ flex: 1 }}>
                    <div className="skeleton skeleton-title" style={{ width: '70%' }} />
                    <div className="skeleton skeleton-text" style={{ width: '30%' }} />
                  </div>
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
    )
  }
  if (activities.length === 0) return (
    <div style={{ textAlign: 'center', padding: '3rem', color: 'var(--text-sub)', background: 'var(--bg-main)', borderRadius: '16px', border: '1px dashed var(--border)' }}>
      <History size={32} style={{ marginBottom: '1rem', opacity: 0.5 }} />
      <p>No recent activity recorded.</p>
    </div>
  )

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
       <div style={{ position: 'relative', width: '100%', maxWidth: '300px' }}>
          <Search size={14} style={{ position: 'absolute', left: '0.75rem', top: '50%', transform: 'translateY(-50%)', color: 'var(--text-sub)' }} />
          <input 
            type="text" 
            placeholder="Search activity history..." 
            value={logSearch}
            onChange={(e) => setLogSearch(e.target.value)}
            style={{ width: '100%', padding: '0.5rem 0.75rem 0.5rem 2.25rem', borderRadius: '10px', background: 'var(--bg-main)', border: '1px solid var(--border)', color: 'var(--text-main)', fontSize: '0.8rem' }}
          />
          {logSearch && (
            <button onClick={() => setLogSearch('')} style={{ position: 'absolute', right: '0.5rem', top: '50%', transform: 'translateY(-50%)', background: 'none', border: 'none', color: 'var(--text-sub)', cursor: 'pointer', display: 'flex' }}><X size={12} /></button>
          )}
       </div>

       {filteredLogs.length === 0 ? (
         <div style={{ textAlign: 'center', padding: '2rem', color: 'var(--text-sub)', border: '1px dashed var(--border)', borderRadius: '12px' }}>No logs match "{logSearch}"</div>
       ) : (
         <div style={{ display: 'flex', flexDirection: 'column', gap: '2rem' }}>
           {grouped.map(group => (
        <div key={group.label}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '1rem' }}>
             <Calendar size={14} color="var(--brand)" />
             <span style={{ fontSize: '0.75rem', fontWeight: 800, color: 'var(--text-sub)', textTransform: 'uppercase', letterSpacing: '1px' }}>{group.label}</span>
          </div>

          <div style={{ position: 'relative', paddingLeft: '2rem', borderLeft: '2px solid var(--border)', marginLeft: '0.5rem', display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
            {group.items.map(activity => (
              <div key={activity.id} style={{ position: 'relative' }}>
                {/* Connector Dot */}
                <div style={{ position: 'absolute', left: '-2.4rem', top: '0.4rem', width: '12px', height: '12px', borderRadius: '50%', background: 'var(--surface)', border: '2px solid var(--brand)', boxShadow: '0 0 8px rgba(var(--brand-rgb), 0.2)' }} />
                
                <div style={{ display: 'flex', alignItems: 'flex-start', gap: '1rem' }}>
                   <div style={{ padding: '0.5rem', background: 'var(--bg-main)', borderRadius: '8px', border: '1px solid var(--border)' }}>
                      {getActionIcon(activity.action_type)}
                   </div>
                   <div style={{ flex: 1 }}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                         <div style={{ fontWeight: 700, fontSize: '0.95rem', color: 'var(--text-main)' }}>{activity.description}</div>
                         <div style={{ display: 'flex', alignItems: 'center', gap: '0.4rem', color: 'var(--text-sub)', fontSize: '0.75rem' }}>
                            <Clock size={12} />
                            {new Date(activity.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                         </div>
                      </div>
                      <div style={{ fontSize: '0.8rem', color: 'var(--text-sub)', marginTop: '0.25rem', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                         {activity.profiles?.avatar_url && (
                           <img
                             src={activity.profiles.avatar_url}
                             alt={`${activity.profiles.full_name ?? 'System'} avatar`}
                             style={{ width: '16px', height: '16px', borderRadius: '50%' }}
                           />
                         )}
                         <span>{activity.profiles?.full_name || 'System'}</span>
                      </div>
                   </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      ))}
      </div>
    )}
    </div>
  )
}

'use client'

import { useState, useEffect, useCallback } from 'react'
import { createBrowserSupabaseClient } from '@/utils/supabase/client'
import {
  Users, AlertTriangle, Activity, MessageSquare, DollarSign,
  Search, Loader2, CheckCircle, XCircle, Ban, Send, Mail, ShieldAlert
} from 'lucide-react'

type AdminTab = 'users' | 'activity' | 'feedback' | 'payout' | 'email' | 'errors'

interface UserRow {
  id: string; full_name: string; email: string
  account_status: string; subscription_plan: string; created_at: string
  stripe_account_status?: string; role?: string
}

interface ActivityRow {
  id: string; created_at: string; action: string; resource_type?: string
  severity: string; user_id: string
  profile?: { full_name: string; email: string }
}

interface FeedbackRow {
  id: string; created_at: string; feedback_type: string; message: string; rating?: number
  profile?: { full_name: string; email: string }
}

interface Campaign {
  id: string; title: string; subject: string; status: string
  sent_count: number; created_at: string; sent_at?: string
}

interface ServerError {
  id: number; route?: string; method?: string; message: string; stack?: string; created_at: string
}

const supabase = createBrowserSupabaseClient()

export default function AdminExtras() {
  const [tab, setTab] = useState<AdminTab>('users')
  const [users, setUsers] = useState<UserRow[]>([])
  const [activity, setActivity] = useState<ActivityRow[]>([])
  const [feedback, setFeedback] = useState<FeedbackRow[]>([])
  const [loading, setLoading] = useState(false)
  const [search, setSearch] = useState('')
  const [actionLoading, setActionLoading] = useState<string | null>(null)

  // Payout state
  const [payoutRecipient, setPayoutRecipient] = useState('')
  const [payoutAmount, setPayoutAmount] = useState('')
  const [payoutNote, setPayoutNote] = useState('')
  const [payoutError, setPayoutError] = useState('')
  const [payoutSuccess, setPayoutSuccess] = useState('')
  const [sendingPayout, setSendingPayout] = useState(false)

  // Email campaign state
  const [campaigns, setCampaigns] = useState<Campaign[]>([])
  const [campaignTitle, setCampaignTitle] = useState('')
  const [campaignSubject, setCampaignSubject] = useState('')
  const [campaignPreview, setCampaignPreview] = useState('')
  const [campaignBody, setCampaignBody] = useState('')
  const [sendingCampaign, setSendingCampaign] = useState(false)
  const [campaignMsg, setCampaignMsg] = useState<{ ok: boolean; text: string } | null>(null)

  // Server error log state
  const [serverErrors, setServerErrors] = useState<ServerError[]>([])
  const [errorsLoading, setErrorsLoading] = useState(false)
  const [expandedError, setExpandedError] = useState<number | null>(null)

  const loadUsers = useCallback(async () => {
    setLoading(true)
    const { data } = await supabase
      .from('profiles')
      .select('id, full_name, email, account_status, subscription_plan, created_at, stripe_account_status, role')
      .order('created_at', { ascending: false })
      .limit(50)
    setUsers(data ?? [])
    setLoading(false)
  }, [])

  const loadActivity = useCallback(async () => {
    setLoading(true)
    const { data } = await supabase
      .from('activity_log')
      .select('id, created_at, action, resource_type, severity, user_id')
      .order('created_at', { ascending: false })
      .limit(100)
    setActivity(data ?? [])
    setLoading(false)
  }, [])

  const loadFeedback = useCallback(async () => {
    setLoading(true)
    const { data } = await supabase
      .from('user_feedback')
      .select('id, created_at, feedback_type, message, rating, user_id')
      .order('created_at', { ascending: false })
      .limit(100)
    setFeedback(data ?? [])
    setLoading(false)
  }, [])

  const loadCampaigns = useCallback(async () => {
    const res = await fetch('/api/admin/email-campaigns')
    if (res.ok) {
      const json = await res.json()
      setCampaigns(json.campaigns ?? [])
    }
  }, [])

  const loadServerErrors = useCallback(async () => {
    setErrorsLoading(true)
    try {
      const res = await fetch('/api/admin/server-errors')
      if (!res.ok) throw new Error(`Failed to load server errors (${res.status})`)
      const json = await res.json()
      setServerErrors(json.errors ?? [])
    } catch (e) {
      setServerErrors([])
      console.error('loadServerErrors:', (e as Error).message)
    } finally {
      setErrorsLoading(false)
    }
  }, [])

  useEffect(() => {
    if (tab === 'users') loadUsers()
    else if (tab === 'activity') loadActivity()
    else if (tab === 'feedback') loadFeedback()
    else if (tab === 'email') loadCampaigns()
    else if (tab === 'errors') loadServerErrors()
  }, [tab, loadUsers, loadActivity, loadFeedback, loadCampaigns, loadServerErrors])

  async function sendCampaign() {
    if (!campaignTitle || !campaignSubject || !campaignBody) return
    setSendingCampaign(true); setCampaignMsg(null)
    try {
      const res = await fetch('/api/admin/email-campaigns', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          title: campaignTitle,
          subject: campaignSubject,
          preview: campaignPreview,
          html_body: campaignBody,
        }),
      })
      const data = await res.json()
      if (!res.ok) {
        setCampaignMsg({ ok: false, text: data.error ?? 'Failed to send campaign' })
      } else {
        setCampaignMsg({ ok: true, text: `✓ Sent to ${data.sent_count} of ${data.total_recipients} recipients.` })
        setCampaignTitle(''); setCampaignSubject(''); setCampaignPreview(''); setCampaignBody('')
        loadCampaigns()
      }
    } catch (e) {
      setCampaignMsg({ ok: false, text: (e as Error).message })
    } finally {
      setSendingCampaign(false)
    }
  }

  async function setAccountStatus(userId: string, status: 'active' | 'suspended' | 'deactivated') {
    setActionLoading(userId)
    const { error } = await supabase.from('profiles').update({ account_status: status }).eq('id', userId)
    if (!error) setUsers(prev => prev.map(u => u.id === userId ? { ...u, account_status: status } : u))
    setActionLoading(null)
  }

  async function sendPayout() {
    setPayoutError(''); setPayoutSuccess(''); setSendingPayout(true)
    try {
      const res = await fetch('/api/admin/payout', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          recipient_id: payoutRecipient,
          amount_cents: Math.round(parseFloat(payoutAmount) * 100),
          note: payoutNote,
        }),
      })
      const data = await res.json()
      if (!res.ok) { setPayoutError(data.error ?? 'Failed'); return }
      setPayoutSuccess(`Transfer sent! ID: ${data.transfer_id}`)
      setPayoutRecipient(''); setPayoutAmount(''); setPayoutNote('')
    } finally { setSendingPayout(false) }
  }

  const statusColor: Record<string, string> = {
    active: '#10B981', suspended: '#F59E0B', deactivated: '#EF4444',
  }

  const severityColor: Record<string, string> = {
    info: 'rgba(255,255,255,0.25)', warning: '#F59E0B', error: '#EF4444', critical: '#EF4444',
  }

  const filteredUsers = users.filter(u =>
    !search || u.full_name?.toLowerCase().includes(search.toLowerCase()) || u.email?.toLowerCase().includes(search.toLowerCase())
  )

  const TABS: { key: AdminTab; label: string; icon: React.ReactNode }[] = [
    { key: 'users', label: 'User Management', icon: <Users size={14} /> },
    { key: 'activity', label: 'Activity Log', icon: <Activity size={14} /> },
    { key: 'feedback', label: 'User Feedback', icon: <MessageSquare size={14} /> },
    { key: 'payout', label: 'Admin Payout', icon: <DollarSign size={14} /> },
    { key: 'email', label: 'Email Marketing', icon: <Mail size={14} /> },
    { key: 'errors', label: 'Error Log', icon: <ShieldAlert size={14} /> },
  ]

  return (
    <div style={{ marginBottom: '3rem' }}>
      <h2 style={{ fontSize: '1.4rem', fontWeight: 950, letterSpacing: '-0.03em', marginBottom: '1.25rem', color: '#F3F4F6' }}>
        Platform <span style={{ color: '#10B981' }}>Operations</span>
      </h2>

      {/* Tab bar */}
      <div style={{ display: 'flex', gap: '0.4rem', flexWrap: 'wrap', marginBottom: '1.5rem' }}>
        {TABS.map(t => (
          <button key={t.key} onClick={() => setTab(t.key)} style={{
            display: 'flex', alignItems: 'center', gap: '0.4rem',
            padding: '0.5rem 1rem', borderRadius: '10px', border: 'none',
            background: tab === t.key ? '#10B981' : 'rgba(255,255,255,0.05)',
            color: tab === t.key ? '#000' : 'rgba(255,255,255,0.5)',
            fontWeight: 800, fontSize: '0.78rem', cursor: 'pointer',
          }}>{t.icon}{t.label}</button>
        ))}
      </div>

      {loading && <div style={{ textAlign: 'center', padding: '2rem', color: 'rgba(255,255,255,0.3)' }}><Loader2 size={22} style={{ display: 'inline-block', animation: 'spin 1s linear infinite' }} /></div>}

      {/* ─── Users ─── */}
      {!loading && tab === 'users' && (
        <div>
          <div style={{ marginBottom: '1rem', display: 'flex', gap: '0.75rem', alignItems: 'center' }}>
            <div style={{ flex: 1, display: 'flex', alignItems: 'center', gap: '0.5rem', background: '#0d0d0d', border: '1px solid rgba(255,255,255,0.08)', borderRadius: '10px', padding: '0.5rem 0.85rem' }}>
              <Search size={14} color="rgba(255,255,255,0.3)" />
              <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search users…" style={{ flex: 1, background: 'transparent', border: 'none', outline: 'none', color: '#E5E7EB', fontSize: '0.85rem', fontFamily: 'inherit' }} />
            </div>
          </div>
          <div style={{ border: '1px solid rgba(255,255,255,0.07)', borderRadius: '12px', overflow: 'hidden' }}>
            <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.8rem' }}>
              <thead>
                <tr style={{ background: 'rgba(255,255,255,0.04)', borderBottom: '1px solid rgba(255,255,255,0.06)' }}>
                  {['Name', 'Email', 'Plan', 'Status', 'Stripe', 'Actions'].map(h => (
                    <th key={h} style={{ padding: '0.65rem 1rem', textAlign: 'left', fontWeight: 800, color: 'rgba(255,255,255,0.4)', whiteSpace: 'nowrap' }}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {filteredUsers.map((u, i) => (
                  <tr key={u.id} style={{ borderBottom: '1px solid rgba(255,255,255,0.04)', background: i % 2 === 0 ? 'transparent' : 'rgba(255,255,255,0.01)' }}>
                    <td style={{ padding: '0.7rem 1rem', color: '#E5E7EB', fontWeight: 700 }}>{u.full_name}</td>
                    <td style={{ padding: '0.7rem 1rem', color: 'rgba(255,255,255,0.4)' }}>{u.email}</td>
                    <td style={{ padding: '0.7rem 1rem' }}><span style={{ background: 'rgba(16,185,129,0.1)', color: '#10B981', fontSize: '0.65rem', fontWeight: 900, padding: '2px 6px', borderRadius: '5px', textTransform: 'uppercase' }}>{u.subscription_plan ?? 'free'}</span></td>
                    <td style={{ padding: '0.7rem 1rem' }}><span style={{ color: statusColor[u.account_status] ?? '#888', fontWeight: 800, fontSize: '0.75rem' }}>{u.account_status ?? 'active'}</span></td>
                    <td style={{ padding: '0.7rem 1rem', color: 'rgba(255,255,255,0.3)', fontSize: '0.72rem' }}>{u.stripe_account_status ?? '—'}</td>
                    <td style={{ padding: '0.7rem 1rem' }}>
                      {actionLoading === u.id ? <Loader2 size={14} style={{ display: 'inline', animation: 'spin 1s linear infinite' }} /> : (
                        <div style={{ display: 'flex', gap: '0.4rem' }}>
                          {u.account_status !== 'active' && (
                            <button onClick={() => setAccountStatus(u.id, 'active')} title="Activate" style={{ background: 'rgba(16,185,129,0.1)', border: 'none', borderRadius: '6px', padding: '4px 8px', color: '#10B981', cursor: 'pointer', fontSize: '0.7rem', fontWeight: 800 }}>Activate</button>
                          )}
                          {u.account_status !== 'suspended' && u.role !== 'admin' && (
                            <button onClick={() => setAccountStatus(u.id, 'suspended')} title="Suspend" style={{ background: 'rgba(245,158,11,0.1)', border: 'none', borderRadius: '6px', padding: '4px 8px', color: '#F59E0B', cursor: 'pointer', fontSize: '0.7rem', fontWeight: 800 }}>Suspend</button>
                          )}
                          {u.account_status !== 'deactivated' && u.role !== 'admin' && (
                            <button onClick={() => { if (window.confirm(`Permanently deactivate ${u.full_name}?`)) setAccountStatus(u.id, 'deactivated') }} style={{ background: 'rgba(239,68,68,0.1)', border: 'none', borderRadius: '6px', padding: '4px 8px', color: '#EF4444', cursor: 'pointer', fontSize: '0.7rem', fontWeight: 800 }}>Deactivate</button>
                          )}
                        </div>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            {filteredUsers.length === 0 && <div style={{ padding: '2rem', textAlign: 'center', color: 'rgba(255,255,255,0.2)', fontSize: '0.8rem' }}>No users found</div>}
          </div>
        </div>
      )}

      {/* ─── Activity Log ─── */}
      {!loading && tab === 'activity' && (
        <div style={{ border: '1px solid rgba(255,255,255,0.07)', borderRadius: '12px', overflow: 'hidden' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.78rem' }}>
            <thead>
              <tr style={{ background: 'rgba(255,255,255,0.04)', borderBottom: '1px solid rgba(255,255,255,0.06)' }}>
                {['Time', 'User', 'Action', 'Resource', 'Severity'].map(h => (
                  <th key={h} style={{ padding: '0.65rem 1rem', textAlign: 'left', fontWeight: 800, color: 'rgba(255,255,255,0.4)', whiteSpace: 'nowrap' }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {activity.map((a, i) => (
                <tr key={a.id} style={{ borderBottom: '1px solid rgba(255,255,255,0.03)', background: i % 2 === 0 ? 'transparent' : 'rgba(255,255,255,0.01)' }}>
                  <td style={{ padding: '0.6rem 1rem', color: 'rgba(255,255,255,0.3)', fontFamily: 'monospace' }}>{new Date(a.created_at).toLocaleTimeString()}</td>
                  <td style={{ padding: '0.6rem 1rem', color: 'rgba(255,255,255,0.5)', fontSize: '0.72rem', maxWidth: 120, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{a.user_id.slice(0, 8)}…</td>
                  <td style={{ padding: '0.6rem 1rem', color: '#E5E7EB', fontWeight: 700 }}>{a.action}</td>
                  <td style={{ padding: '0.6rem 1rem', color: 'rgba(255,255,255,0.4)' }}>{a.resource_type ?? '—'}</td>
                  <td style={{ padding: '0.6rem 1rem' }}><span style={{ color: severityColor[a.severity] ?? 'rgba(255,255,255,0.3)', fontWeight: 800, fontSize: '0.65rem', textTransform: 'uppercase' }}>{a.severity}</span></td>
                </tr>
              ))}
            </tbody>
          </table>
          {activity.length === 0 && <div style={{ padding: '2rem', textAlign: 'center', color: 'rgba(255,255,255,0.2)', fontSize: '0.8rem' }}>No activity logged yet</div>}
        </div>
      )}

      {/* ─── User Feedback ─── */}
      {!loading && tab === 'feedback' && (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
          {feedback.length === 0 && <div style={{ padding: '2rem', textAlign: 'center', color: 'rgba(255,255,255,0.2)', fontSize: '0.8rem' }}>No feedback submitted yet</div>}
          {feedback.map(f => (
            <div key={f.id} style={{ background: '#0d0d0d', border: '1px solid rgba(255,255,255,0.07)', borderRadius: '12px', padding: '1rem 1.25rem' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '0.5rem' }}>
                <div style={{ display: 'flex', gap: '0.5rem', alignItems: 'center' }}>
                  <span style={{ background: 'rgba(16,185,129,0.1)', color: '#10B981', fontSize: '0.65rem', fontWeight: 900, padding: '2px 6px', borderRadius: '5px', textTransform: 'uppercase' }}>{f.feedback_type}</span>
                  {f.rating && <span style={{ fontSize: '0.75rem', color: '#F59E0B' }}>{'★'.repeat(f.rating)}{'☆'.repeat(5 - f.rating)}</span>}
                </div>
                <span style={{ fontSize: '0.7rem', color: 'rgba(255,255,255,0.25)' }}>{new Date(f.created_at).toLocaleDateString()}</span>
              </div>
              <p style={{ margin: 0, fontSize: '0.85rem', color: 'rgba(255,255,255,0.6)', lineHeight: 1.55 }}>{f.message}</p>
            </div>
          ))}
        </div>
      )}

      {/* ─── Admin Payout ─── */}
      {tab === 'payout' && (
        <div style={{ maxWidth: 480 }}>
          <div style={{ background: 'rgba(239,68,68,0.06)', border: '1px solid rgba(239,68,68,0.15)', borderRadius: '10px', padding: '0.75rem 1rem', marginBottom: '1.25rem' }}>
            <p style={{ margin: 0, fontSize: '0.8rem', color: 'rgba(255,255,255,0.5)' }}>
              <strong style={{ color: '#EF4444' }}>⚠ Admin action.</strong> This sends real money via Stripe. The recipient must have an active connected bank account. All payouts are logged.
            </p>
          </div>
          {payoutError && <div style={{ background: 'rgba(239,68,68,0.1)', borderRadius: '8px', padding: '0.6rem 0.9rem', marginBottom: '0.75rem', fontSize: '0.82rem', color: '#EF4444' }}>{payoutError}</div>}
          {payoutSuccess && <div style={{ background: 'rgba(16,185,129,0.1)', borderRadius: '8px', padding: '0.6rem 0.9rem', marginBottom: '0.75rem', fontSize: '0.82rem', color: '#10B981' }}>{payoutSuccess}</div>}
          <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
            <div>
              <label style={labelStyle}>Recipient User ID</label>
              <input value={payoutRecipient} onChange={e => setPayoutRecipient(e.target.value)} placeholder="UUID of recipient" style={inputStyle} />
            </div>
            <div>
              <label style={labelStyle}>Amount (USD)</label>
              <input value={payoutAmount} onChange={e => setPayoutAmount(e.target.value)} placeholder="e.g. 50.00" type="number" min="1" step="0.01" style={inputStyle} />
            </div>
            <div>
              <label style={labelStyle}>Note (optional)</label>
              <input value={payoutNote} onChange={e => setPayoutNote(e.target.value)} placeholder="Reason for payment…" maxLength={200} style={inputStyle} />
            </div>
            <button
              onClick={sendPayout}
              disabled={!payoutRecipient || !payoutAmount || sendingPayout}
              style={{
                display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.4rem',
                background: '#10B981', border: 'none', borderRadius: '10px', color: '#000',
                fontWeight: 900, fontSize: '0.85rem', padding: '0.75rem', cursor: 'pointer',
                opacity: (!payoutRecipient || !payoutAmount || sendingPayout) ? 0.5 : 1,
              }}
            >
              {sendingPayout ? <Loader2 size={14} style={{ animation: 'spin 1s linear infinite' }} /> : <Send size={14} />}
              Send Payout
            </button>
          </div>
        </div>
      )}

      {/* ─── Email Marketing ─── */}
      {tab === 'email' && (
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem' }}>
          {/* Compose form */}
          <div style={{ background: '#0d0d0d', border: '1px solid rgba(255,255,255,0.07)', borderRadius: '12px', padding: '1.5rem', display: 'flex', flexDirection: 'column', gap: '0.9rem' }}>
            <h3 style={{ margin: 0, fontSize: '1rem', fontWeight: 900, color: '#F3F4F6', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
              <Mail size={16} style={{ color: '#10B981' }} /> Compose Campaign
            </h3>
            <p style={{ margin: 0, fontSize: '0.75rem', color: 'rgba(255,255,255,0.35)' }}>
              Only users who have opted in to Marketing Emails will receive this. They will also get a persistent in-app notification.
            </p>
            {campaignMsg && (
              <div style={{ borderRadius: '8px', padding: '0.6rem 0.9rem', fontSize: '0.82rem', background: campaignMsg.ok ? 'rgba(16,185,129,0.1)' : 'rgba(239,68,68,0.1)', color: campaignMsg.ok ? '#10B981' : '#EF4444' }}>{campaignMsg.text}</div>
            )}
            <div>
              <label style={labelStyle}>Campaign Title (internal)</label>
              <input value={campaignTitle} onChange={e => setCampaignTitle(e.target.value)} placeholder="e.g. April Newsletter" style={inputStyle} />
            </div>
            <div>
              <label style={labelStyle}>Email Subject</label>
              <input value={campaignSubject} onChange={e => setCampaignSubject(e.target.value)} placeholder="e.g. Big updates at Espeezy 🚀" style={inputStyle} />
            </div>
            <div>
              <label style={labelStyle}>Preview Text (optional)</label>
              <input value={campaignPreview} onChange={e => setCampaignPreview(e.target.value)} placeholder="Short summary shown in inbox…" maxLength={200} style={inputStyle} />
            </div>
            <div>
              <label style={labelStyle}>Email Body (HTML supported)</label>
              <textarea
                value={campaignBody}
                onChange={e => setCampaignBody(e.target.value)}
                placeholder={'<h2>Hi there!</h2>\n<p>We have exciting news for you...</p>'}
                rows={8}
                style={{ ...inputStyle, resize: 'vertical', lineHeight: 1.5 }}
              />
            </div>
            <button
              onClick={sendCampaign}
              disabled={!campaignTitle || !campaignSubject || !campaignBody || sendingCampaign}
              style={{
                display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem',
                background: '#10B981', border: 'none', borderRadius: '10px', color: '#000',
                fontWeight: 900, fontSize: '0.85rem', padding: '0.85rem', cursor: 'pointer',
                opacity: (!campaignTitle || !campaignSubject || !campaignBody || sendingCampaign) ? 0.5 : 1,
              }}
            >
              {sendingCampaign ? <Loader2 size={14} style={{ animation: 'spin 1s linear infinite' }} /> : <Send size={14} />}
              {sendingCampaign ? 'Sending…' : 'Send to All Opted-In Users'}
            </button>
          </div>

          {/* Campaign history */}
          <div style={{ background: '#0d0d0d', border: '1px solid rgba(255,255,255,0.07)', borderRadius: '12px', padding: '1.5rem' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
              <h3 style={{ margin: 0, fontSize: '1rem', fontWeight: 900, color: '#F3F4F6' }}>Campaign History</h3>
              <button onClick={loadCampaigns} style={{ background: 'rgba(255,255,255,0.05)', border: 'none', borderRadius: '6px', padding: '4px 10px', color: 'rgba(255,255,255,0.4)', fontSize: '0.7rem', cursor: 'pointer', fontWeight: 700 }}>Refresh</button>
            </div>
            {campaigns.length === 0 && <div style={{ textAlign: 'center', padding: '3rem 0', color: 'rgba(255,255,255,0.2)', fontSize: '0.8rem' }}>No campaigns yet</div>}
            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.6rem' }}>
              {campaigns.map(c => (
                <div key={c.id} style={{ background: '#111', borderRadius: '8px', padding: '0.75rem 1rem', display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: '0.5rem' }}>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontWeight: 800, fontSize: '0.85rem', color: '#E5E7EB', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{c.title}</div>
                    <div style={{ fontSize: '0.72rem', color: 'rgba(255,255,255,0.4)', marginTop: '2px', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{c.subject}</div>
                    <div style={{ fontSize: '0.68rem', color: 'rgba(255,255,255,0.25)', marginTop: '4px' }}>
                      {c.sent_at ? new Date(c.sent_at).toLocaleDateString() : new Date(c.created_at).toLocaleDateString()} · {c.sent_count} sent
                    </div>
                  </div>
                  <span style={{ flexShrink: 0, fontSize: '0.65rem', fontWeight: 900, padding: '2px 8px', borderRadius: '5px', textTransform: 'uppercase',
                    background: c.status === 'sent' ? 'rgba(16,185,129,0.1)' : c.status === 'failed' ? 'rgba(239,68,68,0.1)' : 'rgba(245,158,11,0.1)',
                    color: c.status === 'sent' ? '#10B981' : c.status === 'failed' ? '#EF4444' : '#F59E0B' }}>
                    {c.status}
                  </span>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* ─── Error Log ─── */}
      {tab === 'errors' && (
        <div>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
            <p style={{ margin: 0, fontSize: '0.8rem', color: 'rgba(255,255,255,0.35)' }}>
              Most recent 100 internal server errors. Copy the message and paste it into Copilot to fix.
            </p>
            <button onClick={loadServerErrors} style={{ background: 'rgba(255,255,255,0.05)', border: 'none', borderRadius: '6px', padding: '4px 10px', color: 'rgba(255,255,255,0.4)', fontSize: '0.7rem', cursor: 'pointer', fontWeight: 700, whiteSpace: 'nowrap' }}>Refresh</button>
          </div>
          {errorsLoading && <div style={{ textAlign: 'center', padding: '2rem', color: 'rgba(255,255,255,0.3)' }}><Loader2 size={22} style={{ display: 'inline-block', animation: 'spin 1s linear infinite' }} /></div>}
          {!errorsLoading && serverErrors.length === 0 && (
            <div style={{ textAlign: 'center', padding: '3rem', background: '#0d0d0d', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.06)', color: 'rgba(255,255,255,0.2)', fontSize: '0.85rem' }}>
              🟢 No errors logged
            </div>
          )}
          <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
            {serverErrors.map(e => (
              <div key={e.id} style={{ background: '#0d0d0d', border: '1px solid rgba(239,68,68,0.15)', borderRadius: '10px', padding: '0.9rem 1.1rem' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: '1rem', marginBottom: '0.35rem' }}>
                  <div style={{ display: 'flex', gap: '0.5rem', alignItems: 'center', flexWrap: 'wrap' }}>
                    {e.route && <span style={{ background: 'rgba(255,255,255,0.05)', borderRadius: '4px', padding: '1px 6px', fontFamily: 'monospace', fontSize: '0.72rem', color: 'rgba(255,255,255,0.45)' }}>{e.method ?? 'GET'} {e.route}</span>}
                    <span style={{ fontSize: '0.68rem', color: 'rgba(255,255,255,0.25)' }}>{new Date(e.created_at).toLocaleString()}</span>
                  </div>
                  <button
                    onClick={() => setExpandedError(expandedError === e.id ? null : e.id)}
                    style={{ background: 'none', border: 'none', fontSize: '0.7rem', color: 'var(--brand, #10B981)', cursor: 'pointer', fontWeight: 700, whiteSpace: 'nowrap' }}
                  >
                    {expandedError === e.id ? 'Hide stack' : 'Full stack'}
                  </button>
                </div>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: '0.5rem' }}>
                  <code style={{ flex: 1, fontSize: '0.8rem', color: '#EF4444', background: 'rgba(239,68,68,0.05)', borderRadius: '6px', padding: '0.4rem 0.6rem', display: 'block', wordBreak: 'break-all' }}>{e.message}</code>
                  <button
                    onClick={() => navigator.clipboard.writeText(e.stack ? `${e.message}\n\n${e.stack}` : e.message)}
                    style={{ flexShrink: 0, background: 'rgba(255,255,255,0.05)', border: 'none', borderRadius: '6px', padding: '4px 10px', color: 'rgba(255,255,255,0.4)', fontSize: '0.7rem', cursor: 'pointer', fontWeight: 700 }}
                  >
                    Copy
                  </button>
                </div>
                {expandedError === e.id && e.stack && (
                  <pre style={{ marginTop: '0.5rem', fontSize: '0.7rem', color: 'rgba(255,255,255,0.3)', background: '#080808', borderRadius: '6px', padding: '0.75rem', overflowX: 'auto', whiteSpace: 'pre-wrap', wordBreak: 'break-all' }}>{e.stack}</pre>
                )}
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  )
}

const labelStyle: React.CSSProperties = { display: 'block', fontSize: '0.72rem', fontWeight: 800, color: 'rgba(255,255,255,0.4)', marginBottom: '0.35rem', textTransform: 'uppercase', letterSpacing: '0.06em' }
const inputStyle: React.CSSProperties = { width: '100%', boxSizing: 'border-box', background: '#0d0d0d', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '10px', padding: '0.65rem 0.9rem', color: '#F3F4F6', fontSize: '0.88rem', fontFamily: 'inherit', outline: 'none' }

'use client'

import { useState, useEffect, useCallback } from 'react'
import { useRouter } from 'next/navigation'
import {
  Bot, Plus, Trash2, Play, Pause, RefreshCw, ChevronDown, ChevronUp,
  CheckCircle2, Circle, Clock, AlertCircle, Zap, Server, Layout,
  ArrowRight, X, Save, RotateCcw, Terminal, Send
} from 'lucide-react'

type AgentStatus = 'active' | 'paused' | 'training'
type AgentSpec = 'frontend' | 'backend' | 'devops'
type AgentRole = 'builder' | 'validator'
type TaskStatus = 'not_started' | 'in_progress' | 'review' | 'done' | 'blocked'
type TaskPriority = 'low' | 'medium' | 'high' | 'critical'

interface Agent {
  id: string
  name: string
  specialisation: AgentSpec
  role: AgentRole
  status: AgentStatus
  capabilities: string[]
  tasks_completed: number
  system_prompt?: string
  pair?: { id: string; name: string } | null
}

interface Task {
  id: string
  title: string
  description?: string
  status: TaskStatus
  priority: TaskPriority
  assigned_agent_id?: string
  agent?: { id: string; name: string; specialisation: string } | null
  created_at: string
  started_at?: string
  completed_at?: string
  output_artifacts?: unknown[]
  logs?: string
}

const SPEC_ICON: Record<AgentSpec, typeof Bot> = { frontend: Layout, backend: Server, devops: Zap }
const SPEC_COLOR: Record<AgentSpec, string> = {
  frontend: '#3B82F6',
  backend: '#10B981',
  devops: '#F59E0B',
}
const STATUS_COLOR: Record<AgentStatus, string> = {
  active: '#10B981',
  paused: '#F59E0B',
  training: '#3B82F6',
}
const TASK_STATUS_ICON: Record<TaskStatus, typeof Circle> = {
  not_started: Circle,
  in_progress: Clock,
  review: RefreshCw,
  done: CheckCircle2,
  blocked: AlertCircle,
}
const TASK_STATUS_COLOR: Record<TaskStatus, string> = {
  not_started: 'rgba(255,255,255,0.3)',
  in_progress: '#3B82F6',
  review: '#F59E0B',
  done: '#10B981',
  blocked: '#EF4444',
}
const PRIORITY_COLOR: Record<TaskPriority, string> = {
  low: 'rgba(255,255,255,0.3)',
  medium: '#3B82F6',
  high: '#F59E0B',
  critical: '#EF4444',
}

const TASK_COLUMNS: TaskStatus[] = ['not_started', 'in_progress', 'review', 'done', 'blocked']

export default function AgentControlCentre() {
  const router = useRouter()
  const [agents, setAgents] = useState<Agent[]>([])
  const [tasks, setTasks] = useState<Task[]>([])
  const [loading, setLoading] = useState(true)
  const [view, setView] = useState<'agents' | 'board' | 'new-agent' | 'new-task' | 'orchestrate'>('agents')
  const [expandedAgent, setExpandedAgent] = useState<string | null>(null)
  const [expandedTask, setExpandedTask] = useState<string | null>(null)

  // New agent form
  const [newAgent, setNewAgent] = useState({
    name: '', specialisation: 'frontend' as AgentSpec, role: 'builder' as AgentRole,
    system_prompt: '', capabilities: ''
  })

  // New task form
  const [newTask, setNewTask] = useState({
    title: '', description: '', priority: 'medium' as TaskPriority, assigned_agent_id: ''
  })

  const [saving, setSaving] = useState(false)
  const [error, setError] = useState('')

  // Orchestrate command
  const [orchestrateCmd, setOrchestrateCmd] = useState('')
  const [orchestrating, setOrchestrating] = useState(false)
  const [orchestrateResult, setOrchestrateResult] = useState<{ tasks_created: number; plan: { task_id: string; title: string; agent: string }[] } | null>(null)

  const load = useCallback(async () => {
    setLoading(true)
    try {
      const [agentsRes, tasksRes] = await Promise.all([
        fetch('/api/admin/agents'),
        fetch('/api/admin/tasks'),
      ])
      if (agentsRes.status === 401) { router.push('/admin'); return }
      const { agents: a } = await agentsRes.json()
      const { tasks: t } = await tasksRes.json()
      setAgents(a ?? [])
      setTasks(t ?? [])
    } finally {
      setLoading(false)
    }
  }, [router])

  useEffect(() => { load() }, [load])

  async function toggleAgentStatus(agent: Agent) {
    const next = agent.status === 'active' ? 'paused' : 'active'
    await fetch(`/api/admin/agents/${agent.id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ status: next }),
    })
    setAgents(prev => prev.map(a => a.id === agent.id ? { ...a, status: next } : a))
  }

  async function deleteAgent(id: string) {
    if (!confirm('Delete this agent? This cannot be undone.')) return
    await fetch(`/api/admin/agents/${id}`, { method: 'DELETE' })
    setAgents(prev => prev.filter(a => a.id !== id))
  }

  async function deleteTask(id: string) {
    if (!confirm('Delete this task?')) return
    await fetch(`/api/admin/tasks/${id}`, { method: 'DELETE' })
    setTasks(prev => prev.filter(t => t.id !== id))
  }

  async function retryTask(task: Task) {
    await fetch(`/api/admin/tasks/${task.id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ status: 'not_started' }),
    })
    setTasks(prev => prev.map(t => t.id === task.id ? { ...t, status: 'not_started' } : t))
  }

  async function submitOrchestrateCmd() {
    if (orchestrateCmd.trim().length < 10) {
      setError('Command must be at least 10 characters so agents have enough detail to work with')
      return
    }
    setOrchestrating(true); setError(''); setOrchestrateResult(null)
    try {
      const res = await fetch('/api/agents/orchestrate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ command: orchestrateCmd }),
      })
      const data = await res.json()
      if (!res.ok) { setError(data.error ?? 'Failed to create tasks. Please refine your command and try again.'); return }
      setOrchestrateResult(data)
      setOrchestrateCmd('')
      await load()
    } catch (e: unknown) {
      setError(e instanceof Error ? e.message : 'Network error: unable to reach the orchestration service. Please check your connection and try again.')
    } finally {
      setOrchestrating(false)
    }
  }

  async function moveTask(task: Task, status: TaskStatus) {
    await fetch(`/api/admin/tasks/${task.id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ status }),
    })
    setTasks(prev => prev.map(t => t.id === task.id ? { ...t, status } : t))
  }

  async function createAgent() {
    setSaving(true); setError('')
    try {
      const res = await fetch('/api/admin/agents', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          ...newAgent,
          capabilities: newAgent.capabilities.split(',').map(c => c.trim()).filter(Boolean)
        }),
      })
      if (!res.ok) { const j = await res.json(); throw new Error(j.error) }
      await load()
      setView('agents')
      setNewAgent({ name: '', specialisation: 'frontend', role: 'builder', system_prompt: '', capabilities: '' })
    } catch (e: unknown) {
      setError(e instanceof Error ? e.message : 'Unknown error')
    } finally {
      setSaving(false)
    }
  }

  async function createTask() {
    setSaving(true); setError('')
    try {
      const res = await fetch('/api/admin/tasks', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          ...newTask,
          assigned_agent_id: newTask.assigned_agent_id || null,
        }),
      })
      if (!res.ok) { const j = await res.json(); throw new Error(j.error) }
      await load()
      setView('board')
      setNewTask({ title: '', description: '', priority: 'medium', assigned_agent_id: '' })
    } catch (e: unknown) {
      setError(e instanceof Error ? e.message : 'Unknown error')
    } finally {
      setSaving(false)
    }
  }

  const bySpec = (spec: AgentSpec) => agents.filter(a => a.specialisation === spec)

  if (loading) {
    return (
      <div style={{ padding: '2rem', color: 'rgba(255,255,255,0.55)', textAlign: 'center' }}>
        Loading agent network...
      </div>
    )
  }

  return (
    <div style={{ padding: '2rem 0' }}>
      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '2rem', flexWrap: 'wrap', gap: '1rem' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
          <Bot size={22} color="#10B981" />
          <h2 style={{ margin: 0, fontSize: '1.1rem', fontWeight: 900, letterSpacing: '-0.02em', color: '#F3F4F6' }}>
            AGENT CONTROL CENTRE
          </h2>
          <span style={{ background: '#10B98130', border: '1px solid #10B98150', borderRadius: '4px', padding: '1px 8px', fontSize: '0.7rem', fontWeight: 900, letterSpacing: '0.12em', color: '#10B981', textTransform: 'uppercase' }}>
            {agents.filter(a => a.status === 'active').length} ACTIVE
          </span>
        </div>
        <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap' }}>
          {(['agents', 'board', 'orchestrate'] as const).map(v => (
            <button key={v} onClick={() => setView(v)} style={{
              padding: '0.4rem 0.9rem', borderRadius: '6px', border: '1px solid',
              borderColor: view === v ? '#10B981' : 'rgba(255,255,255,0.1)',
              background: view === v ? '#10B98120' : 'transparent',
              color: view === v ? '#10B981' : 'rgba(255,255,255,0.55)',
              fontWeight: 700, fontSize: '0.75rem', letterSpacing: '0.06em',
              textTransform: 'uppercase', cursor: 'pointer',
            }}>
              {v === 'agents' ? 'Agents' : v === 'board' ? 'Task Board' : 'Orchestrate'}
            </button>
          ))}
          <button onClick={() => { setView('new-task'); setError('') }} style={{
            padding: '0.4rem 0.9rem', borderRadius: '6px', border: '1px solid rgba(255,255,255,0.1)',
            background: 'transparent', color: 'rgba(255,255,255,0.55)',
            fontWeight: 700, fontSize: '0.75rem', letterSpacing: '0.06em',
            textTransform: 'uppercase', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '0.4rem',
          }}>
            <Plus size={12} /> Task
          </button>
          <button onClick={() => { setView('new-agent'); setError('') }} style={{
            padding: '0.4rem 0.9rem', borderRadius: '6px', border: '1px solid #10B981',
            background: '#10B98120', color: '#10B981',
            fontWeight: 700, fontSize: '0.75rem', letterSpacing: '0.06em',
            textTransform: 'uppercase', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '0.4rem',
          }}>
            <Plus size={12} /> Agent
          </button>
          <button onClick={load} style={{
            padding: '0.4rem 0.7rem', borderRadius: '6px', border: '1px solid rgba(255,255,255,0.1)',
            background: 'transparent', color: 'rgba(255,255,255,0.4)', cursor: 'pointer',
          }}>
            <RefreshCw size={14} />
          </button>
        </div>
      </div>

      {/* Error banner */}
      {error && (
        <div style={{ background: '#EF444420', border: '1px solid #EF4444', borderRadius: '8px', padding: '0.75rem 1rem', marginBottom: '1.5rem', color: '#EF4444', fontSize: '0.875rem', display: 'flex', justifyContent: 'space-between' }}>
          {error}
          <button onClick={() => setError('')} style={{ background: 'none', border: 'none', color: '#EF4444', cursor: 'pointer' }}><X size={14} /></button>
        </div>
      )}

      {/* AGENTS VIEW */}
      {view === 'agents' && (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
          {(['frontend', 'backend', 'devops'] as AgentSpec[]).map(spec => {
            const Icon = SPEC_ICON[spec]
            const color = SPEC_COLOR[spec]
            return (
              <div key={spec}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.75rem' }}>
                  <Icon size={14} color={color} />
                  <span style={{ fontSize: '0.7rem', fontWeight: 900, letterSpacing: '0.14em', textTransform: 'uppercase', color }}>
                    {spec} pair
                  </span>
                </div>
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '0.75rem' }}>
                  {bySpec(spec).map(agent => (
                    <AgentCard
                      key={agent.id}
                      agent={agent}
                      taskCount={tasks.filter(t => t.assigned_agent_id === agent.id && t.status !== 'done').length}
                      expanded={expandedAgent === agent.id}
                      onExpand={() => setExpandedAgent(expandedAgent === agent.id ? null : agent.id)}
                      onToggle={() => toggleAgentStatus(agent)}
                      onDelete={() => deleteAgent(agent.id)}
                    />
                  ))}
                  {bySpec(spec).length === 0 && (
                    <div style={{ padding: '1.5rem', border: '1px dashed rgba(255,255,255,0.1)', borderRadius: '10px', color: 'rgba(255,255,255,0.25)', fontSize: '0.8rem', textAlign: 'center' }}>
                      No {spec} agents
                    </div>
                  )}
                </div>
              </div>
            )
          })}
        </div>
      )}

      {/* TASK BOARD VIEW */}
      {view === 'board' && (
        <div style={{ overflowX: 'auto' }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(5, minmax(200px, 1fr))', gap: '1rem', minWidth: '1050px' }}>
            {TASK_COLUMNS.map(col => (
              <div key={col}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.75rem' }}>
                  {(() => { const I = TASK_STATUS_ICON[col]; return <I size={13} color={TASK_STATUS_COLOR[col]} /> })()}
                  <span style={{ fontSize: '0.68rem', fontWeight: 900, letterSpacing: '0.14em', textTransform: 'uppercase', color: TASK_STATUS_COLOR[col] }}>
                    {col.replace('_', ' ')}
                  </span>
                  <span style={{ marginLeft: 'auto', fontSize: '0.7rem', color: 'rgba(255,255,255,0.3)' }}>
                    {tasks.filter(t => t.status === col).length}
                  </span>
                </div>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                  {tasks.filter(t => t.status === col).map(task => (
                    <TaskCard
                      key={task.id}
                      task={task}
                      expanded={expandedTask === task.id}
                      onExpand={() => setExpandedTask(expandedTask === task.id ? null : task.id)}
                      onMove={moveTask}
                      onRetry={retryTask}
                      onDelete={deleteTask}
                    />
                  ))}
                  {tasks.filter(t => t.status === col).length === 0 && (
                    <div style={{ padding: '1.5rem 1rem', border: '1px dashed rgba(255,255,255,0.06)', borderRadius: '8px', textAlign: 'center', color: 'rgba(255,255,255,0.2)', fontSize: '0.75rem' }}>
                      Empty
                    </div>
                  )}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* ORCHESTRATE VIEW */}
      {view === 'orchestrate' && (
        <div style={{ maxWidth: '640px' }}>
          <div style={{ background: '#111', border: '1px solid rgba(255,255,255,0.08)', borderRadius: '12px', padding: '1.5rem', marginBottom: '1rem' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.6rem', marginBottom: '1rem' }}>
              <Terminal size={16} color="#10B981" />
              <h3 style={{ margin: 0, fontWeight: 900, letterSpacing: '-0.02em', fontSize: '1rem' }}>Orchestrate Command</h3>
            </div>
            <p style={{ margin: '0 0 1rem', fontSize: '0.78rem', color: 'rgba(255,255,255,0.4)', lineHeight: 1.55 }}>
              Describe what needs to be built. The orchestrator will decompose your command into tasks and assign them to the right agents.
            </p>
            <textarea
              value={orchestrateCmd}
              onChange={e => setOrchestrateCmd(e.target.value)}
              rows={4}
              placeholder="e.g. Build a new API route and UI page for user notifications with database migration and Playwright tests"
              style={{ ...inputStyle, resize: 'vertical', marginBottom: '0.75rem' }}
            />
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <span style={{ fontSize: '0.7rem', color: orchestrateCmd.trim().length < 10 ? '#EF4444' : 'rgba(255,255,255,0.3)' }}>
                {orchestrateCmd.trim().length} / 2000 chars (min 10)
              </span>
              <button
                onClick={submitOrchestrateCmd}
                disabled={orchestrating || orchestrateCmd.trim().length < 10}
                style={{
                  padding: '0.55rem 1.25rem', background: '#10B981', border: 'none', borderRadius: '8px',
                  color: '#000', fontWeight: 900, fontSize: '0.8rem', letterSpacing: '0.06em',
                  textTransform: 'uppercase', cursor: (orchestrating || orchestrateCmd.trim().length < 10) ? 'not-allowed' : 'pointer',
                  opacity: (orchestrating || orchestrateCmd.trim().length < 10) ? 0.5 : 1,
                  display: 'flex', alignItems: 'center', gap: '0.4rem',
                }}
              >
                <Send size={13} /> {orchestrating ? 'Dispatching...' : 'Dispatch'}
              </button>
            </div>
          </div>

          {orchestrateResult && (
            <div style={{ background: '#0d1a12', border: '1px solid #10B98140', borderRadius: '12px', padding: '1.25rem' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '1rem' }}>
                <CheckCircle2 size={15} color="#10B981" />
                <span style={{ fontWeight: 900, fontSize: '0.85rem', color: '#10B981' }}>
                  {orchestrateResult.tasks_created} task{orchestrateResult.tasks_created !== 1 ? 's' : ''} created
                </span>
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '0.4rem' }}>
                {orchestrateResult.plan.map((t, i) => (
                  <div key={t.task_id} style={{ display: 'flex', alignItems: 'center', gap: '0.6rem', fontSize: '0.78rem' }}>
                    <span style={{ color: 'rgba(255,255,255,0.25)', fontFamily: 'monospace', minWidth: '1.2rem' }}>{i + 1}.</span>
                    <span style={{ background: 'rgba(255,255,255,0.06)', borderRadius: '4px', padding: '1px 6px', fontSize: '0.68rem', color: 'rgba(255,255,255,0.45)', fontWeight: 700 }}>{t.agent}</span>
                    <span style={{ color: '#E5E7EB' }}>{t.title}</span>
                  </div>
                ))}
              </div>
              <button
                onClick={() => { setOrchestrateResult(null); setView('board') }}
                style={{ marginTop: '1rem', padding: '0.4rem 0.9rem', background: 'transparent', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '6px', color: 'rgba(255,255,255,0.55)', fontSize: '0.72rem', fontWeight: 700, cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '0.4rem' }}
              >
                <ArrowRight size={11} /> View Task Board
              </button>
            </div>
          )}
        </div>
      )}

      {/* NEW AGENT FORM */}
      {view === 'new-agent' && (
        <div style={{ maxWidth: '540px', background: '#111', border: '1px solid rgba(255,255,255,0.08)', borderRadius: '12px', padding: '1.5rem' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
            <h3 style={{ margin: 0, fontWeight: 900, letterSpacing: '-0.02em', fontSize: '1rem' }}>Register New Agent</h3>
            <button onClick={() => setView('agents')} style={{ background: 'none', border: 'none', color: 'rgba(255,255,255,0.4)', cursor: 'pointer' }}><X size={16} /></button>
          </div>
          <FormField label="Name">
            <input value={newAgent.name} onChange={e => setNewAgent(p => ({ ...p, name: e.target.value }))} placeholder="e.g. Eta" style={inputStyle} />
          </FormField>
          <FormField label="Specialisation">
            <select value={newAgent.specialisation} onChange={e => setNewAgent(p => ({ ...p, specialisation: e.target.value as AgentSpec }))} style={inputStyle}>
              <option value="frontend">Frontend</option>
              <option value="backend">Backend</option>
              <option value="devops">DevOps</option>
            </select>
          </FormField>
          <FormField label="Role">
            <select value={newAgent.role} onChange={e => setNewAgent(p => ({ ...p, role: e.target.value as AgentRole }))} style={inputStyle}>
              <option value="builder">Builder</option>
              <option value="validator">Validator</option>
            </select>
          </FormField>
          <FormField label="Capabilities (comma-separated)">
            <input value={newAgent.capabilities} onChange={e => setNewAgent(p => ({ ...p, capabilities: e.target.value }))} placeholder="React, TypeScript, Tailwind" style={inputStyle} />
          </FormField>
          <FormField label="System Prompt">
            <textarea value={newAgent.system_prompt} onChange={e => setNewAgent(p => ({ ...p, system_prompt: e.target.value }))} rows={4} placeholder="You are..." style={{ ...inputStyle, resize: 'vertical' }} />
          </FormField>
          <button onClick={createAgent} disabled={saving || !newAgent.name} style={{
            width: '100%', padding: '0.75rem', background: '#10B981', border: 'none', borderRadius: '8px',
            color: '#000', fontWeight: 900, fontSize: '0.85rem', letterSpacing: '0.06em',
            textTransform: 'uppercase', cursor: saving ? 'not-allowed' : 'pointer', opacity: saving ? 0.6 : 1,
            display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem', marginTop: '0.5rem',
          }}>
            <Save size={14} /> {saving ? 'Registering...' : 'Register Agent'}
          </button>
        </div>
      )}

      {/* NEW TASK FORM */}
      {view === 'new-task' && (
        <div style={{ maxWidth: '540px', background: '#111', border: '1px solid rgba(255,255,255,0.08)', borderRadius: '12px', padding: '1.5rem' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
            <h3 style={{ margin: 0, fontWeight: 900, letterSpacing: '-0.02em', fontSize: '1rem' }}>Create New Task</h3>
            <button onClick={() => setView('board')} style={{ background: 'none', border: 'none', color: 'rgba(255,255,255,0.4)', cursor: 'pointer' }}><X size={16} /></button>
          </div>
          <FormField label="Title">
            <input value={newTask.title} onChange={e => setNewTask(p => ({ ...p, title: e.target.value }))} placeholder="Task title" style={inputStyle} />
          </FormField>
          <FormField label="Description">
            <textarea value={newTask.description} onChange={e => setNewTask(p => ({ ...p, description: e.target.value }))} rows={3} placeholder="What needs to be done?" style={{ ...inputStyle, resize: 'vertical' }} />
          </FormField>
          <FormField label="Priority">
            <select value={newTask.priority} onChange={e => setNewTask(p => ({ ...p, priority: e.target.value as TaskPriority }))} style={inputStyle}>
              <option value="low">Low</option>
              <option value="medium">Medium</option>
              <option value="high">High</option>
              <option value="critical">Critical</option>
            </select>
          </FormField>
          <FormField label="Assign to Agent">
            <select value={newTask.assigned_agent_id} onChange={e => setNewTask(p => ({ ...p, assigned_agent_id: e.target.value }))} style={inputStyle}>
              <option value="">— Unassigned —</option>
              {agents.map(a => (
                <option key={a.id} value={a.id}>{a.name} ({a.specialisation} / {a.role})</option>
              ))}
            </select>
          </FormField>
          <button onClick={createTask} disabled={saving || !newTask.title} style={{
            width: '100%', padding: '0.75rem', background: '#10B981', border: 'none', borderRadius: '8px',
            color: '#000', fontWeight: 900, fontSize: '0.85rem', letterSpacing: '0.06em',
            textTransform: 'uppercase', cursor: saving ? 'not-allowed' : 'pointer', opacity: saving ? 0.6 : 1,
            display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem', marginTop: '0.5rem',
          }}>
            <Plus size={14} /> {saving ? 'Creating...' : 'Create Task'}
          </button>
        </div>
      )}
    </div>
  )
}

// ─── Sub-components ───────────────────────────────────────────────────────────

function AgentCard({ agent, taskCount, expanded, onExpand, onToggle, onDelete }: {
  agent: Agent; taskCount: number; expanded: boolean
  onExpand: () => void; onToggle: () => void; onDelete: () => void
}) {
  const Icon = SPEC_ICON[agent.specialisation]
  const color = SPEC_COLOR[agent.specialisation]
  return (
    <div style={{ background: '#111', border: `1px solid rgba(255,255,255,0.07)`, borderRadius: '10px', overflow: 'hidden' }}>
      <div style={{ padding: '1rem', display: 'flex', alignItems: 'flex-start', gap: '0.75rem' }}>
        <div style={{ width: '36px', height: '36px', borderRadius: '8px', background: `${color}20`, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
          <Icon size={16} color={color} />
        </div>
        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', flexWrap: 'wrap' }}>
            <span style={{ fontWeight: 900, fontSize: '0.9rem', color: '#F3F4F6' }}>{agent.name}</span>
            <span style={{ background: `${STATUS_COLOR[agent.status]}20`, color: STATUS_COLOR[agent.status], fontSize: '0.62rem', fontWeight: 900, letterSpacing: '0.1em', padding: '1px 6px', borderRadius: '3px', textTransform: 'uppercase' }}>
              {agent.status}
            </span>
            <span style={{ background: 'rgba(255,255,255,0.06)', color: 'rgba(255,255,255,0.4)', fontSize: '0.62rem', fontWeight: 700, padding: '1px 6px', borderRadius: '3px', textTransform: 'uppercase' }}>
              {agent.role}
            </span>
          </div>
          <div style={{ fontSize: '0.75rem', color: 'rgba(255,255,255,0.4)', marginTop: '0.2rem' }}>
            {taskCount} active task{taskCount !== 1 ? 's' : ''} · {agent.tasks_completed} completed
          </div>
        </div>
        <button onClick={onExpand} style={{ background: 'none', border: 'none', color: 'rgba(255,255,255,0.3)', cursor: 'pointer', flexShrink: 0 }}>
          {expanded ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
        </button>
      </div>
      {expanded && (
        <div style={{ padding: '0 1rem 1rem', borderTop: '1px solid rgba(255,255,255,0.06)' }}>
          {agent.capabilities?.length > 0 && (
            <div style={{ paddingTop: '0.75rem', display: 'flex', flexWrap: 'wrap', gap: '0.35rem', marginBottom: '0.75rem' }}>
              {agent.capabilities.map(c => (
                <span key={c} style={{ background: 'rgba(255,255,255,0.06)', borderRadius: '4px', padding: '2px 7px', fontSize: '0.68rem', color: 'rgba(255,255,255,0.5)', fontWeight: 600 }}>
                  {c}
                </span>
              ))}
            </div>
          )}
          {agent.pair && (
            <div style={{ fontSize: '0.73rem', color: 'rgba(255,255,255,0.3)', marginBottom: '0.75rem' }}>
              Paired with: <span style={{ color: 'rgba(255,255,255,0.55)' }}>{agent.pair.name}</span>
            </div>
          )}
          <div style={{ display: 'flex', gap: '0.5rem' }}>
            <button onClick={onToggle} style={{
              flex: 1, padding: '0.4rem', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.08)',
              borderRadius: '6px', color: 'rgba(255,255,255,0.55)', fontSize: '0.72rem', fontWeight: 700, cursor: 'pointer',
              display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.3rem',
            }}>
              {agent.status === 'active' ? <><Pause size={11} /> Pause</> : <><Play size={11} /> Resume</>}
            </button>
            <button onClick={onDelete} style={{
              padding: '0.4rem 0.6rem', background: 'rgba(239,68,68,0.08)', border: '1px solid rgba(239,68,68,0.2)',
              borderRadius: '6px', color: '#EF4444', cursor: 'pointer',
            }}>
              <Trash2 size={11} />
            </button>
          </div>
        </div>
      )}
    </div>
  )
}

function TaskCard({ task, expanded, onExpand, onMove, onRetry, onDelete }: {
  task: Task; expanded: boolean
  onExpand: () => void
  onMove: (task: Task, status: TaskStatus) => void
  onRetry: (task: Task) => void
  onDelete: (id: string) => void
}) {
  const isBlocked = task.status === 'blocked'
  const isDone = task.status === 'done'
  const nextIdx = TASK_COLUMNS.indexOf(task.status) + 1
  const nextStatusCandidate = nextIdx < TASK_COLUMNS.length ? TASK_COLUMNS[nextIdx] : undefined
  const nextStatus = (!isBlocked && !isDone && nextStatusCandidate && nextStatusCandidate !== 'blocked')
    ? nextStatusCandidate
    : undefined
  return (
    <div style={{ background: '#0d0d0d', border: `1px solid ${isBlocked ? 'rgba(239,68,68,0.2)' : 'rgba(255,255,255,0.07)'}`, borderRadius: '8px', overflow: 'hidden' }}>
      <div style={{ padding: '0.75rem', cursor: 'pointer' }} onClick={onExpand}>
        <div style={{ display: 'flex', alignItems: 'flex-start', gap: '0.5rem' }}>
          <div style={{ marginTop: '1px', flexShrink: 0 }}>
            {(() => { const I = TASK_STATUS_ICON[task.status]; return <I size={13} color={TASK_STATUS_COLOR[task.status]} /> })()}
          </div>
          <span style={{ flex: 1, fontSize: '0.8rem', fontWeight: 600, color: '#E5E7EB', lineHeight: 1.4 }}>{task.title}</span>
          <button onClick={e => { e.stopPropagation(); onExpand() }} style={{ background: 'none', border: 'none', color: 'rgba(255,255,255,0.25)', cursor: 'pointer', flexShrink: 0, padding: 0 }}>
            {expanded ? <ChevronUp size={12} /> : <ChevronDown size={12} />}
          </button>
        </div>
        <div style={{ display: 'flex', gap: '0.35rem', marginTop: '0.5rem', flexWrap: 'wrap' }}>
          <span style={{ fontSize: '0.62rem', fontWeight: 700, letterSpacing: '0.08em', textTransform: 'uppercase', color: PRIORITY_COLOR[task.priority] }}>
            {task.priority}
          </span>
          {task.agent && (
            <span style={{ fontSize: '0.62rem', color: 'rgba(255,255,255,0.3)', fontWeight: 600 }}>
              → {task.agent.name}
            </span>
          )}
        </div>
      </div>
      {expanded && (
        <div style={{ padding: '0 0.75rem 0.75rem', borderTop: '1px solid rgba(255,255,255,0.05)' }}>
          {task.description && (
            <p style={{ fontSize: '0.75rem', color: 'rgba(255,255,255,0.45)', marginTop: '0.75rem', lineHeight: 1.6 }}>{task.description}</p>
          )}
          <div style={{ display: 'flex', gap: '0.4rem', marginTop: '0.75rem' }}>
            {isBlocked ? (
              <button onClick={() => onRetry(task)} style={{
                flex: 1, padding: '0.35rem', background: 'rgba(16,185,129,0.1)', border: '1px solid rgba(16,185,129,0.3)',
                borderRadius: '5px', color: '#10B981', fontSize: '0.7rem', fontWeight: 700, cursor: 'pointer',
                display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.3rem',
              }}>
                <RotateCcw size={11} /> Retry
              </button>
            ) : nextStatus ? (
              <button onClick={() => onMove(task, nextStatus)} style={{
                flex: 1, padding: '0.35rem', background: '#10B98115', border: '1px solid #10B98130',
                borderRadius: '5px', color: '#10B981', fontSize: '0.7rem', fontWeight: 700, cursor: 'pointer',
                display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.3rem',
              }}>
                <ArrowRight size={11} /> {nextStatus.replace('_', ' ')}
              </button>
            ) : null}
            <button onClick={() => onDelete(task.id)} style={{
              padding: '0.35rem 0.5rem', background: 'rgba(239,68,68,0.08)', border: '1px solid rgba(239,68,68,0.15)',
              borderRadius: '5px', color: '#EF4444', cursor: 'pointer',
            }}>
              <Trash2 size={10} />
            </button>
          </div>
        </div>
      )}
    </div>
  )
}

function FormField({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <div style={{ marginBottom: '1rem' }}>
      <label style={{ display: 'block', fontSize: '0.7rem', fontWeight: 900, letterSpacing: '0.1em', textTransform: 'uppercase', color: 'rgba(255,255,255,0.4)', marginBottom: '0.4rem' }}>
        {label}
      </label>
      {children}
    </div>
  )
}

const inputStyle: React.CSSProperties = {
  width: '100%', padding: '0.6rem 0.75rem', background: '#0a0a0a',
  border: '1px solid rgba(255,255,255,0.1)', borderRadius: '7px',
  color: '#F3F4F6', fontSize: '0.875rem', fontFamily: 'inherit',
  boxSizing: 'border-box',
