'use client'

import { useState, useEffect, useRef } from 'react'
import {
  RoomProvider,
  useStorage,
  useMutation,
  useOthers,
  useUpdateMyPresence
} from '@/liveblocks.config'
import { LiveList } from '@liveblocks/client'
import { Send, User as UserIcon, Smile, Paperclip, MoreVertical, MessageSquare } from 'lucide-react'

import { createBrowserSupabaseClient } from '@/utils/supabase/client'
import { useSmartLoading } from '@/components/GlobalLoadingProvider'

type ChatHistoryMessage = {
  id: string
  senderId: string
  senderName: string
  text: string
  timestamp: string
  isHistory: boolean
}

interface ChatRoomProps {
  roomId: string;
  currentUser: { id: string; name: string };
}

export default function ChatRoom({ currentUser, roomId }: { currentUser: { id: string; name: string }, roomId: string }) {
  const messages = useStorage((root) => root.messages);
  const [history, setHistory] = useState<ChatHistoryMessage[]>([]);
  const [loadingHistory, setLoadingHistory] = useState(true);
  const [text, setText] = useState("");
  const updateMyPresence = useUpdateMyPresence();
  const others = useOthers();
  const scrollRef = useRef<HTMLDivElement>(null);
  const supabase = createBrowserSupabaseClient();
  const { withLoading } = useSmartLoading();

  const isTyping = others.some((other) => other.presence.isTyping);

  const fetchHistory = async () => {
    setLoadingHistory(true);
    const { data } = await supabase
      .from('chat_messages')
      .select('*')
      .eq('room_id', roomId)
      .order('created_at', { ascending: true })
      .limit(50);

    if (data) {
      setHistory(data.map(m => ({
        id: m.id,
        senderId: m.sender_id,
        senderName: m.metadata?.sender_name || 'Student',
        text: m.content,
        timestamp: m.created_at,
        isHistory: true
      })));
    }
    setLoadingHistory(false);
  };

  useEffect(() => {
    void fetchHistory();
  }, [roomId]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, history]);

  const sendMessage = useMutation(({ storage }, text: string) => {
    const messages = storage.get("messages");
    messages.push({
      id: Math.random().toString(36).substr(2, 9),
      senderId: currentUser.id,
      senderName: currentUser.name,
      text,
      timestamp: new Date().toISOString(),
    });
  }, [currentUser]);

  const handleSend = async () => {
    if (!text.trim()) return;

    // 1. Instant Real-time Broadcast via Liveblocks
    sendMessage(text);
    const messageContent = text;
    setText("");
    updateMyPresence({ isTyping: false });

    // 2. Permanent Archival via Supabase + Notification Trigger for Pop-Ups
    await withLoading(async () => {
      // Find recipient Id from roomId (slug: id1_id2)
      const recipientId = roomId.split('_').find(id => id !== currentUser.id);

      const [msgResult, notifyResult] = await Promise.all([
        supabase
          .from('chat_messages')
          .insert({
            room_id: roomId,
            sender_id: currentUser.id,
            content: messageContent,
            metadata: { sender_name: currentUser.name }
          }),
        recipientId ? supabase
          .from('notifications')
          .insert({
            user_id: recipientId,
            type: 'new_message',
            title: currentUser.name,
            message: messageContent.length > 60 ? messageContent.substring(0, 57) + '...' : messageContent,
            link: `/dashboard/network/chat/${currentUser.id}`
          }) : Promise.resolve({ error: null })
      ]);

      if (msgResult.error) console.error("Message backup failed:", msgResult.error);
    }, 'Synchronizing Archive...')
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100%', background: 'var(--surface)', borderRadius: '24px', overflow: 'hidden', border: '1px solid var(--border)' }}>
      {/* Messages Area */}
      <div
        ref={scrollRef}
        style={{ flex: 1, padding: '1.5rem', overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: '1rem' }}
      >
        {loadingHistory && (
          <div style={{ textAlign: 'center', padding: '1rem', color: 'var(--text-sub)', fontSize: '0.8rem' }}>
            Restoring message history...
          </div>
        )}

        {!loadingHistory && history.length > 0 && (
          <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', margin: '0.5rem 0' }}>
            <div style={{ flex: 1, height: '1px', background: 'var(--border)' }} />
            <span style={{ fontSize: '0.6rem', fontWeight: 800, color: 'var(--text-sub)', textTransform: 'uppercase', letterSpacing: '0.1em' }}>Previous Messages</span>
            <div style={{ flex: 1, height: '1px', background: 'var(--border)' }} />
          </div>
        )}

        {/* Render History from Supabase */}
        {history.map((msg) => {
          const isMe = msg.senderId === currentUser.id;
          return (
            <div
              key={msg.id}
              style={{
                alignSelf: isMe ? 'flex-end' : 'flex-start',
                maxWidth: '80%',
                display: 'flex',
                gap: '0.75rem',
                flexDirection: isMe ? 'row-reverse' : 'row'
              }}
            >
              <div style={{ width: '32px', height: '32px', borderRadius: '10px', background: isMe ? 'var(--brand)' : 'var(--bg-sub)', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                <UserIcon size={16} color={isMe ? "white" : "var(--text-sub)"} />
              </div>
              <div style={{
                padding: '0.75rem 1rem',
                borderRadius: isMe ? '18px 4px 18px 18px' : '4px 18px 18px 18px',
                background: isMe ? 'var(--brand)' : 'var(--bg-sub)',
                color: isMe ? 'white' : 'var(--text-main)',
                fontSize: '0.9rem',
                fontWeight: 600,
                boxShadow: 'var(--shadow-sm)',
                opacity: 0.85
              }}>
                {msg.text}
                <div style={{ fontSize: '0.65rem', opacity: 0.6, marginTop: '0.4rem', textAlign: isMe ? 'right' : 'left' }}>
                  {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </div>
              </div>
            </div>
          );
        })}

        {/* Separator if live messages exist */}
        {(messages?.length || 0) > 0 && history.length > 0 && (
          <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', margin: '0.5rem 0' }}>
            <div style={{ flex: 1, height: '1px', background: 'var(--border)', opacity: 0.3 }} />
            <span style={{ fontSize: '0.6rem', fontWeight: 800, color: 'var(--success)', textTransform: 'uppercase' }}>Live Updates</span>
            <div style={{ flex: 1, height: '1px', background: 'var(--border)', opacity: 0.3 }} />
          </div>
        )}

        {/* Render Live Messages from Liveblocks */}
        {messages?.map((msg) => {
          const isMe = msg.senderId === currentUser.id;
          return (
            <div
              key={msg.id}
              style={{
                alignSelf: isMe ? 'flex-end' : 'flex-start',
                maxWidth: '80%',
                display: 'flex',
                gap: '0.75rem',
                flexDirection: isMe ? 'row-reverse' : 'row'
              }}
            >
              <div style={{ width: '32px', height: '32px', borderRadius: '10px', background: isMe ? 'var(--brand)' : 'var(--bg-sub)', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                <UserIcon size={16} color={isMe ? "white" : "var(--text-sub)"} />
              </div>
              <div style={{
                padding: '0.75rem 1rem',
                borderRadius: isMe ? '18px 4px 18px 18px' : '4px 18px 18px 18px',
                background: isMe ? 'var(--brand)' : 'var(--bg-sub)',
                color: isMe ? 'white' : 'var(--text-main)',
                fontSize: '0.9rem',
                fontWeight: 600,
                boxShadow: 'var(--shadow-sm)'
              }}>
                {msg.text}
                <div style={{ fontSize: '0.65rem', opacity: 0.6, marginTop: '0.4rem', textAlign: isMe ? 'right' : 'left' }}>
                  {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </div>
              </div>
            </div>
          );
        })}
        {isTyping && (
          <div style={{ fontSize: '0.75rem', color: 'var(--text-sub)', fontStyle: 'italic', marginLeft: '3.25rem' }}>
            Someone is typing...
          </div>
        )}
      </div>

      {/* Input Area */}
      <div style={{ padding: '1.25rem', borderTop: '1px solid var(--border)', background: 'var(--bg-sub)' }}>
        <div style={{ position: 'relative', display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
          <div style={{ display: 'flex', gap: '0.5rem', color: 'var(--text-sub)' }}>
            <Paperclip size={20} style={{ cursor: 'pointer' }} />
            <Smile size={20} style={{ cursor: 'pointer' }} />
          </div>
          <input
            type="text"
            className="form-input"
            placeholder="Type a message..."
            value={text}
            onChange={(e) => {
              setText(e.target.value);
              updateMyPresence({ isTyping: e.target.value.length > 0 });
            }}
            onKeyDown={handleKeyDown}
            style={{ flex: 1, height: '3rem', borderRadius: '16px', paddingLeft: '1rem', border: '1px solid var(--border)', background: 'var(--surface)' }}
          />
          <button
            onClick={handleSend}
            style={{
              width: '3rem', height: '3rem', borderRadius: '16px', background: 'var(--brand)',
              color: 'white', border: 'none', display: 'flex', alignItems: 'center',
              justifyContent: 'center', cursor: 'pointer', boxShadow: '0 4px 12px rgba(var(--brand-rgb), 0.3)'
            }}
          >
            <Send size={18} />
          </button>
        </div>
      </div>
    </div>
  );
}

'use client'

import { useState, useEffect, useCallback } from 'react'
import { createBrowserSupabaseClient } from '@/utils/supabase/client'
import { Profile } from '@/types/database'
import { Users, UserPlus, Check, ExternalLink, Shield, Sparkles } from 'lucide-react'
import { getFlagComponent } from '@/utils/geo'

interface CollaboratorsListProps {
  currentGroupId: string | null;
  onViewProfile: (profile: Profile) => void;
}

export default function CollaboratorsList({ currentGroupId, onViewProfile }: CollaboratorsListProps) {
  const [collaborators, setCollaborators] = useState<Profile[]>([])
  const [personalNetwork, setPersonalNetwork] = useState<Profile[]>([])
  const [suggested, setSuggested] = useState<Profile[]>([])
  const [connections, setConnections] = useState<Set<string>>(new Set())
  const [loading, setLoading] = useState(true)
  const supabase = createBrowserSupabaseClient()

  const fetchCollaborators = useCallback(async () => {
    const { data: { user } } = await supabase.auth.getUser()
    // Use either the passed prop or the profile's group_id
    const groupId = currentGroupId
    
    if (!user || !groupId) {
      return
    }

    const { data } = await supabase
      .from('profiles')
      .select('*')
      .eq('group_id', groupId)
      .neq('id', user.id)

    if (data) {
      setCollaborators(data as Profile[])
    }
  }, [supabase, currentGroupId])

  const fetchSuggested = useCallback(async () => {
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) return

    // Fetch users NOT in the current group and NOT already connected
    const { data } = await supabase
      .from('profiles')
      .select('*')
      .neq('id', user.id)
      .not('group_id', 'eq', currentGroupId || '00000000-0000-0000-0000-000000000000')
      .limit(6)

    if (data) setSuggested(data as Profile[])
  }, [supabase, currentGroupId])

  const fetchConnections = useCallback(async () => {
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) return

    // 1. Fetch connected IDs for fast lookup
    const { data: connData } = await supabase
      .from('user_connections')
      .select('user_id, target_id')
      .or(`user_id.eq.${user.id},target_id.eq.${user.id}`)
      .eq('status', 'connected')

    if (connData) {
      const ids = connData.map((c: any) => c.user_id === user.id ? c.target_id : c.user_id)
      const uniqueIds = Array.from(new Set(ids))
      setConnections(new Set(uniqueIds))

      // 2. Fetch full profiles for these connections (Global Discovery unblocked by RLS)
      if (uniqueIds.length > 0) {
        const { data: profiles, error } = await supabase
          .from('profiles')
          .select('*')
          .in('id', uniqueIds)
        
        if (profiles) {
          setPersonalNetwork(profiles as Profile[])
        }
      } else {
        setPersonalNetwork([])
      }
    }
  }, [supabase])

  useEffect(() => {
    let active = true
    const load = async () => {
      setLoading(true)
      await Promise.all([
        fetchCollaborators(),
        fetchConnections(),
        fetchSuggested()
      ])
      if (active) setLoading(false)
    }

    void load()
    
    // Subscribe to connection updates
    const channel = supabase.channel('network_updates')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'user_connections' }, () => {
        void fetchConnections()
      })
      .subscribe()

    return () => { 
      active = false
      supabase.removeChannel(channel)
    }
  }, [currentGroupId, fetchCollaborators, fetchConnections, fetchSuggested])

  const handleConnect = async (targetId: string) => {
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) return

    // Create a connection request/approval flow
    // For immediate addition in this simplified UI flow, we upsert to connected
    const { error } = await supabase
      .from('user_connections')
      .upsert({ user_id: user.id, target_id: targetId, status: 'connected' })

    if (!error) {
      setConnections(prev => new Set([...Array.from(prev), targetId]))
      void fetchConnections() // Refresh network list
      
      // Send notification to target
      await supabase.from('notifications').insert({
        user_id: targetId,
        type: 'connection_request',
        title: 'Network Expansion',
        message: `${user.user_metadata?.full_name || 'A scholar'} has established a synchronization link with you.`,
        metadata: { sender_id: user.id }
      })
    }
  }

  const renderUserCard = (collab: Profile) => {
    const isConnected = connections.has(collab.id)
    const isTeammate = collab.group_id === currentGroupId

    return (
      <div 
        key={collab.id}
        style={{ 
          display: 'flex', 
          alignItems: 'center', 
          gap: '0.6rem', 
          padding: '0.5rem 0', 
          borderBottom: '1px solid rgba(var(--text-main-rgb), 0.05)',
          transition: 'all 0.2s',
          animation: 'fadeIn 0.3s ease-out'
        }}
      >
        <div style={{ width: '32px', height: '32px', borderRadius: '8px', background: 'var(--brand)', overflow: 'hidden', flexShrink: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', fontWeight: 900, fontSize: '0.7rem' }}>
          {collab.avatar_url ? (
            <img src={collab.avatar_url} alt="avatar" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
          ) : (
            collab.full_name?.[0] || '?'
          )}
        </div>
        
        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ fontSize: '0.8rem', fontWeight: 800, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', color: 'var(--text-main)', display: 'flex', alignItems: 'center', gap: '0.4rem' }}>
            {collab.full_name || 'Anonymous'}
            {(() => {
              const Flag = getFlagComponent((collab as any).country_code)
              return Flag ? <div style={{ width: '14px', height: '10px', borderRadius: '2px', overflow: 'hidden' }}><Flag /></div> : null
            })()}
          </div>
          <div style={{ fontSize: '0.6rem', color: 'var(--text-sub)', display: 'flex', alignItems: 'center', gap: '0.4rem', fontWeight: 700, textTransform: 'uppercase' }}>
             {isTeammate && <span style={{ color: 'var(--brand)', display: 'flex', alignItems: 'center', gap: '0.2rem' }}><Users size={10} /> Team</span>}
             <span>{collab.rank || 'Scholar'}</span>
          </div>
        </div>

        <div style={{ display: 'flex', gap: '0.25rem' }}>
          <button 
            onClick={() => onViewProfile(collab)}
            className="panel-tool"
            style={{ width: '28px', height: '28px', display: 'flex', alignItems: 'center', justifyContent: 'center', borderRadius: '6px' }}
          >
            <ExternalLink size={12} />
          </button>
          {!isConnected && (
            <button 
              onClick={() => handleConnect(collab.id)}
              style={{ 
                width: '28px', height: '28px', borderRadius: '6px', border: 'none', 
                background: 'var(--brand)', color: 'white', cursor: 'pointer',
                display: 'flex', alignItems: 'center', justifyContent: 'center'
              }}
            >
              <UserPlus size={12} />
            </button>
          )}
        </div>
      </div>
    )
  }

  return (
    <div className="collaborators-container" style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
      
      {/* 1. TEAM SECTION */}
      <div style={{ background: 'var(--surface)', borderRadius: '20px', border: '1px solid var(--border)', padding: '1rem', boxShadow: 'var(--shadow-sm)' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.75rem' }}>
          <Users size={16} color="var(--brand)" />
          <h3 style={{ margin: 0, fontSize: '0.75rem', fontWeight: 900, textTransform: 'uppercase', letterSpacing: '0.05em' }}>Team Collaborators</h3>
        </div>

        {loading ? (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '0.25rem' }}>
            {[1, 2].map(i => <div key={i} className="skeleton" style={{ height: '32px', borderRadius: '6px' }} />)}
          </div>
        ) : collaborators.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '1rem', border: '1px dashed var(--border)', borderRadius: '12px' }}>
            <span style={{ fontSize: '0.65rem', color: 'var(--text-sub)', fontWeight: 700 }}>Empty Set</span>
          </div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column' }}>
            {collaborators.map(renderUserCard)}
          </div>
        )}
      </div>

      {/* 2. PERSONAL NETWORK SECTION */}
      {personalNetwork.length > 0 && (
        <div style={{ background: 'var(--surface)', borderRadius: '20px', border: '1px solid var(--border)', padding: '1rem', boxShadow: 'var(--shadow-sm)' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.75rem' }}>
            <Sparkles size={16} color="var(--brand)" />
            <h3 style={{ margin: 0, fontSize: '0.75rem', fontWeight: 900, textTransform: 'uppercase', letterSpacing: '0.05em' }}>Personal Network</h3>
          </div>

          <div style={{ display: 'flex', flexDirection: 'column' }}>
            {personalNetwork.map(renderUserCard)}
          </div>
        </div>
      )}

      {/* 3. SUGGESTED SECTION */}
      <div style={{ background: 'var(--surface)', borderRadius: '20px', border: '1px solid var(--border)', padding: '1rem', boxShadow: 'var(--shadow-sm)' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.75rem' }}>
          <UserPlus size={16} color="var(--text-sub)" />
          <h3 style={{ margin: 0, fontSize: '0.75rem', fontWeight: 900, textTransform: 'uppercase', letterSpacing: '0.05em' }}>Global Discovery</h3>
        </div>

        {loading ? (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '0.25rem' }}>
            {[1, 2, 3].map(i => <div key={i} className="skeleton" style={{ height: '32px', borderRadius: '6px' }} />)}
          </div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column' }}>
            {suggested.map(renderUserCard)}
          </div>
        )}
      </div>

      <style jsx>{`
        @keyframes fadeIn { from { opacity: 0; transform: translateY(5px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  )
}

'use client'

import { useState, useEffect } from 'react'
import { createBrowserSupabaseClient } from '@/utils/supabase/client'
import { UserPlus, X, Check, ExternalLink, RefreshCw } from 'lucide-react'
import { useNotifications } from './NotificationProvider'
import Link from 'next/link'

export default function ConnectionAlertTray() {
  const [requests, setRequests] = useState<Array<Record<string, unknown>>>([])
  const [loading, setLoading] = useState(true)
  const [processingId, setProcessingId] = useState<string | null>(null)
  const supabase = createBrowserSupabaseClient()
  const { addToast } = useNotifications()

  const fetchRequests = async () => {
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) return

    const { data, error } = await supabase
      .from('user_connections')
      .select('*, profiles!user_connections_user_id_fkey(id, full_name, avatar_url, course_name)')
      .eq('target_id', user.id)
      .eq('status', 'pending')

    if (error) {
      console.error('Error fetching connection requests:', error)
    } else {
      setRequests(data || [])
    }
    setLoading(false)
  }

  useEffect(() => {
    queueMicrotask(() => {
      void fetchRequests()
    })

    // Real-time subscription for new requests
    const channel = supabase
      .channel('connection_requests_sync')
      .on(
        'postgres_changes',
        { 
          event: '*', 
          schema: 'public', 
          table: 'user_connections'
        },
        () => fetchRequests()
      )
      .subscribe()

    return () => {
      supabase.removeChannel(channel)
    }
  }, [])

  const handleAction = async (requestId: string, senderId: string, action: 'accept' | 'decline') => {
    setProcessingId(requestId)
    try {
      const { data: { user } } = await supabase.auth.getUser()
      if (!user) return

      if (action === 'accept') {
        const { error } = await supabase
          .from('user_connections')
          .update({ status: 'connected' })
          .eq('id', requestId)

        if (error) throw error

        // Notify sender
        await supabase.from('notifications').insert({
          user_id: senderId,
          type: 'connection_accepted',
          title: 'Connection Established',
          message: 'Your connection request was accepted.',
          link: `/dashboard/network/profile/${user.id}`
        })

        addToast('Connected!', 'You are now connected with a new specialist.', 'success')
      } else {
        const { error } = await supabase
          .from('user_connections')
          .delete()
          .eq('id', requestId)

        if (error) throw error
        addToast('Request Ignored', 'The connection request has been removed.', 'info')
      }

      // Mark any associated notifications as read
      const { data: notifs } = await supabase
        .from('notifications')
        .select('id')
        .eq('user_id', user.id)
        .eq('type', 'connection_request')
        .contains('metadata', { sender_id: senderId })

      if (notifs && notifs.length > 0) {
        await supabase
          .from('notifications')
          .update({ read: true })
          .in('id', notifs.map(n => n.id))
      }

      await fetchRequests()
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : 'Action failed'
      addToast('Sync Error', message, 'error')
    } finally {
      setProcessingId(null)
    }
  }

  if (loading || requests.length === 0) return null

  return (
    <div className="connection-tray-container" style={{ margin: '0 0 var(--gap-md) 0', animation: 'slideInDown 0.4s cubic-bezier(0.23, 1, 0.32, 1)' }}>
      {requests.map((req) => (
        <div 
          key={req.id} 
          style={{ 
            background: 'rgba(var(--brand-rgb), 0.05)', 
            border: '1px solid var(--brand)', 
            borderRadius: '16px', 
            padding: '0.75rem 1.25rem',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            gap: '1rem',
            flexWrap: 'wrap',
            boxShadow: '0 4px 15px rgba(var(--brand-rgb), 0.1)',
            marginBottom: requests.length > 1 ? '0.5rem' : 0
          }}
        >
          <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', flex: 1 }}>
            <div style={{ padding: '8px', background: 'var(--brand)', color: 'white', borderRadius: '10px' }}>
              <UserPlus size={18} />
            </div>
            <div>
              <div style={{ fontSize: '0.9rem', fontWeight: 900, color: 'var(--text-main)', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                Pending Connection Request
                <span className="pulse-pill" style={{ width: '6px', height: '6px', borderRadius: '50%', background: 'var(--brand)' }} />
              </div>
              <div style={{ fontSize: '0.8rem', color: 'var(--text-sub)' }}>
                <strong>{req.profiles?.full_name || 'A student'}</strong> wants to connect for collaboration.
              </div>
            </div>
          </div>

          <div style={{ display: 'flex', alignItems: 'center', gap: '0.6rem' }}>
             <Link 
               href={`/dashboard/network/profile/${req.user_id}`}
               style={{ 
                 padding: '0.5rem', 
                 borderRadius: '8px', 
                 color: 'var(--text-sub)', 
                 background: 'var(--bg-sub)',
                 border: '1px solid var(--border)',
                 display: 'flex',
                 alignItems: 'center',
                 justifyContent: 'center',
                 transition: 'all 0.2s'
               }}
               title="View Profile"
             >
                <ExternalLink size={16} />
             </Link>
             
             <button 
               onClick={() => handleAction(req.id, req.user_id, 'decline')}
               disabled={processingId === req.id}
               style={{ 
                 padding: '0.5rem 1rem', 
                 borderRadius: '10px', 
                 background: 'var(--bg-sub)', 
                 color: 'var(--text-sub)',
                 border: '1px solid var(--border)',
                 fontSize: '0.75rem',
                 fontWeight: 800,
                 cursor: 'pointer'
               }}
             >
               {processingId === req.id ? '...' : 'Ignore'}
             </button>

             <button 
               onClick={() => handleAction(req.id, req.user_id, 'accept')}
               disabled={processingId === req.id}
               style={{ 
                 padding: '0.5rem 1.25rem', 
                 borderRadius: '10px', 
                 background: 'var(--brand)', 
                 color: 'white',
                 border: 'none',
                 fontSize: '0.75rem',
                 fontWeight: 900,
                 cursor: 'pointer',
                 boxShadow: '0 4px 10px rgba(var(--brand-rgb), 0.2)',
                 display: 'flex',
                 alignItems: 'center',
                 gap: '0.4rem'
               }}
             >
               {processingId === req.id ? <RefreshCw size={14} className="spin" /> : <Check size={16} />}
               Accept Request
             </button>
          </div>
        </div>
      ))}

      <style jsx>{`
        @keyframes slideInDown {
          from { transform: translateY(-20px); opacity: 0; }
          to { transform: translateY(0); opacity: 1; }
        }
        .spin { animation: spin 1s linear infinite; }
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
      `}</style>
    </div>
  )
}

'use client'

import { useState, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { Shield, Zap, Check } from 'lucide-react'

export default function CookieBanner() {
  const [isVisible, setIsVisible] = useState(false)

  useEffect(() => {
    const consent = localStorage.getItem('gf_cookie_consent')
    if (!consent) {
      const timer = setTimeout(() => setIsVisible(true), 2000)
      return () => clearTimeout(timer)
    }
  }, [])

  const handleAccept = (type: 'all' | 'speed') => {
    localStorage.setItem('gf_cookie_consent', type)
    if (type === 'speed') {
      localStorage.setItem('gf_speed_preference', 'fast')
    }
    setIsVisible(false)
  }

  return (
    <AnimatePresence>
      {isVisible && (
        <motion.div
          initial={{ y: 100, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          exit={{ y: 100, opacity: 0 }}
          style={{
            position: 'fixed',
            bottom: '2rem',
            left: '50%',
            transform: 'translateX(-50%)',
            zIndex: 5000,
            width: '90%',
            maxWidth: '600px',
            background: '#111111',
            border: '1px solid #222222',
            borderRadius: '16px',
            padding: '1.5rem',
            boxShadow: '0 20px 50px rgba(0,0,0,0.8)',
            display: 'flex',
            flexDirection: 'column',
            gap: '1rem'
          }}
        >
          <div style={{ display: 'flex', alignItems: 'flex-start', gap: '1rem' }}>
            <div style={{ padding: '0.75rem', background: 'rgba(16, 185, 129, 0.1)', borderRadius: '12px', color: '#10b981' }}>
              <Shield size={24} />
            </div>
            <div style={{ flex: 1 }}>
              <h4 style={{ margin: 0, color: '#f3f4f6', fontSize: '1.1rem', fontWeight: 700 }}>We value your privacy</h4>
              <p style={{ margin: '0.25rem 0 0', color: '#9ca3af', fontSize: '0.875rem', lineHeight: 1.5 }}>
                We use cookies to improve your experience and keep everything running smoothly. Is that okay?
              </p>
            </div>
          </div>

          <div style={{ display: 'flex', gap: '0.75rem', marginTop: '0.5rem' }}>
            <button 
              onClick={() => handleAccept('speed')}
              style={{ 
                flex: 1, 
                background: 'rgba(255,255,255,0.03)', 
                border: '1px solid #222', 
                color: '#f3f4f6', 
                padding: '0.75rem', 
                borderRadius: '8px', 
                fontWeight: 650, 
                fontSize: '0.875rem',
                cursor: 'pointer',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                gap: '0.5rem'
              }}
            >
              Essential Only
            </button>
            <button 
              onClick={() => handleAccept('all')}
              style={{ 
                flex: 1, 
                background: '#10b981', 
                border: 'none', 
                color: '#0a0a0a', 
                padding: '0.75rem', 
                borderRadius: '8px', 
                fontWeight: 800, 
                fontSize: '0.875rem',
                cursor: 'pointer',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                gap: '0.5rem'
              }}
            >
              <Check size={14} /> Yes, Accept All
            </button>
          </div>
        </motion.div>
      )}
    </AnimatePresence>
  )
}

'use client'

import { useState, useEffect, useMemo, useCallback } from 'react'
import { useRouter } from 'next/navigation'
import { createBrowserSupabaseClient } from '@/utils/supabase/client'
import KanbanBoard from './KanbanBoard'
import CalendarView from './CalendarView'
import { LayoutDashboard, Calendar, Activity, Zap, TrendingUp, Users, UserCircle } from 'lucide-react'
import { Group, Profile } from '@/types/database'
import { useProfile } from '@/context/ProfileContext'
import { useNotifications } from './NotificationProvider'

interface JoinRequest {
  id: string
  group_id: string
  user_id: string
  status: string
  created_at: string
  profiles?: {
    id: string
    full_name: string | null
    avatar_url: string | null
  }
}

export default function DashboardHome({ groupId }: { groupId: string }) {
  const router = useRouter()
  const { profile } = useProfile()
  const { addToast } = useNotifications()
  const [activeTab, setActiveTab] = useState<'board' | 'calendar'>('board')
  const [currentTime, setCurrentTime] = useState(new Date())

  const [greeting] = useState(() => {
    const hour = new Date().getHours()
    if (hour < 12) return 'Good Morning'
    if (hour < 18) return 'Good Afternoon'
    return 'Good Evening'
  })

  // 1. Sync local time display
  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 60000)
    return () => clearInterval(timer)
  }, [])

  const [personalTaskCount, setPersonalTaskCount] = useState(0)
  const [group, setGroup] = useState<Group | null>(null)
  const [newTaskSignal, setNewTaskSignal] = useState(0)
  const [syncToken, setSyncToken] = useState(0)
  const [members, setMembers] = useState<Profile[]>([])
  const [pendingRequests, setPendingRequests] = useState<JoinRequest[]>([])
  const [showMembers, setShowMembers] = useState(false)
  const [projectProgress, setProjectProgress] = useState(0)
  const [progressLabel, setProgressLabel] = useState('Starting up')
  const [totalBacklog, setTotalBacklog] = useState(0)

  // 0. BLAZING SPEED CACHE: Perceptive hydration
  useEffect(() => {
    if (!groupId) return
    try {
      const cachedGroup = localStorage.getItem(`gf_cache_group_${groupId}`)
      const cachedStats = localStorage.getItem(`gf_cache_stats_${groupId}`)

      if (cachedGroup) {
        const parsedGroup = JSON.parse(cachedGroup) as Group
        queueMicrotask(() => setGroup(parsedGroup))
      }
      if (cachedStats) {
        const stats = JSON.parse(cachedStats)
        queueMicrotask(() => {
          setPersonalTaskCount(stats.personal || 0)
          setTotalBacklog(stats.backlog || 0)
          setProjectProgress(stats.progress || 0)
          setProgressLabel(stats.label || 'Just a moment...')
        })
      }
    } catch (e) {
      console.warn('Cache hydration failed defensively:', e)
      // Carry on silently, real data will fetch
    }
  }, [groupId])

  const handleCalendarTaskSaved = useCallback(async () => {
    setSyncToken(prev => prev + 1)
  }, [])

  const supabase = useMemo(() => createBrowserSupabaseClient(), [])

  const fetchGroupDetails = useCallback(async () => {
    const { data } = await supabase.from('groups').select('*').eq('id', groupId).single()
    if (data) {
      setGroup(data)
      localStorage.setItem(`gf_cache_group_${groupId}`, JSON.stringify(data))
    }
  }, [groupId, supabase])

  const fetchMembers = useCallback(async () => {
    if (!groupId) return
    const { data, error } = await supabase
      .from('profiles')
      .select('id, full_name, avatar_url, last_seen, role')
      .eq('group_id', groupId)

    if (error) {
      console.error('Error fetching group members:', error.message)
      return
    }

    if (data) setMembers(data as unknown as Profile[])
  }, [groupId, supabase])

  const fetchPendingRequests = useCallback(async () => {
    if (!groupId || profile?.role !== 'admin') return
    const { data } = await supabase
      .from('group_join_requests')
      .select('*, profiles(id, full_name, avatar_url)')
      .eq('group_id', groupId)
      .eq('status', 'pending')

    setPendingRequests(data || [])
  }, [groupId, profile?.role, supabase])

  const handleAcceptRequest = async (id: string) => {
    const { acceptJoinRequest } = await import('@/app/dashboard/join/actions')
    const res = await acceptJoinRequest(id)
    if (res.error) addToast('Oops, something went wrong', 'We couldn\'t add the member right now. Let\'s try again.', 'error')
    else {
      addToast('All set!', 'Your teammate is now in the group.', 'success')
      void fetchMembers()
      void fetchPendingRequests()
    }
  }

  const handleDeclineRequest = async (id: string) => {
    const { declineJoinRequest } = await import('@/app/dashboard/join/actions')
    const res = await declineJoinRequest(id)
    if (res.error) addToast('Slight issue', 'We couldn\'t update the request. Please try again.', 'error')
    else {
      addToast('Request updated', 'The join request has been removed.', 'info')
      void fetchPendingRequests()
    }
  }

  const fetchPersonalTaskCount = useCallback(async () => {
    if (!profile?.id || !groupId) return

    const { count, error } = await supabase
      .from('tasks')
      .select('*', { count: 'exact', head: true })
      .eq('group_id', groupId)
      .contains('assignees', [profile.id])
      .neq('status', 'Done')

    if (error) {
      console.warn('Silent failure on personal task count:', error.message)
      return
    }

    if (count !== null) setPersonalTaskCount(count)
  }, [profile, groupId, supabase])

  const fetchProjectProgress = useCallback(async () => {
    if (!groupId) return
    const { data: tasks, error } = await supabase
      .from('tasks')
      .select('status')
      .eq('group_id', groupId)

    if (error || !tasks || tasks.length === 0) {
      setProjectProgress(0)
      setProgressLabel('Empty Backlog')
      setTotalBacklog(0)
      return
    }

    const pending = tasks.filter(t => t.status !== 'Done').length
    setTotalBacklog(pending)

    const completed = tasks.filter(t => t.status === 'Done').length
    const progress = Math.round((completed / tasks.length) * 100)
    setProjectProgress(progress)

    // Better logic for labels
    let label = 'Almost finished'
    if (progress <= 30) label = 'Just starting'
    else if (progress <= 50) label = 'Making progress'
    else if (progress <= 80) label = 'Smoothing things out'
    
    setProgressLabel(label)
    
    // PERSIST STATS for PERCEPTIVE SPEED
    localStorage.setItem(`gf_cache_stats_${groupId}`, JSON.stringify({
      personal: personalTaskCount,
      backlog: pending,
      progress: progress,
      label: label
    }))
  }, [groupId, supabase])

  useEffect(() => {
    if (!groupId) return

    // BATCH PARALLEL INITIALIZATION
    const initializeDashboardData = async () => {
      const tasks = [
        fetchGroupDetails(),
        fetchMembers(),
        fetchPendingRequests()
      ]
      
      if (profile?.id) {
        tasks.push(fetchPersonalTaskCount())
        tasks.push(fetchProjectProgress())
      }

      await Promise.all(tasks)
    }

    void initializeDashboardData()

    const channel = supabase.channel('dashboard_sync')
        .on(
          'postgres_changes',
          { event: '*', schema: 'public', table: 'tasks', filter: `group_id=eq.${groupId}` },
          () => {
            void fetchPersonalTaskCount()
            void fetchProjectProgress()
          }
        )
        .on(
          'postgres_changes',
          { event: '*', schema: 'public', table: 'profiles', filter: `group_id=eq.${groupId}` },
          () => void fetchMembers()
        )
        .on(
          'postgres_changes',
          { event: '*', schema: 'public', table: 'group_join_requests', filter: `group_id=eq.${groupId}` },
          () => void fetchPendingRequests()
        )
        .subscribe()

      return () => {
        supabase.removeChannel(channel)
      }
  }, [profile?.id, groupId, fetchPersonalTaskCount, fetchProjectProgress, fetchMembers, fetchPendingRequests, supabase])

  const renderRoleBadge = (role: string | null) => {
    const r = role?.toUpperCase()
    if (r === 'TEAM_LEADER' || r === 'ADMIN') return <span style={{ fontSize: '0.6rem', padding: '1px 6px', borderRadius: '4px', background: 'var(--brand)', color: 'white', fontWeight: 900, marginLeft: '4px' }}>{r.replace('_', ' ')}</span>
    if (r === 'MODERATOR') return <span style={{ fontSize: '0.6rem', padding: '1px 6px', borderRadius: '4px', background: 'var(--success)', color: 'white', fontWeight: 900, marginLeft: '4px' }}>MOD</span>
    return null
  }

  if (!profile) {
    return (
      <div style={{ display: 'flex', flexDirection: 'column', gap: '2rem' }}>
        <div className="skeleton" style={{ height: '140px', borderRadius: '24px' }} />
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end' }}>
          <div style={{ flex: 1 }}>
            <div className="skeleton skeleton-title" style={{ width: '40%' }} />
            <div className="skeleton skeleton-text" style={{ width: '60%' }} />
          </div>
          <div className="skeleton" style={{ width: '200px', height: '50px', borderRadius: '14px' }} />
        </div>
        <div className="skeleton" style={{ height: '400px', borderRadius: '24px' }} />
      </div>
    )
  }

  return (
    <div className="page-fade" style={{ display: 'flex', flexDirection: 'column', gap: 'var(--gap-md)', width: '100%', maxWidth: '1400px', margin: '0 auto', paddingBottom: '4rem' }}>

      {/* ── CONTROL PANEL HEADER ─────────────────────────────────────────── */}
      <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: '2rem', flexWrap: 'wrap' }}>
        <div style={{ flex: 1, minWidth: '300px' }}>

          <h1 style={{ fontSize: 'clamp(1.5rem, 4vw, 2.25rem)', fontWeight: 950, letterSpacing: '-0.04em', color: 'var(--text-main)', margin: 0, lineHeight: 1.1, display: 'flex', alignItems: 'center', gap: '1rem' }}>
            {greeting}, {profile?.full_name?.split(' ')[0] || 'User'}
            {profile?.subscription_plan === 'premium' && <span className="locked-badge locked-badge-premium glow-premium" style={{ margin: 0, fontSize: '0.7rem' }}>PREMIUM TEAM</span>}
            {profile?.subscription_plan === 'pro' && <span className="locked-badge locked-badge-pro glow-pro" style={{ margin: 0, fontSize: '0.7rem' }}>PRO MEMBER</span>}
          </h1>

          <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginTop: '1.25rem' }}>
            <div style={{ padding: '0.4rem 0.8rem', background: 'rgba(var(--brand-rgb), 0.08)', borderRadius: '10px', border: '1px solid rgba(var(--brand-rgb), 0.15)', display: 'flex', alignItems: 'center', gap: '0.5rem', boxShadow: 'var(--shadow-sm)' }}>
              <Zap size={12} color="var(--brand)" fill="var(--brand)" style={{ opacity: 0.8 }} />
              <span style={{ fontSize: '0.75rem', fontWeight: 900, color: 'var(--text-main)', letterSpacing: '0.04em', textTransform: 'uppercase' }}>
                TEAM: <span style={{ color: 'var(--brand)' }}>{group?.name || 'STARTING UP...'}</span>
              </span>
            </div>

            <button
              onClick={() => setShowMembers(!showMembers)}
              className={`btn ${showMembers ? 'btn-primary' : 'btn-secondary'}`}
              style={{
                fontSize: '0.8rem',
                fontWeight: 900,
                padding: '0.65rem 1.4rem',
                borderRadius: '14px',
                display: 'flex',
                alignItems: 'center',
                gap: '0.6rem',
                border: showMembers ? 'none' : '1px solid var(--border)',
                transition: 'all 0.3s cubic-bezier(0.34, 1.56, 0.64, 1)',
                boxShadow: showMembers ? '0 4px 12px rgba(var(--brand-rgb), 0.3)' : 'var(--shadow-sm)',
                textTransform: 'uppercase',
                letterSpacing: '0.05em'
              }}
            >
              <Users size={16} />
              Team Roster
              <span style={{
                background: showMembers ? 'white' : 'var(--brand)',
                color: showMembers ? 'var(--brand)' : 'white',
                padding: '2px 8px',
                borderRadius: '8px',
                fontSize: '0.7rem',
                marginLeft: '0.4rem',
                fontWeight: 950
              }}>
                {members.length || 0} / {group?.capacity || 5}
                {pendingRequests.length > 0 && ` (+${pendingRequests.length} PENDING)`}
              </span>
            </button>
          </div>

          {showMembers && (
            <div style={{
              display: 'flex',
              flexDirection: 'column',
              gap: '1rem',
              marginTop: '1.25rem',
              animation: 'fadeInSlide 0.4s cubic-bezier(0.23, 1, 0.32, 1)',
              background: 'var(--bg-sub)',
              padding: '1.25rem',
              borderRadius: '20px',
              border: '1px solid var(--border)',
              maxWidth: '450px',
              zIndex: 100,
              boxShadow: 'var(--shadow-xl)'
            }}>

              {/* Active Members */}
              <div style={{ fontSize: '0.65rem', fontWeight: 900, color: 'var(--text-sub)', textTransform: 'uppercase', letterSpacing: '0.1em', marginBottom: '0.25rem' }}>Active Members</div>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: '0.75rem' }}>
                {members.map(m => {
                  const isSelf = m.id === profile?.id
                  const lastSeenDate = m.last_seen ? new Date(m.last_seen) : null
                  const isOnline = lastSeenDate && (new Date().getTime() - lastSeenDate.getTime() < 120000)

                  return (
                    <div key={m.id} style={{
                      display: 'flex',
                      alignItems: 'center',
                      gap: '0.6rem',
                      padding: '8px 14px',
                      background: 'var(--surface)',
                      border: '1px solid var(--border)',
                      borderRadius: '12px',
                      boxShadow: 'var(--shadow-sm)',
                      cursor: 'pointer',
                      transition: 'transform 0.2s'
                    }}
                      onClick={() => router.push(`/dashboard/network/profile/${m.id}`)}
                    >
                      <div style={{ position: 'relative' }}>
                        <div style={{ width: '28px', height: '28px', borderRadius: '50%', background: 'var(--bg-main)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '11px', fontWeight: 900, color: 'var(--brand)', border: '1px solid var(--border)', overflow: 'hidden' }}>
                          {m.avatar_url ? <img src={m.avatar_url} style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : m.full_name?.[0]}
                        </div>
                        <div style={{ position: 'absolute', bottom: -1, right: -1, width: '10px', height: '10px', borderRadius: '50%', background: isOnline ? 'var(--success)' : '#94a3b8', border: '2px solid var(--surface)', boxShadow: isOnline ? '0 0 8px var(--success)' : 'none' }} />
                      </div>
                      <div style={{ display: 'flex', flexDirection: 'column' }}>
                        <div style={{ fontSize: '0.85rem', fontWeight: 850, color: 'var(--text-main)', lineHeight: 1, display: 'flex', alignItems: 'center' }}>
                          {m.full_name?.split(' ')[0]}{isSelf && ' (You)'}
                          {renderRoleBadge(m.role)}
                        </div>
                        <span style={{ fontSize: '0.65rem', fontWeight: 700, color: 'var(--text-sub)', marginTop: '2px' }}>
                          {isOnline ? 'Active Now' : 'Offline'}
                        </span>
                      </div>
                    </div>
                  )
                })}
              </div>

              {/* Pending Requests Section */}
              {pendingRequests.length > 0 && (
                <>
                  <div style={{ height: '1px', background: 'var(--border)', margin: '0.5rem 0' }} />
                  <div style={{ fontSize: '0.65rem', fontWeight: 900, color: 'var(--brand)', textTransform: 'uppercase', letterSpacing: '0.1em', marginBottom: '0.25rem' }}>Incoming Requests ({pendingRequests.length})</div>
                  <div style={{ display: 'flex', flexDirection: 'column', gap: '0.6rem' }}>
                    {pendingRequests.map(r => (
                      <div key={r.id} style={{
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'space-between',
                        padding: '10px 14px',
                        background: 'rgba(var(--brand-rgb), 0.03)',
                        border: '1px dashed var(--brand)',
                        borderRadius: '12px'
                      }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                          <div style={{ width: '32px', height: '32px', borderRadius: '8px', background: 'var(--surface)', border: '1px solid var(--border)', overflow: 'hidden', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                            {r.profiles?.avatar_url ? <img src={r.profiles.avatar_url} style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <UserCircle size={18} color="var(--text-sub)" />}
                          </div>
                          <div style={{ fontWeight: 850, fontSize: '0.85rem', color: 'var(--text-main)' }}>{r.profiles?.full_name}</div>
                        </div>
                        <div style={{ display: 'flex', gap: '0.4rem' }}>
                          <button onClick={() => handleDeclineRequest(r.id)} style={{ padding: '6px 10px', borderRadius: '8px', border: '1px solid var(--border)', background: 'var(--surface)', color: 'var(--error)', fontSize: '0.65rem', fontWeight: 900, cursor: 'pointer' }}>Decline</button>
                          <button onClick={() => handleAcceptRequest(r.id)} style={{ padding: '6px 10px', borderRadius: '8px', border: 'none', background: 'var(--brand)', color: 'white', fontSize: '0.65rem', fontWeight: 900, cursor: 'pointer' }}>Accept</button>
                        </div>
                      </div>
                    ))}
                  </div>
                </>
              )}
            </div>
          )}
        </div>

        <div style={{ display: 'flex', gap: '0.75rem' }}>
          <button
            onClick={() => setNewTaskSignal(prev => prev + 1)}
            className="btn btn-primary btn-inline"
            aria-label="Create a new task"
            style={{ padding: '0.6rem 1rem', borderRadius: '10px', fontWeight: 900 }}
          >
            <Zap size={16} fill="currentColor" aria-hidden="true" /> New Task
          </button>
          <button
            onClick={() => router.push(`/dashboard/analytics/${groupId}`)}
            className="btn btn-secondary btn-inline"
            aria-label="View group updates and progress"
            style={{ padding: '0.8rem 1.5rem', borderRadius: '16px', fontWeight: 800 }}
          >
            Group Updates
          </button>
        </div>
      </header>

      {/* ── METRICS MODULES ────────────────────────────────────────────── */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '1.25rem' }}>
        {[
          { icon: <Activity size={20} />, label: 'Your Goals', value: personalTaskCount, sub: 'Tasks for you to do', color: 'var(--brand)' },
          { icon: <Users size={20} />, label: 'Team Progress', value: totalBacklog, sub: 'Tasks left for the team', color: 'var(--success)' },
          { icon: <TrendingUp size={20} />, label: 'Overall Completion', value: `${projectProgress}%`, sub: progressLabel, color: '#f59e0b' },
          { icon: <Zap size={20} />, label: 'Check Status', value: '100%', sub: 'Safe and secure', color: 'var(--accent)' }
        ].map((stat, i) => (
          <div key={i} className="control-card control-card-entrance" style={{
            padding: '1rem',
            background: 'var(--surface)',
            border: '1px solid var(--border)',
            borderRadius: 'var(--radius)',
            position: 'relative',
            overflow: 'hidden',
            boxShadow: 'var(--shadow-sm)',
            transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
            animationDelay: `${i * 0.1}s`,
            opacity: 0 // Start hidden for animation
          }}>
            <div style={{ position: 'absolute', top: '-15px', right: '-15px', width: '70px', height: '70px', background: stat.color, filter: 'blur(45px)', opacity: 0.12, pointerEvents: 'none' }} />
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', color: stat.color, marginBottom: '0.5rem' }}>
              {stat.icon}
              <span style={{ fontSize: '0.65rem', fontWeight: 900, textTransform: 'uppercase', letterSpacing: '0.1em', color: 'var(--text-sub)' }}>{stat.label}</span>
            </div>
            <div style={{ fontSize: '1.75rem', fontWeight: 950, color: 'var(--text-main)', lineHeight: 0.9 }}>{stat.value}</div>
            <div style={{ fontSize: '0.75rem', fontWeight: 700, color: 'var(--text-sub)', marginTop: '0.4rem' }}>{stat.sub}</div>
          </div>
        ))}
      </div>

      {/* ── COMMAND CENTER CONTROLS ─────────────────────────────────────── */}
      <div style={{
        marginTop: '0.5rem',
        padding: '0.6rem',
        background: 'rgba(var(--bg-sub-rgb), 0.5)',
        backdropFilter: 'blur(10px)',
        borderRadius: 'var(--radius)',
        border: '1px solid var(--border)',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        flexWrap: 'wrap',
        gap: '1rem',
        boxShadow: 'var(--shadow-sm)'
      }}>
        <div style={{ display: 'flex', gap: '0.4rem' }}>
          {[
            { id: 'board', label: 'Task Board', icon: <LayoutDashboard size={18} /> },
            { id: 'calendar', label: 'Team Calendar', icon: <Calendar size={18} /> }
          ].map((tab: { id: 'board' | 'calendar'; label: string; icon: JSX.Element }) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`control-tab ${activeTab === tab.id ? 'active' : ''}`}
            >
              {tab.icon} {tab.label}
            </button>
          ))}
        </div>

        <div style={{ display: 'flex', gap: '0.5rem', paddingRight: '0.5rem' }}>
          <button className="panel-tool" data-tooltip="Update view" aria-label="Refresh board data" onClick={() => setSyncToken(v => v + 1)}>
            <Activity size={16} aria-hidden="true" />
          </button>
          <button className="panel-tool" data-tooltip="Board Settings" aria-label="Open board settings" onClick={() => router.push('/dashboard/settings')}>
            <TrendingUp size={16} aria-hidden="true" />
          </button>
        </div>
      </div>

      {/* ── PRIMARY WORKSTATION ────────────────────────────────────────── */}
      <div style={{
        minHeight: '65vh',
        background: 'var(--surface)',
        borderRadius: 'var(--radius-lg)',
        border: '1px solid var(--border)',
        boxShadow: 'var(--shadow-xl)',
        overflow: 'hidden',
        position: 'relative',
        transition: 'all 0.4s ease'
      }}>
        <div style={{
          position: 'absolute',
          top: 0,
          left: 0,
          right: 0,
          height: '4px',
          background: 'linear-gradient(90deg, var(--brand), var(--accent), var(--brand))',
          backgroundSize: '200% 100%',
          animation: 'shimmer-sweep 3s infinite linear',
          zIndex: 10
        }} />
        {activeTab === 'board'
          ? <KanbanBoard groupId={groupId} key={`board-${syncToken}`} profile={profile} newTaskSignal={newTaskSignal} />
          : <CalendarView groupId={groupId} key={`cal-${syncToken}`} onTaskSaved={handleCalendarTaskSaved} />
        }
      </div>

      {/* ── SYSTEM STATUS FOOTER ───────────────────────────────────────── */}
      {group && (
        <footer style={{
          marginTop: '0.5rem',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          padding: '1.25rem 2rem',
          background: 'var(--surface)',
          border: '1px solid var(--border)',
          borderRadius: 'var(--radius)',
          boxShadow: 'var(--shadow-sm)'
        }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '1.25rem' }}>
            <div style={{ display: 'flex', flexDirection: 'column' }}>
              <span style={{ fontSize: '0.65rem', fontWeight: 900, color: 'var(--brand)', textTransform: 'uppercase', letterSpacing: '0.15em' }}>Your Team</span>
              <span style={{ fontSize: '1rem', fontWeight: 800, color: 'var(--text-main)' }}>
                {group.name} <span style={{ color: 'var(--text-sub)', fontWeight: 600 }}>&middot; {group.module_code || 'Project'}</span>
              </span>
            </div>
          </div>

          <div style={{ display: 'flex', gap: '2rem' }} className="mobile-hide">
            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end' }}>
              <span style={{ fontSize: '0.65rem', fontWeight: 900, color: 'var(--text-sub)', textTransform: 'uppercase' }}>Security</span>
              <span style={{ fontSize: '0.85rem', fontWeight: 800, color: 'var(--success)' }}>Your work is safe with us</span>
            </div>
            <div
              style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', cursor: 'pointer' }}
              onClick={() => router.push('/dashboard/network')}
            >
              <span style={{ fontSize: '0.65rem', fontWeight: 900, color: 'var(--text-sub)', textTransform: 'uppercase' }}>Connection</span>
              <div style={{ display: 'flex', alignItems: 'center', gap: '0.4rem' }}>
                <div className="pulse-pill" style={{ width: '6px', height: '6px', borderRadius: '50%', background: 'var(--success)' }} />
                <span style={{ fontSize: '0.85rem', fontWeight: 800 }}>Online & Ready</span>
              </div>
            </div>
          </div>
        </footer>
      )}

      <style jsx>{`
        @keyframes shimmer-sweep {
          0% { background-position: -200% 0; }
          100% { background-position: 200% 0; }
        }
        @keyframes fadeInSlide { 
          from { opacity: 0; transform: translateY(-10px) scale(0.98); } 
          to { opacity: 1; transform: translateY(0) scale(1); } 
        }
        @media (max-width: 768px) {
          .mobile-hide { display: none !important; }
        }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  )
}

'use client'

import { useState, useEffect, useRef } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { AlertCircle, X, Shield, Activity, Globe } from 'lucide-react'
import { createBrowserSupabaseClient } from '@/utils/supabase/client'

interface AnnouncementConfig {
  key: string
  is_active: boolean
  value: {
    title: string
    message: string
    style: 'elite' | 'alert'
  }
}

export default function GlobalAnnouncement() {
  const [config, setConfig] = useState<AnnouncementConfig | null>(null)
  const [isVisible, setIsVisible] = useState(true)
  // Use a ref to prevent React StrictMode double-subscription errors:
  // StrictMode mounts→unmounts→mounts in dev; the cleanup removes the channel
  // before the second mount, so using a unique channel name per effect avoids
  // "cannot add postgres_changes callbacks after subscribe()" errors.
  const mountIdRef = useRef(0)

  useEffect(() => {
    mountIdRef.current += 1
    const mountId = mountIdRef.current

    const supabase = createBrowserSupabaseClient()

    // 1. Initial Fetch
    const fetchConfig = async () => {
      const { data } = await supabase
        .from('platform_config')
        .select('*')
        .eq('key', 'global_announcement')
        .single()
      
      if (data) setConfig(data)
    }
    fetchConfig()

    

  
  }, [])

  const isClient = typeof window !== 'undefined'
  if (!isClient || !isVisible || !config?.is_active) return null

  const { title, message, style } = config.value || { title: 'Institutional Update', message: '', style: 'elite' }

  return (
    <AnimatePresence>
      <motion.div 
        initial={{ opacity: 0, y: 50, scale: 0.95 }}
