      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div className="skeleton skeleton-title" style={{ width: '30%' }} />
        <div className="skeleton" style={{ width: '100px', height: '38px', borderRadius: '14px' }} />
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '1.5rem' }}>
        {[1, 2, 3, 4].map(i => (
          <div key={i} style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
            <div className="skeleton skeleton-title" style={{ width: '40%', height: '1.2rem' }} />
            <div className="skeleton skeleton-card" style={{ height: '120px' }} />
          </div>
        ))}
      </div>
    </div>
  )
}

'use client'

import { useState, useEffect, useRef } from 'react'
import { Globe, Check, ChevronDown } from 'lucide-react'
import { motion, AnimatePresence } from 'framer-motion'
import { locales, detectBrowserLocale, isValidLocale, type LocaleCode } from '@/i18n/config'

// Only show locales that have compiled message files
const SUPPORTED_LOCALE_CODES = new Set([
  'en','es','zh','ar','hi','fr','pt','de','ja','ko',
  'it','tr','vi','pl','nl','id','th','sv','no','da',
])
const SUPPORTED_LOCALES = locales.filter((l) => SUPPORTED_LOCALE_CODES.has(l.code))

function readCookieLocale(): LocaleCode | null {
  if (typeof document === 'undefined') return null
  const match = document.cookie.match(/(?:^|;\s*)NEXT_LOCALE=([^;]+)/)
  const val = match ? decodeURIComponent(match[1]) : undefined
  return val && isValidLocale(val) ? val : null
}

export default function LanguageSelector() {
  const [open, setOpen] = useState(false)
  const [current, setCurrent] = useState<LocaleCode>(() => readCookieLocale() || detectBrowserLocale())
  const containerRef = useRef<HTMLDivElement>(null)

  // Close on outside click
  useEffect(() => {
    if (!open) return
    const handler = (e: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(e.target as Node)) {
        setOpen(false)
      }
    }
    document.addEventListener('mousedown', handler)
    return () => document.removeEventListener('mousedown', handler)
  }, [open])

  const setLocale = (code: LocaleCode) => {
    // eslint-disable-next-line react-hooks/immutability
    document.cookie = `NEXT_LOCALE=${encodeURIComponent(code)}; path=/; max-age=31536000; SameSite=Lax`
    setOpen(false)
    window.location.reload()
  }

  const currentInfo = SUPPORTED_LOCALES.find((l) => l.code === current) ?? SUPPORTED_LOCALES[0]

  return (
    <div ref={containerRef} style={{ position: 'relative' }}>
      <button
        aria-label={`Current language: ${currentInfo.name}, click to change`}
        aria-expanded={open}
        aria-haspopup="listbox"
        onClick={() => setOpen((o) => !o)}
        style={{
          background: 'rgba(255,255,255,0.03)',
          border: '1px solid #222222',
          borderRadius: '6px',
          padding: '0.4rem 0.6rem',
          color: '#9ca3af',
          display: 'flex',
          alignItems: 'center',
          gap: '0.4rem',
          cursor: 'pointer',
          fontSize: '0.75rem',
          fontWeight: 600,
          transition: 'all 0.2s ease',
          whiteSpace: 'nowrap',
        }}
        onMouseEnter={(e) => { e.currentTarget.style.borderColor = '#10b981'; e.currentTarget.style.color = '#f3f4f6' }}
        onMouseLeave={(e) => { e.currentTarget.style.borderColor = '#222222'; e.currentTarget.style.color = '#9ca3af' }}
      >
        <Globe size={14} aria-hidden="true" />
        <span aria-hidden="true">{currentInfo.flag}</span>
        <ChevronDown
          size={10}
          aria-hidden="true"
          style={{ transform: open ? 'rotate(180deg)' : 'rotate(0deg)', transition: 'transform 0.2s ease' }}
        />
      </button>

      <AnimatePresence>
        {open && (
          <motion.div
            role="listbox"
            aria-label="Select language"
            initial={{ opacity: 0, y: -8, scale: 0.97 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: -8, scale: 0.97 }}
            transition={{ duration: 0.15, ease: [0.16, 1, 0.3, 1] }}
            style={{
              position: 'absolute',
              right: 0,
              top: 'calc(100% + 0.5rem)',
              background: '#111111',
              border: '1px solid #222222',
              borderRadius: '10px',
              boxShadow: '0 20px 50px rgba(0,0,0,0.6)',
              width: '220px',
              maxHeight: '320px',
              overflowY: 'auto',
              zIndex: 2000,
              padding: '0.4rem',
            }}
          >
            {SUPPORTED_LOCALES.map((locale) => (
              <button
                key={locale.code}
                role="option"
                aria-selected={current === locale.code}
                onClick={() => setLocale(locale.code)}
                style={{
                  width: '100%',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '0.65rem',
                  padding: '0.55rem 0.7rem',
                  background: current === locale.code ? 'rgba(16,185,129,0.1)' : 'transparent',
                  border: 'none',
                  borderRadius: '6px',
                  cursor: 'pointer',
                  textAlign: 'left',
                  transition: 'background 0.15s ease',
                }}
                onMouseEnter={(e) => {
                  if (current !== locale.code) (e.currentTarget as HTMLElement).style.background = 'rgba(255,255,255,0.04)'
                }}
                onMouseLeave={(e) => {
                  if (current !== locale.code) (e.currentTarget as HTMLElement).style.background = 'transparent'
                }}
              >
                <span style={{ fontSize: '1rem', lineHeight: 1 }}>{locale.flag}</span>
                <div style={{ flex: 1, overflow: 'hidden' }}>
                  <div style={{ color: '#f3f4f6', fontSize: '0.8rem', fontWeight: 600, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                    {locale.nativeName}
                  </div>
                  <div style={{ color: '#6b7280', fontSize: '0.7rem' }}>{locale.name}</div>
                </div>
                {current === locale.code && <Check size={12} color="#10b981" aria-hidden="true" />}
              </button>
            ))}
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  )
}

'use client'

import React, { useState } from 'react'
import { Search, Play, Music, Disc } from 'lucide-react'
import { useSpotify } from '@/context/SpotifyContext'
import { useProfile } from '@/context/ProfileContext'

interface Track {
  id: string
  name: string
  uri: string
  album: { name: string; images: { url: string }[] }
  artists: { name: string }[]
}

export default function MusicDashboard() {
  const [query, setQuery] = useState('')
  const [results, setResults] = useState<Track[]>([])
  const { playTrack, isConnected, isPremium, connectSpotify } = useSpotify()
  const { profile } = useProfile()

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!query || !profile?.spotify_access_token) return

    try {
      const resp = await fetch(`https://api.spotify.com/v1/search?q=${encodeURIComponent(query)}&type=track&limit=10`, {
        headers: { 'Authorization': `Bearer ${profile.spotify_access_token}` }
      })
      const data = await resp.json()
      setResults(data.tracks.items)
    } catch (err) {
      console.error('Search error:', err)
    }
  }

  if (!isConnected) {
    return (
      <div style={{ padding: '4rem', textAlign: 'center', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '1.5rem' }}>
        <div style={{ width: '80px', height: '80px', borderRadius: '24px', background: 'rgba(29, 185, 84, 0.1)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <Music size={40} color="#1DB954" />
        </div>
        <h2 style={{ fontSize: '1.5rem', fontWeight: 900 }}>Connect to Spotify</h2>
        <p style={{ color: 'var(--text-sub)', maxWidth: '400px' }}>Join your team&apos;s rhythm. Connect your account to listen together and share your favorite study tracks.</p>
        <button className="btn btn-primary" onClick={connectSpotify} style={{ background: '#1DB954', border: 'none', color: 'black', padding: '1rem 2.5rem', borderRadius: '14px', fontWeight: 900 }}>
          Sign in to Spotify
        </button>
      </div>
    )
  }

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '2rem', padding: '1rem' }}>
      <header>
        <h2 style={{ fontSize: '2rem', fontWeight: 950, letterSpacing: '-0.04em' }}>Team Jukebox</h2>
        <p style={{ color: 'var(--text-sub)' }}>Search and play music for everyone in your workspace.</p>
      </header>

      <form onSubmit={handleSearch} style={{ position: 'relative' }} role="search">
        <input 
          type="text" 
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="Search for tracks, artists, or albums..."
          aria-label="Search Spotify tracks"
          style={{
            width: '100%',
            padding: '1.25rem 1.5rem 1.25rem 3.5rem',
            background: 'var(--bg-sub)',
            border: '1px solid var(--border)',
            borderRadius: '16px',
            fontSize: '1rem',
            color: 'var(--text-main)',
            outline: 'none'
          }}
        />
        <Search style={{ position: 'absolute', left: '1.25rem', top: '50%', transform: 'translateY(-50%)', color: 'var(--text-sub)' }} size={20} aria-hidden="true" />
      </form>

      {isConnected && isPremium === false && (
        <div style={{ 
          padding: '1rem', 
          background: 'rgba(251, 191, 36, 0.05)', 
          border: '1px solid rgba(251, 191, 36, 0.1)', 
          borderRadius: '16px',
          display: 'flex',
          gap: '1rem',
          alignItems: 'center'
        }}>
          <Disc size={24} color="#fbbf24" />
          <div style={{ fontSize: '0.85rem', color: '#fbbf24', fontWeight: 700 }}>
            Since you&apos;re on a Spotify Free account, playback will open in your external Spotify app rather than inside Espeezy.
          </div>
        </div>
      )}

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '1rem' }} aria-label="Search results">
        {results.map(track => (
          <div 
            key={track.id} 
            role="listitem"
            style={{ 
              display: 'flex', 
              alignItems: 'center', 
              gap: '1rem', 
              padding: '1rem', 
              background: 'var(--surface)', 
              border: '1px solid var(--border)', 
              borderRadius: '16px',
              transition: 'all 0.3s ease',
              cursor: 'default'
            }} 
            className="hover-lift"
          >
            <img 
              src={track.album.images[0]?.url} 
              style={{ width: '64px', height: '64px', borderRadius: '8px', objectFit: 'cover' }} 
              alt={`Cover for ${track.name}`}
            />
            <div style={{ flex: 1, overflow: 'hidden' }}>
              <div style={{ fontWeight: 850, fontSize: '0.95rem', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{track.name}</div>
              <div style={{ fontSize: '0.8rem', color: 'var(--text-sub)', fontWeight: 600 }}>{track.artists.map(a => a.name).join(', ')}</div>
            </div>
            <div style={{ display: 'flex', gap: '0.5rem' }}>
              <button 
                onClick={() => playTrack(track.uri)}
                aria-label={`Play ${track.name} by ${track.artists[0].name}`}
                style={{ width: '40px', height: '40px', borderRadius: '50%', background: 'var(--brand)', color: 'white', border: 'none', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' }}
              >
                <Play size={18} fill="currentColor" style={{ marginLeft: '2px' }} aria-hidden="true" />
              </button>
            </div>
          </div>
        ))}

        {results.length === 0 && (
          <div style={{ gridColumn: '1 / -1', padding: '4rem', textAlign: 'center', border: '1px dashed var(--border)', borderRadius: '24px' }}>
            <Disc size={48} color="var(--text-sub)" style={{ marginBottom: '1rem', opacity: 0.3 }} />
            <div style={{ color: 'var(--text-sub)', fontWeight: 700 }}>Search for music to start the session</div>
          </div>
        )}
      </div>
    </div>
  )
}

'use client'

import { useState, useRef, useEffect, type CSSProperties } from 'react'
import { Bell, Check, Clock, ExternalLink, Inbox } from 'lucide-react'
import { useNotifications } from './NotificationProvider'
import { createBrowserSupabaseClient } from '@/utils/supabase/client'

export default function NotificationBell() {
  const { notifications, unreadCount, markAsRead, markAllAsRead } = useNotifications()
  const [isOpen, setIsOpen] = useState(false)
  const [dropdownStyle, setDropdownStyle] = useState<CSSProperties>({})
  const menuRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
        setIsOpen(false)
      }
    }
    document.addEventListener('mousedown', handleClickOutside)
    return () => document.removeEventListener('mousedown', handleClickOutside)
  }, [])

  useEffect(() => {
    if (!isOpen || !menuRef.current) return

    const updatePosition = () => {
      const rect = menuRef.current?.getBoundingClientRect()
      if (!rect) return

      const isMobile = window.innerWidth <= 768
      const width = isMobile ? Math.min(380, window.innerWidth - 32) : 320
      
      let left: string | number = rect.right - width
      let top: string | number = rect.bottom + 10

      if (isMobile) {
        // Force fixed centering on mobile
        left = 16
        top = 70 // Below mobile header
        setDropdownStyle({
          position: 'fixed',
          top: `${top}px`,
          left: `${left}px`,
          width: `calc(100vw - 32px)`,
          maxHeight: '70vh',
          overflow: 'hidden',
          zIndex: 9000,
        })
      } else {
        // Clamp to screen edges for desktop
        left = Math.min(Math.max(12, rect.right - width), window.innerWidth - width - 12)
        const maxHeight = Math.min(450, window.innerHeight - top - 20)
        setDropdownStyle({
          position: 'fixed',
          top: `${top}px`,
          left: `${left}px`,
          width: `${width}px`,
          maxHeight: `${maxHeight}px`,
          overflow: 'hidden',
          zIndex: 9000,
        })
      }
    }

    updatePosition()
    window.addEventListener('resize', updatePosition)
    window.addEventListener('scroll', updatePosition, true)
    return () => {
      window.removeEventListener('resize', updatePosition)
      window.removeEventListener('scroll', updatePosition, true)
    }
  }, [isOpen])

  return (
    <div style={{ position: 'relative' }} ref={menuRef}>
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className="nav-bubble"
        style={{ 
          background: 'none', 
          border: 'none', 
          cursor: 'pointer', 
          position: 'relative',
          padding: '0.5rem',
          color: unreadCount > 0 ? 'var(--brand)' : 'var(--text-sub)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          transition: 'transform 0.2s'
        }}
      >
        <Bell size={20} />
        {unreadCount > 0 && (
          <div style={{ 
            position: 'absolute', 
            top: '0', 
            right: '0', 
            background: 'var(--error)', 
            color: 'white', 
            fontSize: '10px', 
            fontWeight: 800, 
            width: '18px', 
            height: '18px', 
            borderRadius: '50%', 
            display: 'flex', 
            alignItems: 'center', 
            justifyContent: 'center',
            border: '2px solid var(--surface)',
            boxShadow: '0 0 10px rgba(var(--error-rgb), 0.3)'
          }}>
            {unreadCount > 9 ? '9+' : unreadCount}
          </div>
        )}
      </button>

      {isOpen && (
        <div style={{
          ...dropdownStyle,
          background: 'var(--surface)',
          border: '1px solid var(--border)',
          borderRadius: '16px',
          boxShadow: 'var(--shadow-lg)',
          animation: 'popIn 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275)',
          overflow: 'hidden'
        }}>
          <div style={{ padding: '1rem', borderBottom: '1px solid var(--border)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
             <h3 style={{ margin: 0, fontSize: '0.9rem', fontWeight: 800 }}>Project Alerts</h3>
             <button 
               onClick={markAllAsRead} 
               style={{ background: 'none', border: 'none', fontSize: '0.75rem', color: 'var(--brand)', cursor: 'pointer', fontWeight: 600 }}
             >
                Clear All
             </button>
          </div>

          <div style={{ maxHeight: '400px', overflowY: 'auto' }}>
            {notifications.length === 0 ? (
              <div style={{ padding: '3rem 1rem', textAlign: 'center', color: 'var(--text-sub)' }}>
                 <Inbox size={32} style={{ marginBottom: '1rem', opacity: 0.3 }} />
                 <p style={{ fontSize: '0.875rem' }}>No new signals detected.</p>
              </div>
            ) : (
              notifications.map((notif) => (
                <div 
                  key={notif.id} 
                  onClick={() => markAsRead(notif.id)}
                  style={{ 
                    padding: '1rem', 
                    borderBottom: '1px solid var(--bg-main)', 
                    cursor: 'pointer',
                    background: notif.read ? 'transparent' : 'rgba(var(--brand-rgb), 0.03)',
                    transition: 'background 0.2s'
                  }}
                  className="notif-item"
                >
                   <div style={{ display: 'flex', gap: '0.75rem' }}>
                      <div style={{ marginTop: '0.2rem' }}>
                         <div style={{ width: '8px', height: '8px', borderRadius: '50%', background: notif.read ? 'transparent' : 'var(--brand)' }} />
                      </div>
                      <div style={{ flex: 1 }}>
                         <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.2rem' }}>
                            <span style={{ fontSize: '0.85rem', fontWeight: 700, color: notif.read ? 'var(--text-sub)' : 'var(--text-main)' }}>{notif.title}</span>
                            <span style={{ fontSize: '0.65rem', color: 'var(--text-sub)' }}>
                               {new Date(notif.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                            </span>
                         </div>
                         <p style={{ margin: 0, fontSize: '0.75rem', color: 'var(--text-sub)', lineHeight: 1.4 }}>{notif.message}</p>
                         
                         {notif.type === 'connection_request' && !notif.read && (
                           <div style={{ display: 'flex', gap: '0.5rem', marginTop: '0.75rem' }} onClick={(e) => e.stopPropagation()}>
                             <button 
                               className="btn-sm btn-primary" 
                               style={{ padding: '0.3rem 0.6rem', fontSize: '0.7rem' }}
                               onClick={async () => {
                                 const supabase = createBrowserSupabaseClient();
                                 const senderId = notif.metadata?.sender_id;
                                 if (!senderId) return;

                                 const myId = (await supabase.auth.getUser()).data.user?.id;
                                 const { error: updErr } = await supabase
                                   .from('user_connections')
                                   .update({ status: 'connected' })
                                   .eq('user_id', senderId)
                                   .eq('target_id', myId);

                                 if (!updErr) {
                                   markAsRead(notif.id);
                                   // Notify sender back
                                   await supabase.from('notifications').insert({
                                     user_id: senderId,
                                     type: 'connection_accepted',
                                     title: 'Request Accepted',
                                     message: `You are now connected.`,
                                     link: `/dashboard/network/profile/${myId}`
                                   });
                                 }
                               }}
                             >
                               Accept
                             </button>
                             <button 
                               className="btn-sm btn-ghost" 
                               style={{ padding: '0.3rem 0.6rem', fontSize: '0.7rem', border: '1px solid var(--border)' }}
                               onClick={async () => {
                                 const supabase = createBrowserSupabaseClient();
                                 const senderId = notif.metadata?.sender_id;
                                 if (!senderId) return;
                                 const myId = (await supabase.auth.getUser()).data.user?.id;

                                 const { error } = await supabase
                                   .from('user_connections')
                                   .delete()
                                   .eq('user_id', senderId)
                                   .eq('target_id', myId);

                                 if (!error) markAsRead(notif.id);
                               }}
                             >
                               Decline
                             </button>
                             <button 
                               className="btn-sm btn-ghost" 
                               style={{ padding: '0.3rem 0.6rem', fontSize: '0.7rem', display: 'flex', alignItems: 'center', gap: '0.2rem' }}
                               onClick={() => {
                                 const senderId = notif.metadata?.sender_id;
                                 if (senderId) {
                                   window.location.href = `/dashboard/network/profile/${senderId}`;
                                 }
                               }}
                             >
                               <ExternalLink size={12} /> Profile
                             </button>
                           </div>
                         )}

                         {notif.type === 'quiz_invite' && !notif.read && (
                           <div style={{ display: 'flex', gap: '0.5rem', marginTop: '0.75rem' }} onClick={(e) => e.stopPropagation()}>
                             <button 
                               className="btn-sm btn-primary" 
                               style={{ padding: '0.3rem 0.6rem', fontSize: '0.7rem', background: 'var(--accent)', borderColor: 'var(--accent)' }}
                               onClick={() => {
                                 markAsRead(notif.id);
                                 const roomId = notif.metadata?.room_id;
                                 if (roomId) window.location.href = `/dashboard/chillout/room/${roomId}`;
                               }}
                             >
                               Accept & Join
                             </button>
                             <button 
                               className="btn-sm btn-ghost" 
                               style={{ padding: '0.3rem 0.6rem', fontSize: '0.7rem', border: '1px solid var(--border)' }}
                               onClick={() => markAsRead(notif.id)}
                             >
                               Decline
                             </button>
                           </div>
                         )}
                      </div>
                   </div>
                </div>
              ))
            )}
          </div>
          
          <div style={{ padding: '0.75rem', borderTop: '1px solid var(--border)', textAlign: 'center' }}>
             <button style={{ background: 'none', border: 'none', fontSize: '0.7rem', color: 'var(--text-sub)', cursor: 'pointer', fontWeight: 600, display: 'flex', alignItems: 'center', gap: '0.4rem', justifyContent: 'center', width: '100%' }}>
                <Clock size={12} /> View Full Timeline
             </button>
          </div>
        </div>
      )}

      <style jsx>{`
        @keyframes popIn {
          from { opacity: 0; transform: translateY(-10px) scale(0.95); }
          to { opacity: 1; transform: translateY(0) scale(1); }
        }
        .notif-item:hover { background: var(--bg-main) !important; }
      `}</style>
    </div>
  )
}

'use client'

import React, { createContext, useContext, useEffect, useState, useCallback, useMemo } from 'react'
import type { RealtimeChannel } from '@supabase/supabase-js'
import { createBrowserSupabaseClient } from '@/utils/supabase/client'
import { X, Info, UserPlus, CheckCircle2, AlertCircle, Timer } from 'lucide-react'
import { Notification, NotificationContextType, Toast } from '@/types/ui'

const NotificationContext = createContext<NotificationContextType | undefined>(undefined)

export const useNotifications = () => {
  const context = useContext(NotificationContext)
  if (!context) throw new Error('useNotifications must be used within NotificationProvider')
  return context
}

export function NotificationProvider({ children }: { children: React.ReactNode }) {
  const [notifications, setNotifications] = useState<Notification[]>([])
  const [toasts, setToasts] = useState<Toast[]>([])
  // Removed unused notificationPermission state
  const supabase = useMemo(() => createBrowserSupabaseClient(), [])

  const addToast = (title: string, message: string, type: string = 'info') => {
    const id = Math.random().toString(36).substr(2, 9)
    setToasts(prev => [...prev, { id, title, message, type }])
    setTimeout(() => {
      setToasts(prev => prev.filter(t => t.id !== id))
    }, 5000)
  }

  const fetchNotifications = useCallback(async () => {
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) return

    const { data } = await supabase
      .from('notifications')
      .select('*')
      .eq('user_id', user.id)
      .order('created_at', { ascending: false })
      .limit(20)

    if (data) setNotifications(data)
  }, [supabase])

  useEffect(() => {
    // Only request permission if needed; do not attempt to set Notification.permission (read-only)
    if (typeof window !== 'undefined' && 'Notification' in window) {
      if (window.Notification.permission === 'default') {
        window.Notification.requestPermission();
      }
    }

    let channel: RealtimeChannel | null = null;
    let active = true;

    const showBrowserAlert = (title: string, message: string) => {
      if (typeof window === 'undefined') return;
      if (window.Notification?.permission !== 'granted') return;
      if (!document.hidden && document.hasFocus()) return;

      const notification = new window.Notification(title, {
        body: message,
        icon: '/favicon.ico',
        silent: true
      });
      notification.onclick = () => window.focus();
    };

    const setupSubscription = async () => {
      // Always clean up previous channel before creating a new one
      if (channel) {
        supabase.removeChannel(channel);
        channel = null;
      }
      await fetchNotifications();
      const { data: { user } } = await supabase.auth.getUser();
      if (user && active) {
        // Use a unique channel name to avoid Supabase callback errors
        const uniqueId = Math.random().toString(36).slice(2) + Date.now();
        const channelName = `notifications_${user.id}_${uniqueId}`;
        const newChannel = supabase
          .channel(channelName)
          .on('postgres_changes', {
            event: '*',
            schema: 'public',
            table: 'notifications',
            filter: `user_id=eq.${user.id}`,
          }, (payload) => {
            if (!payload.new) return;
            const incoming = payload.new as Notification;
            
            // Update local state for all events (INSERT, UPDATE) to keep tabs in sync
            setNotifications(prev => {
              const exists = prev.some(n => n.id === incoming.id);
              if (exists) {
                return prev.map(n => n.id === incoming.id ? incoming : n);
              }
              return [incoming, ...prev];
            });

            // ONLY trigger active alerts/toasts on NEW notifications
            // This prevents "Clear All" (which triggers multiple UPDATEs) from spamming the user
            if (payload.eventType === 'INSERT') {
              addToast(incoming.title, incoming.message, incoming.type);
              showBrowserAlert(incoming.title, incoming.message);
            }
          });
        await newChannel.subscribe();
        channel = newChannel;
      }
    };

    setupSubscription();

    return () => {
      active = false;
      if (channel) supabase.removeChannel(channel);
    };
  }, [fetchNotifications, supabase]);

  const markAsRead = async (id: string) => {
    const original = notifications.find(n => n.id === id)
    if (!original || original.read) return

    // Optimistic Update
    setNotifications(prev => prev.map(n => n.id === id ? { ...n, read: true } : n))

    try {
      const { error } = await supabase.from('notifications').update({ read: true }).eq('id', id)
      if (error) throw error
    } catch (err) {
      console.error('Persistence error (markAsRead):', err)
      // Rollback
      setNotifications(prev => prev.map(n => n.id === id ? { ...n, read: false } : n))
      addToast('Check connection', 'We couldn\'t update that just now.', 'error')
    }
  }

  const markAllAsRead = async () => {
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) return

    const original = [...notifications]
    setNotifications(prev => prev.map(n => ({ ...n, read: true })))

    try {
      const { error } = await supabase.from('notifications').update({ read: true }).eq('user_id', user.id)
      if (error) throw error
    } catch (err) {
      console.error('Persistence error (markAllAsRead):', err)
      setNotifications(original)
      addToast('Check connection', 'We couldn\'t clear your notifications.', 'error')
    }
  }

  const unreadCount = notifications.filter(n => !n.read).length

  return (
    <NotificationContext.Provider value={{ notifications, unreadCount, markAsRead, markAllAsRead, addToast, refreshNotifications: fetchNotifications }}>
      {children}
      
      {/* Absolute Toast Container */}
      <div style={{ position: 'fixed', bottom: '2rem', right: '2rem', display: 'flex', flexDirection: 'column', gap: '0.75rem', zIndex: 99999, pointerEvents: 'none' }}>
        {toasts.map(toast => {
          const type = toast.type?.toLowerCase() || 'info'
          const isError = type === 'error'
          const isSuccess = type === 'success'
          const isWarning = type === 'warning'
          
          const colors = {
            brand: isError ? '#ef4444' : isSuccess ? '#10b981' : isWarning ? '#f59e0b' : '#38bdf8',
            bg: 'rgba(15, 15, 20, 0.9)',
            border: isError ? 'rgba(239, 68, 68, 0.3)' : isSuccess ? 'rgba(16, 185, 129, 0.3)' : isWarning ? 'rgba(245, 158, 11, 0.3)' : 'rgba(56, 189, 248, 0.3)'
          }

          return (
            <div 
              key={toast.id} 
              style={{ 
                pointerEvents: 'auto',
                padding: '1.25rem 1.5rem', 
                borderRadius: '24px', 
                minWidth: '340px', 
                maxWidth: '450px', 
                display: 'flex', 
                alignItems: 'center', 
                gap: '1.25rem',
                border: `1px solid ${colors.border}`,
                background: colors.bg,
                backdropFilter: 'blur(20px)',
                boxShadow: '0 25px 50px rgba(0,0,0,0.5)',
                position: 'relative',
                overflow: 'hidden',
                animation: 'elite-toast-in 0.5s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards'
              }}
            >
              {/* Progress Bar */}
              <div style={{
                position: 'absolute',
                bottom: 0,
                left: 0,
                height: '3px',
                background: colors.brand,
                width: '100%',
                animation: 'elite-toast-progress 5s linear forwards'
              }} />

              <div style={{ 
                width: '40px',
                height: '40px',
                borderRadius: '12px', 
                background: `rgba(${isError ? '239, 68, 68' : isSuccess ? '16, 185, 129' : '56, 189, 248'}, 0.1)`,
                color: colors.brand,
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                flexShrink: 0
              }}>
                 {isError ? <AlertCircle size={22} /> : 
                  isSuccess ? <CheckCircle2 size={22} /> : 
                  isWarning ? <Timer size={22} /> : <Info size={22} />}
              </div>
              
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: '0.7rem', fontWeight: 950, color: colors.brand, textTransform: 'uppercase', letterSpacing: '1px', marginBottom: '2px' }}>
                  {type === 'info' ? 'Update' : type}
                </div>
                <div style={{ fontWeight: 800, fontSize: '1rem', color: 'white', letterSpacing: '-0.01em', lineHeight: 1.2 }}>{toast.title}</div>
                {toast.message && <div style={{ fontSize: '0.8rem', color: 'rgba(255,255,255,0.6)', marginTop: '4px', lineHeight: 1.4 }}>{toast.message}</div>}
              </div>

              <button 
                onClick={() => setToasts(prev => prev.filter(t => t.id !== toast.id))}
                style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'rgba(255,255,255,0.2)', padding: '4px' }}
              >
                <X size={18} />
              </button>
            </div>
          )
        })}
      </div>

      <style jsx global>{`
        @keyframes elite-toast-in {
          from { opacity: 0; transform: translateX(60px) scale(0.9); }
          to { opacity: 1; transform: translateX(0) scale(1); }
        }
        @keyframes elite-toast-progress {
          from { width: 100%; }
          to { width: 0%; }
        }
      `}</style>
    </NotificationContext.Provider>
  )
}

'use client'

import { useState } from 'react'
import { createBrowserSupabaseClient } from '@/utils/supabase/client'
import { 
  CheckCircle2, 
  ArrowRight, 
  Sparkles, 
  ShieldCheck,
  Zap
} from 'lucide-react'
import confetti from 'canvas-confetti'

const PRESET_AVATARS = [
  'https://api.dicebear.com/7.x/shapes/svg?seed=Avatar1&backgroundColor=1a73e8',
  'https://api.dicebear.com/7.x/shapes/svg?seed=Avatar2&backgroundColor=34a853',
  'https://api.dicebear.com/7.x/shapes/svg?seed=Avatar3&backgroundColor=ea4335',
  'https://api.dicebear.com/7.x/shapes/svg?seed=Avatar4&backgroundColor=fbbc04',
  'https://api.dicebear.com/7.x/shapes/svg?seed=Avatar5&backgroundColor=9334e1',
  'https://api.dicebear.com/7.x/shapes/svg?seed=Avatar6&backgroundColor=111111',
  'https://api.dicebear.com/7.x/shapes/svg?seed=Avatar7&backgroundColor=ef4444',
  'https://api.dicebear.com/7.x/shapes/svg?seed=Avatar8&backgroundColor=22c55e',
]

import { OnboardingModalProps } from '@/types/ui'

export default function OnboardingModal({ user, onComplete }: OnboardingModalProps) {
  const [step, setStep] = useState(1)
  const [fullName, setFullName] = useState('')
  const [selectedAvatar, setSelectedAvatar] = useState('')
  const [saving, setSaving] = useState(false)
  const supabase = createBrowserSupabaseClient()

  const handleNext = async () => {
    if (step === 1 && !fullName) return
    if (step === 2 && !selectedAvatar) return
    
    if (step === 3) {
      onComplete()
      return
    }
    
    setStep(step + 1)
    if (step === 2) {
      confetti({
        particleCount: 150,
        spread: 70,
        origin: { y: 0.6 },
        colors: ['#1a73e8', '#34a853', '#ea4335', '#fbbc04']
      })
    }
  }

  const saveIdentity = async () => {
    setSaving(true)
    const { error } = await supabase
      .from('profiles')
      .update({ 
        full_name: fullName, 
        avatar_url: selectedAvatar 
      })
      .eq('id', user.id)
    
    setSaving(false)
    if (!error) handleNext()
  }

  return (
    <div className="onboarding-overlay" style={{
      position: 'fixed', inset: 0, zIndex: 10000,
      background: 'rgba(0,0,0,0.85)', backdropFilter: 'blur(10px)',
      display: 'flex', alignItems: 'center', justifyContent: 'center',
      animation: 'fadeIn 0.3s ease-out'
    }}>
      <div className="onboarding-content" style={{
        maxWidth: '500px', width: '90%', background: 'var(--surface)',
        borderRadius: '32px', border: '1px solid var(--border)',
        padding: '2rem 1.5rem', position: 'relative', overflowY: 'auto',
        maxHeight: 'calc(100dvh - 8rem)',
        boxShadow: '0 20px 50px rgba(0,0,0,0.5)',
        display: 'flex', flexDirection: 'column'
      }}>
        
        {/* Progress Bar */}
        <div style={{ display: 'flex', gap: '8px', marginBottom: '3rem' }}>
          {[1, 2, 3].map(i => (
            <div key={i} style={{ 
              flex: 1, height: '4px', borderRadius: '10px',
              background: i <= step ? 'var(--brand)' : 'var(--bg-main)',
              transition: 'all 0.3s'
            }} />
          ))}
        </div>

        {step === 1 && (
          <div style={{ animation: 'slideIn 0.4s ease-out' }}>
            <div style={{ padding: '1rem', background: 'rgba(26, 115, 232, 0.1)', color: 'var(--brand)', borderRadius: '16px', display: 'inline-flex', marginBottom: '1.5rem' }}>
              <ShieldCheck size={32} />
            </div>
            <h1 style={{ fontSize: '2.5rem', fontWeight: 900, letterSpacing: '-0.04em', lineHeight: 1, marginBottom: '1rem' }}>Welcome to Espeezy</h1>
            <p style={{ color: 'var(--text-sub)', fontSize: '1.1rem', marginBottom: '2.5rem' }}>Let&apos;s set up your profile. What name should we show in the dashboard?</p>
            
            <div className="form-group">
               <label className="form-label" style={{ fontSize: '0.8rem', opacity: 0.7 }}>YOUR FULL NAME</label>
               <input 
                 type="text" className="form-input" 
                 value={fullName} onChange={e => setFullName(e.target.value)} 
                 placeholder="e.g. Alan Turing"
                 autoFocus
                 style={{ fontSize: '1.25rem', padding: '1rem' }}
               />
            </div>
            
            <button 
              onClick={handleNext} 
              disabled={!fullName}
              className="btn btn-primary" 
              style={{ marginTop: '2rem', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.75rem' }}
            >
              Continue <ArrowRight size={20} />
            </button>
          </div>
        )}

        {step === 2 && (
          <div style={{ animation: 'slideIn 0.4s ease-out' }}>
            <h2 style={{ fontSize: '2rem', fontWeight: 900, marginBottom: '1.5rem' }}>Choose an Avatar</h2>
            <p style={{ color: 'var(--text-sub)', marginBottom: '2rem' }}>Select a profile icon to represent you in the workspace.</p>
            
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '1rem', marginBottom: '3rem' }}>
              {PRESET_AVATARS.map((url, i) => (
                <button 
                  key={i}
                  onClick={() => setSelectedAvatar(url)}
                  style={{
                    padding: 0, border: selectedAvatar === url ? '3px solid var(--brand)' : '1px solid var(--border)',
                    borderRadius: '50%', overflow: 'hidden', background: 'var(--bg-main)',
                    cursor: 'pointer', transition: 'all 0.2s cubic-bezier(0.175, 0.885, 0.32, 1.275)',
                    transform: selectedAvatar === url ? 'scale(1.1)' : 'scale(1)'
                  }}
                >
                  <img src={url} alt="Avatar option" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                </button>
              ))}
            </div>
            
            <button 
              onClick={saveIdentity} 
              disabled={!selectedAvatar || saving}
              className="btn btn-primary" 
              style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.75rem' }}
            >
              {saving ? 'Saving...' : 'Finish Setup'} <CheckCircle2 size={20} />
            </button>
          </div>
        )}

        {step === 3 && (
          <div style={{ textAlign: 'center', animation: 'slideIn 0.4s ease-out' }}>
            <div style={{ 
              width: '100px', height: '100px', background: 'var(--success)', color: 'white', 
              borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center',
              margin: '0 auto 2rem', boxShadow: '0 0 30px rgba(34, 197, 94, 0.4)'
            }}>
              <Sparkles size={48} />
            </div>
            <h2 style={{ fontSize: '2.5rem', fontWeight: 900, marginBottom: '1rem' }}>All Set!</h2>
            <p style={{ color: 'var(--text-sub)', fontSize: '1.1rem', marginBottom: '2.5rem' }}>Your profile is ready. Welcome to the team, {fullName.split(' ')[0]}.</p>
            
            <button 
              onClick={handleNext} 
              className="btn btn-primary" 
              style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.75rem' }}
            >
              Go to Dashboard <Zap size={20} />
            </button>
          </div>
        )}

      </div>
      
      <style jsx>{`
        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
        @keyframes slideIn { from { transform: translateX(30px); opacity: 0; } to { transform: translateX(0); opacity: 1; } }
      `}</style>
    </div>
  )
}

