        alignItems: 'center',
        justifyContent: 'center',
        zIndex: 1000,
        transition: 'all 0.3s'
      }}
      className="chat-toggle"
      aria-label="Open team chat"
    >
      <MessageSquare size={24} />
      <div
        style={{
          position: 'absolute',
          top: '2px',
          right: '2px',
